window.COURSE_REGISTRY = window.COURSE_REGISTRY || {};
window.COURSE_REGISTRY["c16-fire-sprinkler"] = [
  {id:1, block:1, sec:"Fire Science & Suppression Basics", q:"The classic 'fire triangle' represents the three elements that must be present for combustion. Which set lists them correctly?", opts:["Pressure, velocity, and density","Water, air, and electricity","Smoke, flame, and ash","Fuel, oxygen (oxidizer), and heat"], correct:3, re:"The fire triangle is fuel, an oxidizing agent (typically oxygen), and heat; remove any one and combustion stops. This is the foundation of fire suppression. Source: NFPA fire-science fundamentals; WFCA fire tetrahedron overview."},
  {id:2, block:1, sec:"Fire Science & Suppression Basics", q:"The 'fire tetrahedron' adds a fourth element to the fire triangle. What is that fourth element?", opts:["The self-sustaining chemical chain reaction","An ignition spark only","A pressurized fuel source","A confined space"], correct:0, re:"The tetrahedron adds the uninhibited chemical chain reaction to fuel, oxygen and heat. Agents like clean agents/halon work by interrupting this reaction. Source: WFCA 'Fire Tetrahedron Explained'; Firetrace fire tetrahedron."},
  {id:3, block:1, sec:"Fire Science & Suppression Basics", q:"A water-based fire sprinkler system primarily extinguishes or controls fire by which main mechanism?", opts:["Cooling — removing heat from the fire and the fuel surface","Smothering the fuel with foam blanket","Adding oxygen to dilute the smoke","Electrically interrupting the flame"], correct:0, re:"Water's high heat-capacity and heat-of-vaporization make cooling (heat removal) its dominant suppression mode; it also provides some surface wetting/pre-wetting. Source: NFPA fire-science fundamentals; fire tetrahedron suppression methods."},
  {id:4, block:1, sec:"Fire Science & Suppression Basics", q:"Approximately what percentage of oxygen does normal air contain, which combustion depends upon?", opts:["About 5 percent","About 50 percent","About 21 percent","About 78 percent"], correct:2, re:"Air is roughly 21% oxygen (and ~78% nitrogen); most flaming combustion is suppressed when oxygen drops below ~15-16%. Source: WFCA fire tetrahedron (oxygen ~21%, fires need a minimum ~16%)."},
  {id:5, block:1, sec:"Fire Science & Suppression Basics", q:"Which of the three heat-transfer modes is MOST responsible for carrying hot fire gases to a ceiling-mounted sprinkler's thermal element and triggering it?", opts:["Conduction through the building steel","Radiation from cold surfaces","Convection — the rising plume of hot gases","Evaporation of the antifreeze"], correct:2, re:"Convection (the buoyant hot-gas plume forming a ceiling jet) has the greatest effect on sprinkler activation; the ceiling jet heats the thermal element. Source: NFSA 'Fire Dynamics and Sprinkler Activation.'"},
  {id:6, block:1, sec:"Fire Science & Suppression Basics", q:"Heat transfer by direct contact through a solid material (for example, hot pipe heating an adjacent member) is called:", opts:["Convection","Radiation","Conduction","Sublimation"], correct:2, re:"Conduction is heat transfer within or between solids in contact. Convection moves heat by fluid/gas motion; radiation by electromagnetic waves. Source: fire behavior & heat-transfer fundamentals (Warren Forensics; Adaston)."},
  {id:7, block:1, sec:"Fire Science & Suppression Basics", q:"Heat transfer by electromagnetic waves that can ignite materials across an air gap without contact is called:", opts:["Convection","Conduction","Radiation","Diffusion"], correct:2, re:"Radiation transfers heat as electromagnetic waves and can ignite materials at a distance (e.g., breaking windows, igniting nearby buildings). Source: heat-transfer fundamentals (Warren Forensics; Ark-FP)."},
  {id:8, block:1, sec:"Fire Science & Suppression Basics", q:"A Class A fire involves which type of fuel?", opts:["Energized electrical equipment","Ordinary combustibles such as wood, paper, and cloth","Flammable liquids such as gasoline","Combustible metals such as magnesium"], correct:1, re:"Class A = ordinary combustibles (wood, paper, cloth, many plastics); water is well suited to Class A fires. Source: NFPA 10 fire-class definitions; Pye-Barker classes of fire."},
  {id:9, block:1, sec:"Fire Science & Suppression Basics", q:"Which class of fire involves flammable or combustible LIQUIDS and gases (gasoline, oil, solvents)?", opts:["Class A","Class C","Class B","Class D"], correct:2, re:"Class B = flammable liquids and gases (gasoline, oil, solvents). Plain water can spread these fires, so foam or other agents are used. Source: NFPA 10 fire-class definitions; Swartz Fire & Safety."},
  {id:10, block:1, sec:"Fire Science & Suppression Basics", q:"Which class of fire involves ENERGIZED electrical equipment, where a conductive agent like water is hazardous?", opts:["Class B","Class A","Class C","Class K"], correct:2, re:"Class C = fires in energized electrical equipment; non-conductive agents are required. Once power is removed it may become a Class A or B fire. Source: NFPA 10; UCLA Health classes of fire."},
  {id:11, block:1, sec:"Fire Science & Suppression Basics", q:"Class K fires, requiring special wet-chemical agents, involve which fuel?", opts:["Cooking oils and fats (commercial kitchens)","Combustible metals","Energized electronics","Paper and wood"], correct:0, re:"Class K = cooking oils/fats; wet-chemical agents saponify the grease to cool and seal it against re-ignition. Source: NFPA 10; NFPA 17A / Pye-Barker classes of fire."},
  {id:12, block:1, sec:"Fire Science & Suppression Basics", q:"When water absorbs heat and turns to steam, the large expansion in volume helps suppression by:", opts:["Adding fuel to the fire","Displacing oxygen around the fire and absorbing heat","Increasing the chemical chain reaction","Raising the fuel's temperature"], correct:1, re:"Converting to steam absorbs large amounts of heat (latent heat of vaporization) and the steam expansion displaces oxygen near the seat of the fire, aiding control. Source: fire-suppression fundamentals; water as a Class A agent (NFPA)."},
  {id:13, block:1, sec:"Fire Science & Suppression Basics", q:"The temperature at which a material gives off enough vapor to ignite momentarily when an ignition source is present is called its:", opts:["Boiling point","Freezing point","Flash point","Specific heat"], correct:2, re:"Flash point is the lowest temperature at which a liquid gives off vapor in sufficient concentration to flash (ignite momentarily) near an ignition source. Source: NFPA 30 / fire-science fundamentals (flammable & combustible liquids)."},
  {id:14, block:1, sec:"Fire Science & Suppression Basics", q:"'Flashover' in a compartment fire refers to:", opts:["The first flame becoming visible","An electrical short circuit","Water flashing into steam at a sprinkler","The near-simultaneous ignition of all exposed combustibles in a room as it reaches full involvement"], correct:3, re:"Flashover is the transition to full-room involvement when radiant heat ignites nearly all exposed surfaces at once. Residential sprinklers (NFPA 13D) aim to prevent flashover to allow escape. Source: fire-dynamics fundamentals; NFPA 13D life-safety objective."},
  {id:15, block:1, sec:"Fire Science & Suppression Basics", q:"Compared with merely 'controlling' a fire, to 'suppress' a fire means to:", opts:["Sound the alarm only","Sharply reduce the heat-release rate and prevent regrowth, working toward extinguishment","Keep the fire size constant","Vent smoke from the building"], correct:1, re:"Control limits fire growth and pre-wets surroundings; suppression sharply reduces heat release and prevents regrowth (the goal of ESFR sprinklers). Source: NFPA 13 control vs. suppression concepts; ESFR design intent."},
  {id:16, block:1, sec:"Fire Science & Suppression Basics", q:"Why is plain water generally NOT recommended as the primary agent on a Class B flammable-liquid pool fire?", opts:["It freezes too quickly","Lighter-than-water fuels can float and spread, and water can splash burning liquid","Water adds nitrogen to the fire","Water is non-conductive"], correct:1, re:"Many flammable liquids are lighter than and immiscible with water, so a water stream can spread the burning fuel; foam (not plain water) is used for such fires. Source: NFPA 10/11; fire-class agent selection."},
  {id:17, block:1, sec:"Fire Science & Suppression Basics", q:"In fire suppression terms, applying a foam blanket over a liquid fuel surface works mainly by:", opts:["Cooling the chain reaction electrically","Separating the fuel from oxygen (and suppressing vapors)","Adding oxygen","Increasing radiant heat"], correct:1, re:"Foam blankets the fuel, excluding oxygen and suppressing flammable vapors (it also cools). This attacks the oxygen and fuel-vapor legs of the tetrahedron. Source: NFPA 11 foam fundamentals; fire tetrahedron suppression methods."},
  {id:18, block:1, sec:"Wet Pipe Systems", q:"In a wet pipe sprinkler system, the piping is normally filled with:", opts:["Pressurized air only","Water under pressure","Pressurized nitrogen","Antifreeze gas"], correct:1, re:"A wet pipe system has piping constantly filled with water under pressure, so water discharges immediately when a sprinkler opens. Source: NFPA 13 definition of wet pipe system; NFPA 'Types of Sprinkler Systems.'"},
  {id:19, block:1, sec:"Wet Pipe Systems", q:"Which statement about water-delivery speed is correct for wet pipe systems?", opts:["They are the slowest of all system types","They deliver water faster than dry, preaction, or deluge systems because water is already at the sprinkler","They deliver water only after a detector trips","They require an accelerator to deliver water"], correct:1, re:"Because water is already in the pipe with no intermediate trip, wet pipe systems deliver water faster than any other system type, minimizing fire growth. Source: NFPA 'Sprinkler System Basics: Types of Sprinkler Systems.'"},
  {id:20, block:1, sec:"Wet Pipe Systems", q:"What is the single biggest limitation that makes a standard wet pipe system unsuitable for some areas?", opts:["It cannot be used above 2 stories","It cannot use pendent sprinklers","It requires nitrogen generators","The water in the pipe can freeze in unheated/below-freezing spaces"], correct:3, re:"Standing water in wet pipe makes it unsuitable for areas subject to freezing unless protected (e.g., antifreeze loop or dry/preaction used instead). Source: NFPA 13; Ryan F.P. wet vs. dry differences."},
  {id:21, block:1, sec:"Wet Pipe Systems", q:"In a wet pipe system, an individual sprinkler operates (opens) when:", opts:["A smoke detector sends a signal","The fire alarm panel commands it","Its heat-sensitive element (glass bulb or fusible link) reaches its rated temperature","A manual pull station is activated"], correct:2, re:"Each closed sprinkler opens individually when its own thermal element reaches its temperature rating; only sprinklers over the fire operate. Source: NFPA 13; QRFS thermal-sensitivity guide."},
  {id:22, block:1, sec:"Wet Pipe Systems", q:"A common misconception is that 'all sprinklers go off at once' in a fire. In a typical wet pipe system:", opts:["Every sprinkler in the building discharges together","No sprinkler operates without the alarm panel","Half the building's sprinklers operate","Only the sprinkler(s) whose thermal element has reached its rating operate"], correct:3, re:"Standard sprinklers are individually heat-activated; usually only one or a few over the fire open, unlike a deluge system. Source: NFPA public-education materials; NFPA 13 operation."},
  {id:23, block:1, sec:"Wet Pipe Systems", q:"Which valve is commonly used on a wet pipe riser to detect water flow and initiate an alarm?", opts:["An alarm check valve","A deluge valve","A dry pipe valve","A pressure-reducing valve"], correct:0, re:"A wet pipe riser typically uses an alarm check valve (or a 'shotgun' riser with a flow switch) to detect flow and initiate the waterflow alarm. Source: Code Red Consultants 'Alarm Check Valves'; NFPA 13 riser components."},
  {id:24, block:1, sec:"Wet Pipe Systems", q:"On a wet pipe system, the purpose of a RETARD CHAMBER associated with the alarm check valve is to:", opts:["Store antifreeze","Reduce false alarms from brief water-pressure surges","Speed up water delivery","Drain the entire system"], correct:1, re:"The retard chamber adds a short mechanical delay so momentary supply-pressure surges don't trip the waterflow alarm; it fills before the alarm sounds. Source: NFPA 13; Code Red Consultants alarm check valve trim."},
  {id:25, block:1, sec:"Wet Pipe Systems", q:"A water motor gong (mechanical alarm) on a wet system is driven by:", opts:["Building electrical power","Water pressure/flow alone","A battery backup only","Compressed air"], correct:1, re:"The water motor gong is hydraulically driven by system water flow and needs no electricity, providing an audible mechanical alarm. Source: QRFS 'How Does a Water Motor Gong Work.'"},
  {id:26, block:1, sec:"Wet Pipe Systems", q:"Which of these is a key ADVANTAGE of wet pipe systems over other types?", opts:["Simplicity, reliability, low maintenance, and fastest water delivery","They are the most mechanically complex","They never need any drains","They eliminate the need for a water supply"], correct:0, re:"Wet pipe systems are the simplest and most reliable, with the fewest components and the fastest water delivery, which is why they are the most widely used. Source: NFPA 'Types of Sprinkler Systems'; Engineered Fire Systems technical guide."},
  {id:27, block:1, sec:"Wet Pipe Systems", q:"For a small, normally heated office building, which system type is usually the default and most economical choice?", opts:["Deluge system","Double-interlock preaction system","Wet pipe system","Dry pipe system"], correct:2, re:"In heated occupancies a wet pipe system is normally the default — simplest, cheapest, fastest. Dry/preaction/deluge are reserved for freezing or special-hazard conditions. Source: NFPA system-selection guidance; Engineered Fire Systems guide."},
  {id:28, block:1, sec:"Wet Pipe Systems", q:"What does a main drain (typically 2 in.) at the wet pipe riser allow a technician to do?", opts:["Add nitrogen","Increase the air pressure","Drain the system and perform a main-drain flow test of the water supply","Bypass the backflow preventer permanently"], correct:2, re:"The main drain lets the system be drained and is used for the main-drain test that verifies water-supply condition. Source: NFPA 13/NFPA 25 main-drain test; riser components."},
  {id:29, block:1, sec:"Wet Pipe Systems", q:"If a heated building has a small unheated area (like a loading dock canopy), a common wet-system solution for just that area is:", opts:["Converting the whole building to deluge","Removing all sprinklers there","An antifreeze loop or a dry-pendent/dry-sidewall sprinkler off the wet system","Filling the area's pipe with nitrogen"], correct:2, re:"Small freeze-exposed areas off a wet system are commonly served by a listed antifreeze loop or by dry-pendent/dry-sidewall sprinklers that keep water back in the heated space. Source: NFPA 13 antifreeze and dry-sprinkler provisions; QRFS dry-sprinkler guide."},
  {id:30, block:1, sec:"Wet Pipe Systems", q:"Why must a wet pipe system maintain a continuous water supply at adequate pressure?", opts:["To keep the air compressor running","To prevent the glass bulbs from freezing","So that any operating sprinkler immediately receives water at the required flow and pressure","To keep the deluge valve closed"], correct:2, re:"Operation depends on the supply delivering required flow/pressure to operating sprinklers; hydraulic calculations confirm the supply meets the demand. Source: NFPA 13 water-supply and hydraulic design requirements."},
  {id:31, block:1, sec:"Wet Pipe Systems", q:"On a wet pipe system, the inspector's test connection is used to:", opts:["Add antifreeze to the system","Pressurize the system with air","Simulate the flow of a single sprinkler to verify the waterflow alarm operates","Test the fire pump churn pressure"], correct:2, re:"The inspector's test connection discharges water at a flow equivalent to the smallest sprinkler's orifice to confirm the waterflow alarm functions. Source: NFPA 13/NFPA 25 inspector's test connection."},
  {id:32, block:1, sec:"Wet Pipe Systems", q:"Which sprinkler thermal element is held closed by a liquid-filled glass capsule that shatters when the liquid expands?", opts:["Fusible-link sprinkler","Quick-opening device","Open (deluge) sprinkler","Glass-bulb sprinkler"], correct:3, re:"In a glass-bulb sprinkler the heated liquid expands until the bulb shatters, releasing the cap. Fusible-link types instead use a solder alloy that melts. Source: QRFS sprinkler thermal-sensitivity; NFSA sprinkler operation."},
  {id:33, block:1, sec:"Wet Pipe Systems", q:"The sprinkler 'K-factor' is a measure of the sprinkler's:", opts:["Temperature rating color","Pipe thread size","Discharge coefficient — relating flow rate to the square root of pressure","Corrosion resistance"], correct:2, re:"K-factor is the discharge coefficient in Q = K√P; a larger K passes more water at a given pressure. Source: NFPA 13 hydraulic principles; sprinkler K-factor definition."},
  {id:34, block:1, sec:"Wet Pipe Systems", q:"Standard upright and pendent spray sprinklers commonly have a nominal K-factor around:", opts:["K=1000","K=200","K=0.5","K=5.6 (about 80 in U.S. units family, e.g., K5.6/K8.0)"], correct:3, re:"Standard-orifice sprinklers are typically K5.6 (1/2 in.) or K8.0, far below high-flow ESFR heads (K14.2-K25.2). Source: NFPA 13 sprinkler tables; CA-FIRE ESFR vs. standard K-factors."},
  {id:35, block:1, sec:"Dry Pipe Systems", q:"In a dry pipe sprinkler system, the piping above the dry pipe valve is normally filled with:", opts:["Water under pressure","Pressurized air or nitrogen","Antifreeze solution","Foam concentrate"], correct:1, re:"Dry pipe systems hold the piping under pressurized air or nitrogen; the air holds the dry pipe valve closed until a sprinkler opens. Source: NFPA 13 dry pipe system definition; QRFS dry-systems guide."},
  {id:36, block:1, sec:"Dry Pipe Systems", q:"The PRIMARY reason to use a dry pipe system instead of a wet pipe system is:", opts:["To deliver water faster","To avoid needing a water supply","To reduce the number of sprinklers","To protect spaces subject to freezing where standing water would be a problem"], correct:3, re:"Dry pipe systems are used where freezing temperatures would freeze water in a wet system (unheated warehouses, parking garages, freezers, etc.). Source: NFPA 13; QRFS 'A Guide to Dry Sprinkler Systems.'"},
  {id:37, block:1, sec:"Dry Pipe Systems", q:"In a dry pipe valve, a relatively small amount of air pressure holds back a much larger water pressure. This is known as the valve's:", opts:["Friction loss","Residual","Velocity head","Differential"], correct:3, re:"The dry pipe valve uses a differential design: a larger air-side clapper area lets modest air pressure hold back higher water pressure (e.g., a ~5.5:1 or 6:1 ratio). Source: NFSA 'Determining Differential for Dry Pipe Valves.'"},
  {id:38, block:1, sec:"Dry Pipe Systems", q:"If a differential dry pipe valve has roughly a 6:1 differential, then about 1 psi of air can hold back approximately:", opts:["1 psi of water","0.6 psi of water","60 psi of water","6 psi of water"], correct:3, re:"At a 6:1 differential, 1 psi of air holds back about 6 psi of water (e.g., 30 psi air holds ~180 psi water). Source: Construction-manuals differential dry pipe valve; NFSA differential article."},
  {id:39, block:1, sec:"Dry Pipe Systems", q:"When a sprinkler on a dry pipe system opens, the sequence is:", opts:["Water flows instantly with no delay","A detector must trip before air can escape","Air escapes first, the dry pipe valve trips, then water flows to the open sprinkler","The deluge valve opens all sprinklers"], correct:2, re:"The open sprinkler bleeds the air, system pressure falls, the differential is lost, the clapper trips, and water then travels to the open sprinkler — inherently slower than wet pipe. Source: NFPA 13; QRFS dry-systems operation."},
  {id:40, block:1, sec:"Dry Pipe Systems", q:"A QUICK-OPENING DEVICE such as an accelerator is added to a dry pipe system to:", opts:["Speed up tripping of the dry pipe valve by hastening the air-pressure drop at the valve","Slow down the water delivery","Add antifreeze automatically","Increase the air pressure during a fire"], correct:0, re:"An accelerator senses the air-pressure drop and redirects air to the valve's intermediate chamber, equalizing pressure so the clapper trips sooner — reducing water-delivery time. Source: Code Red Consultants 'Quick-Opening Devices'; QRFS trip-testing guide."},
  {id:41, block:1, sec:"Dry Pipe Systems", q:"Per NFPA 13, dry pipe systems generally must deliver water to the inspector's test connection within how many seconds (with stated exceptions for small/QOD-equipped systems)?", opts:["10 seconds","30 minutes","5 minutes","60 seconds"], correct:3, re:"NFPA 13 sets a 60-second maximum water-delivery time to the test connection, with exceptions for systems =500 gal, or =750 gal with a quick-opening device. Source: NFPA 13 (2019) 8.2.3; Sprinkler Age 'Dry Pipe Water Delivery Time.'"},
  {id:42, block:1, sec:"Dry Pipe Systems", q:"Without a quick-opening device, NFPA 13 limits an individual dry pipe system volume to a maximum of about:", opts:["100 gallons","5,000 gallons","500 gallons","50 gallons"], correct:2, re:"NFPA 13 caps an individual dry system at 500 gal without a quick-opening device (and 750 gal with one) to keep delivery times acceptable. Source: NFPA 13 8.2.3.3/8.2.3.4; UpCodes 'Size of Systems.'"},
  {id:43, block:1, sec:"Dry Pipe Systems", q:"With a quick-opening device, NFPA 13 allows an individual dry pipe system volume up to a maximum of about:", opts:["2,000 gallons","250 gallons","750 gallons","100 gallons"], correct:2, re:"With a quick-opening device the maximum individual dry system size is 750 gal; above that, delivery-time tables apply. Source: NFPA 13 8.2.3.4; Code Red Consultants QOD article."},
  {id:44, block:1, sec:"Dry Pipe Systems", q:"Why are dry pipe systems more susceptible to internal corrosion than wet pipe systems?", opts:["Trapped air plus residual water/condensate create oxygen-rich conditions promoting corrosion","They use copper only","They run at higher water pressure","They contain antifreeze"], correct:0, re:"The mix of trapped oxygen (air) with residual moisture/condensate accelerates internal corrosion; nitrogen is often used instead of air to reduce it. Source: ORR Protection corrosion guidance; NFPA 13 corrosion considerations."},
  {id:45, block:1, sec:"Dry Pipe Systems", q:"Using NITROGEN instead of compressed air in a dry system primarily helps by:", opts:["Lowering the freezing point of water","Eliminating the need for a dry pipe valve","Increasing water pressure","Reducing internal corrosion because nitrogen is inert (displaces oxygen)"], correct:3, re:"Nitrogen is inert and oxygen-poor, so it slows the oxidation/corrosion that compressed air promotes inside dry/preaction piping. Source: ORR Protection; United Fire Systems nitrogen technical note."},
  {id:46, block:1, sec:"Dry Pipe Systems", q:"Because residual water can be trapped after a trip, dry pipe piping must be pitched (sloped) so that:", opts:["Condensate and water drain to the dry pipe valve or to auxiliary (low-point) drains","Air pressure rises automatically","The sprinklers face upward","The alarm cannot sound"], correct:0, re:"NFPA 13 requires dry/preaction pipe to be pitched to drain toward the valve or auxiliary low-point drains so trapped water doesn't freeze. Mains ~1/4 in./10 ft, branch lines ~1/2 in./10 ft. Source: NFPA 13 slope requirements; FPS-EG slope guide."},
  {id:47, block:1, sec:"Dry Pipe Systems", q:"A 'drum drip' or auxiliary drain at a low point of a dry system is provided to:", opts:["Add nitrogen to the riser","Test the fire pump","Speed up the accelerator","Periodically remove accumulated condensate/water from trapped low sections"], correct:3, re:"Low-point auxiliary drains (drum drips) let technicians bleed off condensate that collects in trapped sections, preventing freezing and corrosion. Source: AGF Mfg auxiliary-drain guidance; NFPA 13 auxiliary drains."},
  {id:48, block:1, sec:"Dry Pipe Systems", q:"NFPA 13 generally requires the air or nitrogen supply to restore normal system pressure within about how long after a drop?", opts:["30 minutes","5 seconds","8 hours","3 days"], correct:0, re:"The air/nitrogen supply must be able to restore normal system pressure within 30 minutes; an air-maintenance device regulates make-up pressure. Source: NFPA 13 8.2.6; QRFS 'Air Compressors and Air Maintenance Devices.'"},
  {id:49, block:1, sec:"Dry Pipe Systems", q:"What is the role of an AIR-MAINTENANCE DEVICE on a dry pipe system?", opts:["It opens all the sprinklers","It regulates make-up air so the system stays at the proper supervisory pressure without over-pressurizing","It drains the system after a fire","It replaces the dry pipe valve"], correct:1, re:"The air-maintenance device (regulator with restriction/bypass) tops up small leaks to keep supervisory air pressure correct while preventing rapid refill that could mask a trip. Source: QRFS air-maintenance device guide; NFPA 13."},
  {id:50, block:1, sec:"Dry Pipe Systems", q:"A key trade-off (disadvantage) of dry pipe vs. wet pipe systems is:", opts:["They cost less and are simpler","Delayed water delivery and greater complexity/maintenance (air supply, drains, corrosion)","They cannot protect freezing areas","They use no valves"], correct:1, re:"Dry systems trade away speed and simplicity: water is delayed, and they add air supplies, low-point drains, and corrosion management. Source: NFPA 'Types of Sprinkler Systems'; Engineered Fire Systems guide."},
  {id:51, block:1, sec:"Dry Pipe Systems", q:"After a dry pipe system trips and is restored, why is prompt draining of trapped water especially important in a freezer or below-freezing space?", opts:["Because trapped water can freeze within minutes and damage/block the piping","To recharge the battery","To reset the smoke detectors","To lower the water supply pressure"], correct:0, re:"In spaces at/below 0°F, trapped water can begin to freeze within minutes after a trip, so low points must be drained promptly. Source: AGF Mfg freeze-prevention; NFPA 13 freezing-area drainage."},
  {id:52, block:1, sec:"Preaction & Deluge Systems", q:"A preaction sprinkler system can be thought of as a combination of:", opts:["A wet system and a standpipe","A dry pipe system plus a separate fire-detection system that controls a preaction valve","Two deluge valves in series","An antifreeze loop and a fire pump"], correct:1, re:"Preaction systems use closed sprinklers on pipe held dry (air/nitrogen or supervised) and a separate detection system that opens the preaction valve, admitting water. Source: NFPA 13; NFPA 'Types of Sprinkler Systems.'"},
  {id:53, block:1, sec:"Preaction & Deluge Systems", q:"The MAIN benefit of a preaction system is that it:", opts:["Reduces the risk of accidental water discharge where water damage would be especially costly","Discharges water from all heads at once","Eliminates the need for sprinklers","Delivers water faster than a wet system"], correct:0, re:"By requiring an event (detection and/or sprinkler operation) before water enters the pipe, preaction guards against accidental discharge in spaces like data centers, archives, and museums. Source: NFPA; Impact Fire pre-action overview."},
  {id:54, block:1, sec:"Preaction & Deluge Systems", q:"In a SINGLE-INTERLOCK preaction system, water is admitted to the piping when:", opts:["The fire-detection system operates (a detector trips)","Both a detector operates AND a sprinkler opens","Only a sprinkler opens with no detection","The main drain is opened"], correct:0, re:"Single-interlock admits water upon operation of the detection system (one event); the closed sprinklers then discharge as they open. Source: NFPA 13; SF-Fire single/double interlock guidance."},
  {id:55, block:1, sec:"Preaction & Deluge Systems", q:"In a DOUBLE-INTERLOCK preaction system, water is admitted to the piping only when:", opts:["A detector OR a sprinkler operates (either one)","The alarm panel loses power","The air compressor starts","BOTH the detection system operates AND a sprinkler opens"], correct:3, re:"Double-interlock requires two independent events — detection AND sprinkler operation (air loss) — before water enters, giving the highest protection against accidental discharge (common in freezers). Source: NFPA 13; SF-Fire double-interlock guidance."},
  {id:56, block:1, sec:"Preaction & Deluge Systems", q:"In a NON-INTERLOCK preaction system, water is admitted to the piping when:", opts:["Only the alarm panel is reset","Both detection AND sprinkler must operate","Either the detection system operates OR a sprinkler opens","The system is drained"], correct:2, re:"Non-interlock admits water upon operation of detection OR sprinklers (either event), so even sprinkler operation alone (without detection) will let water in. Source: NFPA 13; SF-Fire interlock comparison."},
  {id:57, block:1, sec:"Preaction & Deluge Systems", q:"Which application is a CLASSIC use for a preaction system because of sensitivity to water damage?", opts:["A data center / computer room or rare-book archive","An open parking deck","An outdoor loading dock","A swimming pool deck"], correct:0, re:"Preaction systems are favored for data centers, telecom rooms, archives, libraries, and museums where an accidental discharge would be very damaging. Source: NFPA; Impact Fire pre-action applications."},
  {id:58, block:1, sec:"Preaction & Deluge Systems", q:"For water-delivery purposes, a DOUBLE-INTERLOCK preaction system is generally treated like a:", opts:["Dry pipe system (delivery delayed; larger design area)","Wet pipe system","Deluge system with open heads","Standpipe"], correct:0, re:"Because the pipe is dry and both events are required, double-interlock systems are treated like dry pipe systems for delivery time and use a larger design area. Source: NFPA 13; BERMAD/phcppros preaction discussion."},
  {id:59, block:1, sec:"Preaction & Deluge Systems", q:"NFPA 13 limits the number of automatic sprinklers controlled by a single preaction valve to approximately:", opts:["10 sprinklers","1,000 sprinklers","100,000 sprinklers","25 sprinklers"], correct:1, re:"NFPA 13 limits a single (interlock) preaction valve to about 1,000 automatic sprinklers. Source: NFPA 13; NY-Engineers / NFSA preaction design notes."},
  {id:60, block:1, sec:"Preaction & Deluge Systems", q:"A DELUGE system differs fundamentally from wet, dry, and preaction systems because it uses:", opts:["Only glass-bulb sprinklers","Antifreeze in every line","OPEN sprinklers/nozzles (no thermal element) on the piping","A retard chamber instead of a valve"], correct:2, re:"In a deluge system all sprinklers/nozzles are OPEN (no heat-sensitive element); when the deluge valve opens, water flows from every head simultaneously. Source: NFPA 13; NFPA 'Types of Sprinkler Systems.'"},
  {id:61, block:1, sec:"Preaction & Deluge Systems", q:"A deluge system discharges water by:", opts:["Each sprinkler opening individually as it heats","Bleeding air through an accelerator","Melting a fusible link at one head","Opening the deluge valve (via a detection system), flooding all open heads at once"], correct:3, re:"A detection system (heat/flame/smoke) opens the deluge valve, and because all heads are open, water discharges from the entire system simultaneously. Source: NFPA 13; VFP/Oliver deluge overviews."},
  {id:62, block:1, sec:"Preaction & Deluge Systems", q:"Deluge systems are typically used in which kind of hazard?", opts:["High-hazard areas with rapid fire-spread potential (aircraft hangars, flammable-liquid/chemical areas, power plants)","Low-hazard offices","Residential bedrooms","Refrigerated archives"], correct:0, re:"Deluge systems suit high-hazard, fast-spreading fires — aircraft hangars (often foam-water per NFPA 409), flammable-liquid and chemical facilities, and power plants. Source: NFPA; Oliver/Interstate deluge applications."},
  {id:63, block:1, sec:"Preaction & Deluge Systems", q:"What primarily controls when a deluge system discharges?", opts:["A separate fire-detection system that signals the deluge valve to open","The temperature rating of individual heads","The freezing point of the water","The pitch of the piping"], correct:0, re:"Because the heads have no thermal element, discharge timing is set entirely by the separate detection system opening the deluge valve. Source: NFPA 13; deluge-system fundamentals."},
  {id:64, block:1, sec:"Preaction & Deluge Systems", q:"In an aircraft hangar, a deluge system is frequently combined with which agent for flammable-liquid fire control?", opts:["Firefighting foam (foam-water deluge)","Dry chemical powder","Carbon dioxide flooding","Clean-agent gas"], correct:0, re:"Large aircraft hangars commonly use foam-water deluge systems (per NFPA 409) to combat fuel-spill fires over large floor areas. Source: NFPA 409; deluge foam-water references (Security Fire / DTIC hangar study)."},
  {id:65, block:1, sec:"Preaction & Deluge Systems", q:"Why are preaction and deluge systems considered MORE complex and maintenance-intensive than wet pipe systems?", opts:["They use fewer parts","They depend on a separate detection system and special valves that must be tested and maintained","They have no valves at all","They never require any testing"], correct:1, re:"Both rely on detection equipment and special valves (preaction/deluge), adding components, wiring, and periodic testing beyond a simple wet system. Source: NFPA 13/NFPA 25; system-comparison references."},
  {id:66, block:1, sec:"Preaction & Deluge Systems", q:"Compared with a single-interlock preaction system, a double-interlock system generally provides:", opts:["Faster water delivery","No detection requirement","Open sprinkler heads","Greater protection against accidental discharge but slower water delivery"], correct:3, re:"Requiring both detection and sprinkler operation maximizes protection against inadvertent water flow but delays delivery (treated like dry pipe). Source: NFPA 13; SF-Fire interlock comparison."},
  {id:67, block:1, sec:"Preaction & Deluge Systems", q:"In a preaction system, the closed sprinklers are typically installed on piping that is:", opts:["Always full of water at all times","Filled with foam concentrate","Normally dry / supervised (air or pressurized monitoring), with water held back by the preaction valve","Filled with antifreeze in every branch"], correct:2, re:"Preaction piping is normally dry (often supervised with low-pressure air/nitrogen), and water is held back by the preaction valve until the controlling event occurs. Source: NFPA 13; Reliable preaction design guide."},
  {id:68, block:1, sec:"Preaction & Deluge Systems", q:"A deluge system's open nozzles arranged to apply water over a defined area or object are often used for:", opts:["Drinking-water distribution","Cooling/protecting equipment such as transformers or spray booths","Heating the building","Replacing the fire alarm"], correct:1, re:"Deluge/water-spray systems apply water over a surface or object (transformers, vessels, spray booths) for control, cooling, or exposure protection. Source: NFPA 15 water spray / NFPA 13 deluge applications."},
  {id:69, block:1, sec:"System Components Overview", q:"The vertical pipe at the source of a sprinkler system, where the main control valve and alarm devices are usually located, is called the:", opts:["Branch line","Riser","Cross main","Drop nipple"], correct:1, re:"The riser is the vertical supply pipe carrying water up into the system; the riser assembly typically holds the main control valve, check/alarm valve, gauges, and drains. Source: NFPA 13 system components; Capitol Fire 'Fire Sprinkler Parts.'"},
  {id:70, block:1, sec:"System Components Overview", q:"In sprinkler pipe layout, the pipes that the sprinklers themselves are directly attached to are the:", opts:["Cross mains","Branch lines","Feed mains","Risers"], correct:1, re:"Branch lines are the pipes that carry sprinklers; branch lines connect to cross mains, which are fed by feed mains from the riser. Source: NFPA 13 piping terminology."},
  {id:71, block:1, sec:"System Components Overview", q:"The pipe that supplies water to the cross mains (which in turn feed the branch lines) is the:", opts:["Feed main","Drop","Sprig","Armover"], correct:0, re:"Feed mains supply cross mains; cross mains supply branch lines; branch lines carry the sprinklers. Source: NFPA 13 piping terminology / system layout."},
  {id:72, block:1, sec:"System Components Overview", q:"A FIRE DEPARTMENT CONNECTION (FDC) on a sprinkler system allows the fire department to:", opts:["Drain the system to the sewer","Test the smoke detectors","Shut off the city water main","Pump additional water/pressure into the system from their apparatus"], correct:3, re:"The FDC lets responding apparatus boost water and pressure into the sprinkler/standpipe system to supplement the supply. Source: NFPA 13/NFPA 14 FDC; QRFS components guide."},
  {id:73, block:1, sec:"System Components Overview", q:"A CHECK VALVE in a fire sprinkler system functions to:", opts:["Reduce the water temperature","Open all the sprinklers","Allow water flow in one direction only and prevent backflow","Add air to the system"], correct:2, re:"A check valve permits flow in one direction and prevents reverse flow (e.g., keeping system water from flowing back into the supply). Source: QRFS 'Guide to Check Valves'; NFPA 13."},
  {id:74, block:1, sec:"System Components Overview", q:"The main system control valve (e.g., an OS&Y or butterfly indicating valve) must be:", opts:["Hidden and unmarked","Removed during a fire","A listed indicating valve that shows whether it is open or shut, and supervised/secured open","Painted to match the wall"], correct:2, re:"Control valves must be listed indicating valves whose open/shut position is visible, and they must be supervised or locked open so the supply is not inadvertently closed. Source: NFPA 13 control valves; NFPA 25 valve supervision."},
  {id:75, block:1, sec:"System Components Overview", q:"A waterflow alarm/pressure switch on a sprinkler riser is used to:", opts:["Regulate the antifreeze concentration","Detect water moving in the system and send an electrical alarm signal","Pressurize the dry pipe valve","Reduce supply pressure"], correct:1, re:"A waterflow (pressure) switch senses flow at the riser and transmits an electrical signal to the alarm panel/bell to indicate system operation. Source: NFPA 13/NFPA 72 waterflow alarm; riser components."},
  {id:76, block:1, sec:"System Components Overview", q:"Sprinkler system gauges at the riser typically display:", opts:["Outdoor temperature","The number of sprinklers installed","Antifreeze color","System and supply water pressure (and air pressure on dry/preaction systems)"], correct:3, re:"Riser gauges show supply and system pressure (and on dry/preaction risers, the air/nitrogen pressure above the valve). Source: NFPA 13 gauges; riser-assembly components."},
  {id:77, block:1, sec:"System Components Overview", q:"A PENDENT sprinkler is installed so that it:", opts:["Points upward above the branch pipe","Has no deflector","Sprays sideways from a wall","Hangs down below the pipe/ceiling and sprays water downward in a circular pattern"], correct:3, re:"A pendent sprinkler hangs below the piping/ceiling with its deflector at the bottom, distributing water down and out over the floor area. Source: QRFS 'Fire Sprinkler Head Types'; NFPA 13 deflector position."},
  {id:78, block:1, sec:"System Components Overview", q:"An UPRIGHT sprinkler is installed so that it:", opts:["Sits above the branch pipe and sprays water up into its deflector, which redirects it downward","Hangs below the pipe","Mounts horizontally on a wall","Discharges only upward"], correct:0, re:"An upright sprinkler sits above the branch line; water strikes the top-mounted deflector and is redirected down in a hemispherical/fan pattern (useful where the pipe is exposed). Source: QRFS sprinkler head types; NFPA 13."},
  {id:79, block:1, sec:"System Components Overview", q:"A SIDEWALL sprinkler is used to:", opts:["Discharge only straight down from the center of a room","Drain the system","Replace the dry pipe valve","Mount on a wall and throw water horizontally across a room (useful where overhead piping is impractical)"], correct:3, re:"Sidewall sprinklers mount on a wall/beam and project water horizontally with an asymmetric deflector, used where ceiling piping is impractical (corridors, small rooms). Source: QRFS sidewall sprinklers; NFPA 13."},
  {id:80, block:1, sec:"System Components Overview", q:"The COLOR of a glass-bulb sprinkler (e.g., red, orange, green) primarily indicates its:", opts:["Temperature rating","Manufacturer","Pipe thread size","K-factor exactly"], correct:0, re:"Glass-bulb liquid color indicates the temperature rating (e.g., orange ~135°F, red ~155°F, green ~200°F); fusible-link types use a frame-arm color code. Source: NFPA 13 temperature ratings; NFSA sprinkler colors."},
  {id:81, block:1, sec:"System Components Overview", q:"An 'ordinary' temperature-rated sprinkler typically operates in which approximate range?", opts:["32°F to 60°F","500°F to 650°F","135°F to 170°F","1000°F and above"], correct:2, re:"Ordinary-rated sprinklers operate roughly 135-170°F; intermediate is ~175-225°F, with higher classes for hotter environments. Source: NFPA 13 temperature ratings; TPMC/Kord temperature tables."},
  {id:82, block:1, sec:"System Components Overview", q:"Sprinkler system piping and components installed aboveground are commonly rated for a maximum working pressure of at least:", opts:["175 psi","50 psi","1,000 psi","10 psi"], correct:0, re:"NFPA 13 aboveground components are generally rated for 175 psi working pressure (higher-pressure components are required where pressures exceed that). Source: NFPA 13 component rating; Eng-Tips/NFPA 13 pressure discussion."},
  {id:83, block:1, sec:"System Components Overview", q:"New sprinkler piping is hydrostatically tested per NFPA 13 at 200 psi, or at what level if the working pressure is higher?", opts:["At exactly the working pressure","At 500 psi regardless","At 10 psi below working pressure","At 50 psi above the maximum system working pressure"], correct:3, re:"NFPA 13 requires a 2-hour hydrostatic test at 200 psi, or 50 psi above the maximum working pressure when that exceeds 150 psi, whichever is greater. Source: NFPA 13 hydrostatic testing; Fire Safety Central testing guide."},
  {id:84, block:1, sec:"System Components Overview", q:"A backflow prevention assembly is installed on many sprinkler systems primarily to:", opts:["Increase sprinkler flow","Protect the public/potable water supply from contamination by system water","Speed up the dry pipe valve","Replace the riser check valve's alarm function"], correct:1, re:"Backflow preventers keep potentially stagnant or treated system water from flowing back into the potable supply, protecting public health (required by many water purveyors/codes). Source: NFPA 13 / local water-purveyor cross-connection rules."},
  {id:85, block:1, sec:"NFPA 13 Scope & Occupancy Intro", q:"What is the title and purpose of NFPA 13?", opts:["Standard for Portable Fire Extinguishers","Standard for Fire Alarm Systems","National Electrical Code","Standard for the Installation of Sprinkler Systems — providing minimum requirements for design and installation"], correct:3, re:"NFPA 13 is the 'Standard for the Installation of Sprinkler Systems,' giving minimum design/installation requirements to protect life and property. Source: NFPA 13 scope/purpose; NFPA product page."},
  {id:86, block:1, sec:"NFPA 13 Scope & Occupancy Intro", q:"NFPA 13 has the BROADEST scope of the installation standards because it:", opts:["Applies only to single-family homes","Only covers high-rise buildings","Only covers warehouses","Can be used to sprinkler virtually any building/occupancy type"], correct:3, re:"Any building can be protected under NFPA 13; NFPA 13R and 13D are narrower residential standards. Source: NFPA 'Differences Between NFPA 13, 13R, and 13D.'"},
  {id:87, block:1, sec:"NFPA 13 Scope & Occupancy Intro", q:"NFPA 13D is the standard for sprinkler systems in:", opts:["One- and two-family dwellings and manufactured homes","High-rise office towers","Aircraft hangars","Chemical plants"], correct:0, re:"NFPA 13D covers one- and two-family dwellings and manufactured homes (and certain townhomes), focused on life safety/escape. Source: NFPA 13D scope; NFPA 13 vs 13R vs 13D comparison."},
  {id:88, block:1, sec:"NFPA 13 Scope & Occupancy Intro", q:"NFPA 13R is the standard for sprinkler systems in residential occupancies up to:", opts:["Forty stories","Four stories in height (and not over 60 ft)","Single-family homes only","Underground only"], correct:1, re:"NFPA 13R applies to residential occupancies up to and including four stories (not exceeding 60 ft), e.g., low-rise apartments. Source: NFPA 13R scope; NFPA comparison article."},
  {id:89, block:1, sec:"NFPA 13 Scope & Occupancy Intro", q:"A central life-safety GOAL of an NFPA 13D residential system is to:", opts:["Help prevent flashover in the room of origin so occupants can escape","Protect the structure for many hours","Discharge from all sprinklers at once","Replace smoke alarms"], correct:0, re:"NFPA 13D aims to control a fire and prevent flashover long enough for occupants to escape, prioritizing life safety over property protection. Source: NFPA 13D objectives; NFPA comparison article."},
  {id:90, block:1, sec:"NFPA 13 Scope & Occupancy Intro", q:"NFPA 13 classifies occupancies by hazard. The three broad occupancy hazard classes are:", opts:["Wet, dry, and preaction","Light hazard, ordinary hazard, and extra hazard","Class A, B, and C","Residential, commercial, and industrial"], correct:1, re:"NFPA 13 occupancy hazard classes are Light, Ordinary, and Extra hazard; Ordinary and Extra each split into Group 1 and Group 2. Source: NFPA 13 Chapter 4; NFPA 'Occupancy Classifications in NFPA 13.'"},
  {id:91, block:1, sec:"NFPA 13 Scope & Occupancy Intro", q:"Which occupancy is an example of LIGHT HAZARD under NFPA 13?", opts:["An office, church, or school classroom","A paint/spray finishing operation","A tire-manufacturing plant","An oil refinery"], correct:0, re:"Light hazard = low quantity/combustibility contents: offices, churches, schools, hospitals, museums, most residential. Source: NFPA 13 light-hazard examples; phcppros occupancy article."},
  {id:92, block:1, sec:"NFPA 13 Scope & Occupancy Intro", q:"Ordinary Hazard (Group 1 or 2) occupancies are characterized by:", opts:["Moderate combustible loading/combustibility (e.g., laundries, machine shops, mercantile)","Negligible combustibles","Only flammable liquids","No contents at all"], correct:0, re:"Ordinary hazard covers moderate combustibility/quantity: OH-1 (e.g., parking garages, laundries, restaurant service) and OH-2 (e.g., machine shops, mercantile, woodworking). Source: NFPA 13 occupancy classes; NFPA blog."},
  {id:93, block:1, sec:"NFPA 13 Scope & Occupancy Intro", q:"Extra Hazard occupancies under NFPA 13 involve:", opts:["The lowest fire severity","Only empty attics","High combustible/flammable loading or processes (e.g., spray painting, flammable liquids, certain manufacturing)","Only office spaces"], correct:2, re:"Extra hazard = high quantities of combustibles and/or flammable liquids: EH-1 (e.g., printing, certain textiles) and EH-2 (e.g., spray painting, flammable-liquid handling). Source: NFPA 13 extra-hazard examples; NFPA blog."},
  {id:94, block:1, sec:"NFPA 13 Scope & Occupancy Intro", q:"Why does correctly classifying the occupancy hazard matter for sprinkler design?", opts:["It sets the paint color of the pipe","It has no effect on design","It decides the sprinkler bulb manufacturer","It determines the required design density/area and water demand for the system"], correct:3, re:"Occupancy hazard drives the design density and design area (and thus water demand); a higher hazard requires more water over a larger area. Source: NFPA 13 design approaches; hazard-classification design rules."},
  {id:95, block:1, sec:"NFPA 13 Scope & Occupancy Intro", q:"In addition to occupancy hazard, NFPA 13 separately classifies stored goods using:", opts:["Sprinkler color codes","Standpipe classes","Pipe schedule numbers","Commodity classifications (e.g., Class I-IV and plastics)"], correct:3, re:"Storage protection uses commodity classifications (Class I-IV and various plastics/rubber) in addition to occupancy hazard to set storage sprinkler criteria. Source: NFPA 13 Chapter on classification of commodities; Koorsen commodity guide."},
  {id:96, block:1, sec:"NFPA 13 Scope & Occupancy Intro", q:"An ESFR (Early Suppression Fast Response) sprinkler is designed mainly to:", opts:["Control fires only, never suppress","Protect only light-hazard offices","Suppress high-challenge storage fires quickly, often avoiding in-rack sprinklers","Operate all heads simultaneously like a deluge"], correct:2, re:"ESFR uses high K-factor, fast-response heads to SUPPRESS (not just control) storage fires, often eliminating in-rack sprinklers. Source: NFPA 13 ESFR design; Precision FP / CA-FIRE ESFR overview."},
  {id:97, block:1, sec:"NFPA 13 Scope & Occupancy Intro", q:"A standpipe system (NFPA 14) primarily provides:", opts:["Antifreeze to sprinklers","Piping and hose connections so firefighters/occupants can apply hose streams within a building","Air pressure to dry systems","Backflow prevention only"], correct:1, re:"Standpipes are vertical/horizontal piping with hose-valve connections that supply water for manual firefighting inside buildings (especially high-rises). Source: NFPA 14 standpipe systems; NFPA standpipe design blog."},
  {id:98, block:1, sec:"NFPA 13 Scope & Occupancy Intro", q:"A CLASS I standpipe (NFPA 14) provides which hose connection, intended for the fire department?", opts:["1-inch garden hose","2½-inch hose connections","No hose connections","½-inch test connection"], correct:1, re:"Class I standpipes provide 2½-in. connections for fire-department use; Class II provides 1½-in. for occupants; Class III provides both. Source: NFPA 14; CA-FIRE / J.F. Ahern standpipe classes."},
  {id:99, block:1, sec:"NFPA 13 Scope & Occupancy Intro", q:"Under NFPA 13, antifreeze used in NEW sprinkler systems must be:", opts:["Any household automotive antifreeze","Saltwater","Pure glycerine at any concentration","A listed, factory-premixed antifreeze solution"], correct:3, re:"NFPA 13 now requires listed, factory-premixed antifreeze for new systems; older field-mixed glycerine/propylene glycol can act as fuel at high concentrations and is no longer permitted for new installs. Source: NFPA 13 7.6 antifreeze; NFSA listed-antifreeze guidance."},
  {id:100, block:1, sec:"NFPA 13 Scope & Occupancy Intro", q:"In California, which CSLB classification covers water-based fire protection (sprinkler and standpipe) work?", opts:["C-10 Electrical","C-16 Fire Protection Contractor","C-36 Plumbing","C-20 HVAC"], correct:1, re:"The C-16 Fire Protection classification covers laying out, fabricating, and installing fire-protection systems including water-based sprinkler and standpipe systems (electrical alarm work falls under C-10). Source: CSLB C-16 classification description; CSLB C-16 study guide."},
  {id:101, block:2, sec:"Sprinkler Head Types & Orientation", q:"On a pendent sprinkler, where is the deflector positioned relative to the waterway, and which way is the spray directed?", opts:["Below the orifice, spray directed downward","Above the orifice, spray directed upward","Beside the orifice, spray directed sideways","Behind the orifice, spray directed backward"], correct:0, re:"A pendent sprinkler hangs down from the pipe with the deflector below the waterway so the discharging water strikes it and forms an umbrella-shaped pattern downward. Source: NFPA 13 sprinkler definitions; sprinkler head type references."},
  {id:102, block:2, sec:"Sprinkler Head Types & Orientation", q:"An upright (SSU) spray sprinkler is installed so that water is discharged in what direction before being dispersed by the deflector?", opts:["Upward against the deflector, then dispersed downward","Horizontally along the ceiling first","Straight down with no deflector action","Into the pipe to build pressure"], correct:0, re:"An upright sprinkler sits above the branch line; water is thrown upward against the deflector, which then disperses it downward over the area. Source: NFPA 13; SSU (Standard Spray Upright) sprinkler references."},
  {id:103, block:2, sec:"Sprinkler Head Types & Orientation", q:"A sidewall sprinkler is primarily used in which situation?", opts:["Where piping cannot be run across the ceiling, discharging from a wall","In freezers to prevent freezing of the head","Only on the riser as a test connection","Exclusively in ESFR storage applications"], correct:0, re:"Sidewall sprinklers project water out from a wall and are used in rooms (corridors, hotel rooms) where it is impractical to run branch lines across the ceiling. Source: NFPA 13 sidewall sprinkler provisions."},
  {id:104, block:2, sec:"Sprinkler Head Types & Orientation", q:"In a concealed sprinkler assembly, what hides the sprinkler from view, and what happens to it in a fire?", opts:["A glass dome that shatters at 1000°F","A metal guard that is removed by the fire department","A cover plate that drops away at a lower temperature than the sprinkler","A plastic cap that the occupant must remove manually"], correct:2, re:"A concealed sprinkler is hidden by a decorative cover plate held on by solder rated to release at a temperature below the sprinkler's own rating, so the plate drops first and lets the head operate. Source: NFPA 13; concealed sprinkler/cover-plate listings."},
  {id:105, block:2, sec:"Sprinkler Head Types & Orientation", q:"The cover plate of a concealed sprinkler is listed to release at a temperature that is which of the following relative to the sprinkler's operating temperature?", opts:["Lower, so the plate drops before the head operates","Higher, so the head operates before the plate drops","Identical, so they operate at the same instant","Unrelated and chosen by the installer at random"], correct:0, re:"Cover plates are rated lower (commonly at least about 20°F cooler) than the sprinkler so the plate falls away first and does not block operation; ratings such as 135°F and 165°F are common. Source: NFPA 13; cover-plate temperature listings."},
  {id:106, block:2, sec:"Sprinkler Head Types & Orientation", q:"ESFR stands for which of the following?", opts:["Early Suppression Fast Response","Extended Spray Fire Response","Enhanced Storage Fire Resistance","Elevated Sidewall Flow Rate"], correct:0, re:"ESFR = Early Suppression Fast Response, a sprinkler designed to suppress (not just control) high-challenge storage fires using high-momentum droplets and a fast-response element. Source: NFPA 13 Chapter on ESFR sprinklers."},
  {id:107, block:2, sec:"Sprinkler Head Types & Orientation", q:"ESFR sprinklers are most commonly applied in which type of occupancy?", opts:["Light-hazard offices and schools","Open parking garages only","High-piled storage and warehouse occupancies","Residential single-family dwellings only"], correct:2, re:"ESFR sprinklers are intended for high-challenge fires such as high-piled/rack storage warehouses, where they can suppress the fire at the ceiling without in-rack sprinklers in many layouts. Source: NFPA 13 storage/ESFR provisions."},
  {id:108, block:2, sec:"Sprinkler Head Types & Orientation", q:"A dry-pendent (dry-type) sprinkler is specifically used in which application?", opts:["Where the head extends into an unheated/freezing space from a heated wet pipe","Only in ESFR rack-storage rooms","As the standard head for light-hazard offices","On the fire department connection inlet"], correct:0, re:"A dry-pendent sprinkler has a sealed drop tube that keeps water back out of the head, allowing a sprinkler to serve a freezer or unheated area while connected to a wet system in a heated space. Source: NFPA 13; dry sprinkler listings."},
  {id:109, block:2, sec:"Sprinkler Head Types & Orientation", q:"Residential sprinklers (per NFPA 13D/13R) are required to be which response type?", opts:["Quick (fast) response","Standard response only","High-temperature only","Non-listed of any type"], correct:0, re:"Residential sprinklers are listed quick-response devices designed to wet walls and improve tenability for occupant escape; standard-response heads do not meet the residential listing. Source: NFPA 13D/13R residential sprinkler requirements."},
  {id:110, block:2, sec:"Sprinkler Head Types & Orientation", q:"What is the main purpose of the deflector on a spray sprinkler?", opts:["To break the water stream into a defined distribution pattern","To hold the glass bulb in place during shipping","To sense heat and trigger the sprinkler","To connect the sprinkler to the branch line"], correct:0, re:"The deflector is the plate the discharging stream strikes; its shape and orientation break the water into the listed spray pattern (umbrella, sidewall, ESFR, etc.). Source: NFPA 13 sprinkler definitions."},
  {id:111, block:2, sec:"Sprinkler Head Types & Orientation", q:"A recessed sprinkler differs from a flush or concealed sprinkler in that it is:", opts:["Installed with part of the body in a recessed escutcheon but the operating element still exposed","Mounted entirely above the ceiling with no head exposed","Always an upright head in a pit","A head with no deflector"], correct:0, re:"A recessed sprinkler sits partly up in a recessed escutcheon for appearance, but the heat-sensing element remains in the room (unlike a concealed head hidden by a cover plate). Source: NFPA 13; recessed sprinkler/escutcheon listings."},
  {id:112, block:2, sec:"Sprinkler Head Types & Orientation", q:"Why must the correct escutcheon or cover plate be used with a recessed or concealed sprinkler?", opts:["It must be part of the listed assembly because it affects activation and spray","It is purely decorative and has no effect on performance","Any escutcheon may be substituted to save cost","It is required only for upright sprinklers"], correct:0, re:"Escutcheons and cover plates are part of the listed sprinkler assembly; using a non-matching part can change the head's thermal response and water distribution. Source: NFPA 13 accessory/listing requirements."},
  {id:113, block:2, sec:"Sprinkler Head Types & Orientation", q:"An upright sprinkler is generally preferred over a pendent in which situation?", opts:["Where the branch piping is exposed below the ceiling and collecting dust/obstructions is a concern","In smooth-ceiling finished offices only","Where the head must be hidden from view","Only on residential systems"], correct:0, re:"Uprights are favored on exposed piping (e.g., mechanical rooms, unfinished ceilings) where they sit above the pipe and are less prone to collecting debris that a pendent drop might. Source: NFPA 13; sprinkler orientation guidance."},
  {id:114, block:2, sec:"Sprinkler Head Types & Orientation", q:"A pendent sprinkler installed in the upright position (or vice versa) creates what problem?", opts:["No problem, orientation does not matter","Faster, better coverage","An incorrect, unlisted spray pattern that may not protect the area","Automatic conversion to an ESFR head"], correct:2, re:"Deflectors are designed for a specific orientation; installing a pendent as upright (or the reverse) produces an unlisted, distorted pattern and is not permitted. Source: NFPA 13 installation requirements for spray sprinklers."},
  {id:115, block:2, sec:"Sprinkler Head Types & Orientation", q:"The letters 'SSU' stamped relative to a sprinkler indicate which type?", opts:["Standard Spray Upright","Sidewall Storage Unit","Special Suppression Unit","Standard Sidewall Upright"], correct:0, re:"SSU = Standard Spray Upright; the companion designation SSP = Standard Spray Pendent. Source: sprinkler manufacturer/NFPA 13 nomenclature."},
  {id:116, block:2, sec:"Sprinkler Head Types & Orientation", q:"An open sprinkler (used in a deluge system) differs from a standard automatic sprinkler because it:", opts:["Has a larger glass bulb","Operates only at high temperature","Has no heat-responsive element and is always open","Is always a sidewall type"], correct:2, re:"Open sprinklers have the fusible link/bulb removed so all heads flow at once when the deluge valve opens; they are not heat-activated individually. Source: NFPA 13 deluge/open sprinkler provisions."},
  {id:117, block:2, sec:"Sprinkler Head Types & Orientation", q:"Extended-coverage sprinklers are listed to do which of the following compared with standard-spray sprinklers?", opts:["Cover a smaller area at higher pressure only","Operate only as upright heads","Cover a larger floor area per sprinkler when installed per their listing","Eliminate the need for any hydraulic calculation"], correct:2, re:"Extended-coverage sprinklers are specifically listed and tested to protect a larger area per head than standard-spray sprinklers, within the spacing/pressure limits of their listing. Source: NFPA 13 extended-coverage sprinkler provisions."},
  {id:118, block:2, sec:"Temperature & Response Ratings", q:"Per NFPA 13, the ordinary temperature classification covers which rating range?", opts:["100°F to 130°F","175°F to 225°F","135°F to 170°F","250°F to 300°F"], correct:2, re:"Ordinary-temperature sprinklers are rated 135°F–170°F (57°C–77°C) and are used in most normally occupied spaces. Source: NFPA 13 temperature ratings table."},
  {id:119, block:2, sec:"Temperature & Response Ratings", q:"The intermediate temperature classification per NFPA 13 covers which rating range?", opts:["135°F to 170°F","250°F to 300°F","175°F to 225°F","325°F to 375°F"], correct:2, re:"Intermediate-temperature sprinklers are rated 175°F–225°F (79°C–107°C), used where ambient heat is elevated (near skylights, unit heaters, etc.). Source: NFPA 13 temperature ratings table."},
  {id:120, block:2, sec:"Temperature & Response Ratings", q:"A fire-sprinkler glass bulb filled with ORANGE liquid corresponds to which temperature rating?", opts:["135°F","155°F","200°F","286°F"], correct:0, re:"In the NFPA color code for glass bulbs, orange = 135°F, red = 155°F, yellow = 174°F, green = 200°F, blue = 286°F, purple = 360°F. Source: NFPA 13 color-code references."},
  {id:121, block:2, sec:"Temperature & Response Ratings", q:"A fire-sprinkler glass bulb filled with RED liquid corresponds to which temperature rating?", opts:["135°F","200°F","155°F","360°F"], correct:2, re:"Red glass-bulb liquid indicates a 155°F (68°C) sprinkler, the most common ordinary-temperature rating. Source: NFPA 13 color-code references."},
  {id:122, block:2, sec:"Temperature & Response Ratings", q:"A GREEN glass-bulb sprinkler is rated for approximately which temperature?", opts:["135°F","174°F","200°F","286°F"], correct:2, re:"Green bulb liquid = 200°F (93°C), an intermediate-temperature rating. Source: NFPA 13 glass-bulb color code."},
  {id:123, block:2, sec:"Temperature & Response Ratings", q:"What does the temperature rating of a sprinkler represent?", opts:["The ceiling height in feet","The water pressure in psi","The nominal temperature at which the heat-sensitive element operates","The pipe size in inches"], correct:2, re:"The temperature rating is the nominal operating temperature of the fusible link or glass bulb, selected with a margin above expected maximum ambient temperature. Source: NFPA 13 temperature-rating selection."},
  {id:124, block:2, sec:"Temperature & Response Ratings", q:"For ordinary-temperature (135–170°F) sprinklers, NFPA 13 limits the maximum ambient ceiling temperature to about:", opts:["100°F","150°F","225°F","300°F"], correct:0, re:"Ordinary-rated heads are limited to a maximum ceiling temperature of 100°F; above that an intermediate or higher rating is required to avoid nuisance operation. Source: NFPA 13 maximum ceiling temperature table."},
  {id:125, block:2, sec:"Temperature & Response Ratings", q:"For intermediate-temperature (175–225°F) sprinklers, the maximum permitted ambient ceiling temperature is about:", opts:["100°F","250°F","150°F","350°F"], correct:2, re:"Intermediate-rated sprinklers are permitted up to a maximum ceiling temperature of 150°F. Source: NFPA 13 maximum ceiling temperature table."},
  {id:126, block:2, sec:"Temperature & Response Ratings", q:"The primary difference between a Quick Response (QR) and a Standard Response (SR) glass-bulb sprinkler of the same temperature is:", opts:["The QR bulb is thinner (about 3 mm) for faster thermal response","The QR head discharges more water","The SR head has no deflector","The QR head is always high-temperature rated"], correct:0, re:"QR and SR can share a temperature rating; the QR bulb is smaller in diameter (≈3 mm vs ≈5 mm) so it heats and operates faster (lower RTI). Source: NFPA 13; sprinkler response/thermal-sensitivity references."},
  {id:127, block:2, sec:"Temperature & Response Ratings", q:"RTI (Response Time Index) is a measure of a sprinkler's:", opts:["Discharge coefficient","Corrosion resistance","Thermal sensitivity (how fast it responds to heat)","Maximum working pressure"], correct:2, re:"RTI quantifies the thermal sensitivity of the operating element; a lower RTI means faster response. Source: NFPA 13; sprinkler thermal-sensitivity references."},
  {id:128, block:2, sec:"Temperature & Response Ratings", q:"A sprinkler is generally classified as quick (fast) response when its RTI is approximately:", opts:["50 (m·s)^1/2 or less","Exactly 100 (m·s)^1/2","200 (m·s)^1/2 or more","Unrelated to RTI"], correct:0, re:"Fast/quick-response sprinklers have an RTI of about 50 (m·s)^1/2 or less; standard-response is about 80 (m·s)^1/2 or higher. Source: NFPA 13; sprinkler response-classification references."},
  {id:129, block:2, sec:"Temperature & Response Ratings", q:"A standard-response sprinkler typically has an RTI of approximately:", opts:["Less than 20 (m·s)^1/2","Exactly 50 (m·s)^1/2","80 (m·s)^1/2 or more","Negative values"], correct:2, re:"Standard-response sprinklers have an RTI of roughly 80 (m·s)^1/2 or greater (slower thermal response than quick-response). Source: NFPA 13; sprinkler response-classification references."},
  {id:130, block:2, sec:"Temperature & Response Ratings", q:"Quick-response sprinklers are most associated with which hazard classification?", opts:["High-piled storage only","Extra-hazard chemical plants only","Light-hazard occupancies (offices, schools)","Outdoor loading docks only"], correct:2, re:"QR sprinklers are predominantly installed in light-hazard occupancies, where their faster response improves life safety. Source: NFPA 13; QR application references."},
  {id:131, block:2, sec:"Temperature & Response Ratings", q:"On a fusible-link (solder-type) sprinkler, the temperature rating is typically indicated by:", opts:["The color of the water in a bulb","The shape of the deflector","A color code on the frame arms or link","The size of the orifice"], correct:2, re:"Solder/fusible-link sprinklers carry their temperature color code on the frame arms (or the link), since they have no liquid bulb. Source: NFPA 13 color-code provisions."},
  {id:132, block:2, sec:"Temperature & Response Ratings", q:"Why are higher-temperature-rated sprinklers installed near unit heaters, skylights, or in attics?", opts:["To make them operate faster in a fire","Because they discharge less water","To prevent nuisance operation from high ambient heat","Because code prohibits ordinary heads in any commercial building"], correct:2, re:"Where ambient temperatures run high, a higher-rated head avoids accidental operation from heat that is not a fire; the rating is matched to the expected maximum ceiling temperature. Source: NFPA 13 temperature-selection provisions."},
  {id:133, block:2, sec:"Temperature & Response Ratings", q:"A BLUE glass-bulb sprinkler corresponds to which approximate temperature rating?", opts:["155°F","200°F","286°F","360°F"], correct:2, re:"Blue bulb liquid indicates a 286°F (141°C) high-temperature sprinkler. Source: NFPA 13 glass-bulb color code."},
  {id:134, block:2, sec:"Temperature & Response Ratings", q:"The high temperature classification per NFPA 13 covers which rating range?", opts:["135°F to 170°F","175°F to 225°F","250°F to 300°F","400°F to 475°F"], correct:2, re:"The high-temperature classification is 250°F–300°F (121°C–149°C). Source: NFPA 13 temperature ratings table."},
  {id:135, block:2, sec:"K-Factors & Orifices", q:"In the sprinkler discharge formula Q = K√P, what does Q represent?", opts:["Flow rate in gpm","Pressure in psi","Pipe diameter in inches","The K-factor"], correct:0, re:"Q is the discharge (flow) in gallons per minute; K is the discharge coefficient and P is the pressure at the sprinkler in psi. Source: NFPA 13 hydraulic/discharge formula."},
  {id:136, block:2, sec:"K-Factors & Orifices", q:"In Q = K√P, the term P represents:", opts:["The flow in gpm","The temperature rating","The pipe length","The pressure at the sprinkler in psi"], correct:3, re:"P is the pressure at the sprinkler orifice in psi; the square root of P is multiplied by the K-factor to get flow Q. Source: NFPA 13 discharge formula."},
  {id:137, block:2, sec:"K-Factors & Orifices", q:"The K-factor of a sprinkler is best described as:", opts:["The orifice discharge coefficient relating flow to pressure","The temperature rating divided by 10","The thread size in millimeters","The hanger spacing in feet"], correct:0, re:"The K-factor is the nominal discharge coefficient that ties flow to the square root of pressure (Q = K√P); a larger K means a larger effective orifice. Source: NFPA 13 K-factor definition."},
  {id:138, block:2, sec:"K-Factors & Orifices", q:"The most common standard-orifice spray sprinkler has a nominal K-factor of:", opts:["2.8","25.2","14.0","5.6"], correct:3, re:"K = 5.6 (US units) is the standard 1/2 in. orifice spray sprinkler, the most widely used K-factor. Source: NFPA 13; standard-orifice sprinkler data."},
  {id:139, block:2, sec:"K-Factors & Orifices", q:"For a given pressure, a sprinkler with a LARGER K-factor will:", opts:["Discharge less water","Not discharge at all","Discharge the same water","Discharge more water"], correct:3, re:"Because Q = K√P, increasing K at the same pressure increases flow; larger K-factors mean larger orifices and higher discharge. Source: NFPA 13 discharge formula."},
  {id:140, block:2, sec:"K-Factors & Orifices", q:"A K=5.6 sprinkler flowing at 7 psi discharges approximately how much water? (Q = 5.6 × √7)", opts:["About 8 gpm","About 100 gpm","About 56 gpm","About 15 gpm"], correct:3, re:"√7 ≈ 2.646, so Q ≈ 5.6 × 2.646 ≈ 14.8 ≈ 15 gpm. Source: NFPA 13 discharge formula (Q = K√P)."},
  {id:141, block:2, sec:"K-Factors & Orifices", q:"NFPA 13 sets the minimum operating pressure for most standard spray sprinklers at:", opts:["1 psi","50 psi","25 psi","7 psi"], correct:3, re:"The minimum operating pressure for standard spray sprinklers under NFPA 13 is 7 psi. Source: NFPA 13 minimum operating pressure provisions."},
  {id:142, block:2, sec:"K-Factors & Orifices", q:"ESFR sprinklers are available in which set of nominal K-factors?", opts:["2.8 and 4.2","5.6 and 8.0 only","14.0, 16.8, and 25.2","0.5 and 1.0"], correct:2, re:"ESFR sprinklers use large orifices with nominal K-factors of 14.0, 16.8, and 25.2 (and larger) to deliver high flows for storage fires. Source: NFPA 13 ESFR provisions."},
  {id:143, block:2, sec:"K-Factors & Orifices", q:"If a sprinkler's K-factor doubles while pressure stays the same, the flow Q will:", opts:["Stay the same","Increase fourfold","Be halved","Double"], correct:3, re:"Q is directly proportional to K (Q = K√P); doubling K at constant P doubles the flow. Source: NFPA 13 discharge formula."},
  {id:144, block:2, sec:"K-Factors & Orifices", q:"To DOUBLE the flow from a single sprinkler by raising pressure alone, the pressure must be increased by a factor of:", opts:["2","16","8","4"], correct:3, re:"Because Q ∝ √P, doubling Q requires quadrupling P (√4 = 2). Source: NFPA 13 discharge formula."},
  {id:145, block:2, sec:"K-Factors & Orifices", q:"The standard 1/2 in. orifice spray sprinkler corresponds to a nominal orifice (thread) size of:", opts:["1/4 in.","2 in.","1 in.","1/2 in."], correct:3, re:"The standard-orifice spray sprinkler (K=5.6) has a nominal 1/2 in. orifice/thread connection. Source: NFPA 13; standard-orifice sprinkler data."},
  {id:146, block:2, sec:"K-Factors & Orifices", q:"A large-orifice spray sprinkler commonly has a nominal K-factor of:", opts:["2.8","5.6","8.0","0.5"], correct:2, re:"K = 8.0 is the common large-orifice spray sprinkler, discharging more water than the K=5.6 standard orifice at the same pressure. Source: NFPA 13; large-orifice sprinkler data."},
  {id:147, block:2, sec:"K-Factors & Orifices", q:"Why are larger-K (larger-orifice) sprinklers often used to lower required system pressure?", opts:["They discharge the needed flow at a lower pressure","They cost less to manufacture","They eliminate the need for a deflector","They reduce the temperature rating"], correct:0, re:"For a target flow, a larger K delivers it at lower pressure (P = (Q/K)^2), which can reduce pump/water-supply demand. Source: NFPA 13 hydraulic design principles."},
  {id:148, block:2, sec:"K-Factors & Orifices", q:"A K=8.0 sprinkler must flow 24 gpm. The required pressure P = (Q/K)^2 is approximately:", opts:["About 3 psi","About 64 psi","About 24 psi","About 9 psi"], correct:3, re:"(24/8)^2 = 3^2 = 9 psi. Source: NFPA 13 discharge formula rearranged, P = (Q/K)^2."},
  {id:149, block:2, sec:"K-Factors & Orifices", q:"In the inch-pound (US) form of Q = K√P, the units of the K-factor are:", opts:["gpm/psi","gpm·psi","psi/gpm","gpm/(psi)^1/2"], correct:3, re:"K has units of gpm per square-root-psi, i.e., gpm/(psi)^1/2, so that K√P yields gpm. Source: NFPA 13 hydraulic formula definitions."},
  {id:150, block:2, sec:"K-Factors & Orifices", q:"Two identical sprinklers on a branch line see different pressures. Compared with the head nearest the supply, the most remote head will:", opts:["Flow more water","Not flow at all","Flow exactly the same","Flow less water due to lower available pressure"], correct:3, re:"Friction loss reduces pressure along the line, so the most remote sprinkler usually has the lowest pressure and lowest flow (Q = K√P). This is why the remote area governs design. Source: NFPA 13 hydraulic calculation principles."},
  {id:151, block:2, sec:"Pipe, Tube & Fittings", q:"Schedule 40 steel pipe differs from Schedule 10 steel pipe primarily in that Schedule 40 has:", opts:["A thicker wall","A thinner wall","A larger outside diameter for the same nominal size","No threads allowed"], correct:0, re:"For a given nominal size the outside diameter is the same; Schedule 40 has a thicker wall (smaller bore) than Schedule 10. Source: NFPA 13 pipe schedules; ASTM steel-pipe standards."},
  {id:152, block:2, sec:"Pipe, Tube & Fittings", q:"Per NFPA 13, threading is generally permitted on which steel pipe?", opts:["Schedule 10 only","Only copper tube","Any wall thickness without restriction","Schedule 40 (or heavier), unless lighter wall is specifically listed for threading"], correct:3, re:"Threads cut into the wall, so NFPA 13 permits threading Schedule 40 or heavier; thinner pipe may be threaded only if specifically listed. Source: NFPA 13 joining-methods provisions."},
  {id:153, block:2, sec:"Pipe, Tube & Fittings", q:"Thin-wall Schedule 10 steel pipe is typically joined by:", opts:["Cut threads","Compression sleeves only","Solvent cement","Roll-grooved couplings or welding"], correct:3, re:"Schedule 10 is too thin to thread safely, so it is roll-grooved (grooved couplings) or welded. Source: NFPA 13 joining methods; steel-pipe references."},
  {id:154, block:2, sec:"Pipe, Tube & Fittings", q:"CPVC pipe used in fire sprinkler systems is joined by:", opts:["Brazing","Threading","Solvent cement welding","Roll grooving"], correct:2, re:"Listed CPVC (e.g., BlazeMaster) is joined with the manufacturer's solvent cement; it is not threaded, brazed, or grooved. Source: NFPA 13; listed CPVC installation instructions."},
  {id:155, block:2, sec:"Pipe, Tube & Fittings", q:"Listed CPVC sprinkler pipe is generally limited to which system type?", opts:["Dry-pipe systems only","High-temperature industrial systems","Deluge systems only","Wet-pipe systems (with listing limitations)"], correct:3, re:"Listed CPVC is used in wet-pipe systems within its listing; it is not used in dry/preaction air-filled systems and must be protected from excessive temperatures. Source: NFPA 13; CPVC product listings."},
  {id:156, block:2, sec:"Pipe, Tube & Fittings", q:"A typical listed CPVC sprinkler pipe is rated for service up to approximately:", opts:["150°F","300°F","500°F","750°F"], correct:0, re:"Listed CPVC (e.g., BlazeMaster) is rated for sprinkler service up to about 150°F (65°C); above that it must be insulated/ventilated or another material used. Source: listed CPVC product ratings."},
  {id:157, block:2, sec:"Pipe, Tube & Fittings", q:"Copper tube used for sprinkler piping is most commonly joined by:", opts:["Solvent cement","Cut threads","Roll grooving only","Brazing or soldering (soldering allowed in light hazard wet systems)"], correct:3, re:"Copper tube is brazed; NFPA 13 permits soldered joints for wet-pipe light-hazard systems. It is not solvent-cemented. Source: NFPA 13 copper joining provisions."},
  {id:158, block:2, sec:"Pipe, Tube & Fittings", q:"For copper water tube, which type has the THICKEST wall?", opts:["Type M","Type L","Type K","Type DWV"], correct:2, re:"Among copper water tube, Type K is the heaviest wall, Type L is medium, and Type M is the lightest. Source: ASTM B88; copper tube types."},
  {id:159, block:2, sec:"Pipe, Tube & Fittings", q:"A reducing coupling in sprinkler piping is used to:", opts:["Change the direction of the pipe 90°","Provide a test connection","Cap the end of a line","Connect two pipes of different diameters in line"], correct:3, re:"A reducer/reducing coupling joins two different pipe sizes in a straight run; elbows change direction and caps close ends. Source: standard pipe-fitting nomenclature."},
  {id:160, block:2, sec:"Pipe, Tube & Fittings", q:"A 'tee' fitting in sprinkler piping is used to:", opts:["Close the end of a branch line","Allow only one-way flow","Join two pipes of the same size straight in line only","Create a branch (90° take-off) from a run of pipe"], correct:3, re:"A tee provides a side outlet (branch) from a main run; common in sprinkler mains to feed branch lines. Source: standard pipe-fitting nomenclature."},
  {id:161, block:2, sec:"Pipe, Tube & Fittings", q:"In NFPA 13 hydraulic calculations, fittings such as elbows and tees are accounted for using:", opts:["Their actual measured length only","Their color code","Their weight in pounds","Equivalent pipe lengths (friction-loss equivalents)"], correct:3, re:"Fittings add friction loss represented as 'equivalent length' of pipe added to the actual pipe length in the Hazen-Williams calculation. Source: NFPA 13 equivalent-length tables."},
  {id:162, block:2, sec:"Pipe, Tube & Fittings", q:"Galvanized steel pipe is sometimes specified for which sprinkler system to resist corrosion?", opts:["Wet-pipe light-hazard offices","Copper systems","CPVC systems","Dry-pipe and preaction systems (interior subject to condensation)"], correct:3, re:"Galvanizing is often used in dry-pipe/preaction systems where trapped air and condensate accelerate internal corrosion. Source: NFPA 13; corrosion-control practice for dry systems."},
  {id:163, block:2, sec:"Pipe, Tube & Fittings", q:"The Hazen-Williams 'C' factor in sprinkler hydraulics represents:", opts:["The pipe's internal roughness/smoothness for friction loss","The pipe temperature rating","The sprinkler K-factor","The seismic load"], correct:0, re:"The C-factor describes interior pipe smoothness; higher C (e.g., copper/CPVC) means lower friction loss than rougher pipe (e.g., older steel). Source: NFPA 13 Hazen-Williams C-values."},
  {id:164, block:2, sec:"Pipe, Tube & Fittings", q:"Compared with steel, listed CPVC pipe generally has a Hazen-Williams C-factor that is:", opts:["Lower (rougher)","Negative","Identical to steel","Higher (smoother), reducing friction loss"], correct:3, re:"CPVC and copper have higher C-values (smoother bore) than steel, so they produce less friction loss for the same flow. Source: NFPA 13 Hazen-Williams C-values."},
  {id:165, block:2, sec:"Pipe, Tube & Fittings", q:"A grooved (roll-grooved) coupling joins steel pipe by:", opts:["Melting the pipe ends together","Threading into a coupling","Gluing with solvent cement","Engaging a groove rolled or cut near the pipe end with a gasketed housing"], correct:3, re:"Grooved couplings clamp a two-piece housing into a groove at each pipe end, sealing with a gasket; common and fast for steel sprinkler pipe. Source: NFPA 13; grooved-fitting listings."},
  {id:166, block:2, sec:"Pipe, Tube & Fittings", q:"A union or grooved coupling near a valve or device is provided mainly to:", opts:["Increase water pressure","Serve as a sprinkler head","Change the pipe material","Allow the device to be removed/serviced without cutting the pipe"], correct:3, re:"A union/flange/grooved coupling provides a break point so valves, alarm devices, etc., can be serviced or replaced without cutting piping. Source: standard installation practice; NFPA 13/25 serviceability."},
  {id:167, block:2, sec:"Pipe, Tube & Fittings", q:"NFPA 13 requires that pipe, fittings, valves, and devices used in a sprinkler system be:", opts:["Painted red regardless of listing","Sized at 6 in. minimum","Made only of copper","Listed/approved for fire protection service or meeting referenced standards"], correct:3, re:"Components must be listed/approved or comply with the standards referenced by NFPA 13; arbitrary substitution of non-listed parts is not permitted. Source: NFPA 13 materials and listing requirements."},
  {id:168, block:2, sec:"Valves (Control, Check, Alarm)", q:"An OS&Y valve gets its name from which design feature?", opts:["Outside Screw and Yoke (rising stem)","Open System and Yield","Orifice Sizing and Yaw","Overhead Sprinkler and Yard"], correct:0, re:"OS&Y = Outside Screw and Yoke; the threaded stem rises outside the body through the yoke, visibly indicating open/closed position. Source: NFPA 13; OS&Y valve references."},
  {id:169, block:2, sec:"Valves (Control, Check, Alarm)", q:"On an OS&Y gate valve, you can tell the valve is OPEN because:", opts:["The handwheel is removed","A green light turns on automatically","The valve hums","The threaded stem protrudes (rises) out through the yoke"], correct:3, re:"When an OS&Y valve is open, the rising stem extends out through the yoke; a retracted stem means closed. This visible indication is why it qualifies as an indicating valve. Source: NFPA 13; OS&Y operation."},
  {id:170, block:2, sec:"Valves (Control, Check, Alarm)", q:"NFPA 13 requires sprinkler system control valves to be of what type?", opts:["Non-indicating only","Pressure-reducing only","Spring-loaded check valves","Indicating type (open/closed status visible)"], correct:3, re:"Control valves must be indicating so personnel can verify the water supply is open without operating the valve (OS&Y, butterfly with position indicator, PIV, wall PIV). Source: NFPA 13 control-valve requirements."},
  {id:171, block:2, sec:"Valves (Control, Check, Alarm)", q:"A butterfly valve controls flow by:", opts:["Raising and lowering a gate","Rotating a disc 90° within the pipe","Melting a fusible link","Opening a clapper by water pressure"], correct:1, re:"A butterfly valve turns a disc 90° to start/stop flow; for fire service it is an indicating valve with a position indicator and is supervised. Source: NFPA 13; butterfly valve references."},
  {id:172, block:2, sec:"Valves (Control, Check, Alarm)", q:"Most fire-protection butterfly control valves include which feature for monitoring?", opts:["A built-in sprinkler head","An integral tamper (supervisory) switch","A flow meter only","A retard chamber"], correct:1, re:"Fire-service butterfly valves typically come with a tamper/supervisory switch that signals the panel if the valve is moved from full open. Source: NFPA 13/NFPA 72; valve supervision."},
  {id:173, block:2, sec:"Valves (Control, Check, Alarm)", q:"The primary purpose of a check valve in a sprinkler system is to:", opts:["Indicate open/closed position","Allow flow in one direction and prevent backflow","Reduce the temperature rating","Throttle the flow to a set pressure"], correct:1, re:"A check valve permits water to flow only toward the system and prevents reverse flow (e.g., back into the supply). Source: NFPA 13; check-valve function."},
  {id:174, block:2, sec:"Valves (Control, Check, Alarm)", q:"An alarm check valve performs which function in a wet-pipe system?", opts:["Holds back air in a dry system","Permits flow to the system and actuates a water-flow alarm","Reduces incoming pressure to 7 psi","Drains the system after use"], correct:1, re:"The alarm check valve is a one-way clapper on the riser; when water flows, an alarm port routes water to a pressure switch and/or water-motor gong to signal flow. Source: NFPA 13; alarm-check-valve operation."},
  {id:175, block:2, sec:"Valves (Control, Check, Alarm)", q:"The retard chamber associated with an alarm check valve is provided to:", opts:["Store extra water for the sprinklers","Prevent false alarms from brief pressure surges","Increase the discharge K-factor","Hold back air in a dry system"], correct:1, re:"The retard chamber fills and drains slowly so momentary supply-pressure surges do not trip the water-flow alarm; sustained flow fills it and trips the switch. Source: NFPA 13; retard-chamber function."},
  {id:176, block:2, sec:"Valves (Control, Check, Alarm)", q:"A water-motor gong (water motor alarm) is driven by:", opts:["An electric motor only","Water diverted by the alarm valve striking a vaned wheel","Compressed air from the dry valve","The fire department connection pump"], correct:1, re:"When the alarm valve operates, water is routed to the gong where it spins a vaned wheel turning a hammer to ring the bell - a purely hydraulic local alarm. Source: NFPA 13; water-motor-gong operation."},
  {id:177, block:2, sec:"Valves (Control, Check, Alarm)", q:"A dry-pipe valve in a dry system holds back water using:", opts:["A locked OS&Y stem","Air or nitrogen pressure on the system side","Solvent cement","A retard chamber only"], correct:1, re:"A dry-pipe valve uses pressurized air/nitrogen on the system side to hold the larger water-side force back; when a sprinkler opens, air bleeds off and the valve trips to admit water. Source: NFPA 13 dry-pipe provisions."},
  {id:178, block:2, sec:"Valves (Control, Check, Alarm)", q:"A deluge valve is used with which sprinkler arrangement?", opts:["Closed standard sprinklers in a wet system","Open sprinklers, flowing all heads at once when actuated","A single residential sidewall head","ESFR in-rack only"], correct:1, re:"A deluge valve admits water to a system of OPEN sprinklers when an actuating (detection) system trips, wetting the whole area simultaneously. Source: NFPA 13 deluge provisions."},
  {id:179, block:2, sec:"Valves (Control, Check, Alarm)", q:"NFPA requires control valves that are not electrically supervised to be:", opts:["Painted green","Locked in the open position and inspected on a set schedule","Removed during occupancy","Replaced annually"], correct:1, re:"Where not monitored by a tamper switch, control valves must be locked/sealed open and physically inspected (commonly weekly) to confirm they remain open. Source: NFPA 13/NFPA 25 valve supervision."},
  {id:180, block:2, sec:"Valves (Control, Check, Alarm)", q:"A Post Indicator Valve (PIV) is a control valve that:", opts:["Is buried with no way to tell its position","Has an aboveground post with an OPEN/SHUT target window for an underground valve","Is the same as a check valve","Only works on CPVC pipe"], correct:1, re:"A PIV brings the operating nut and an OPEN/SHUT indicator target above grade for a buried main valve, satisfying the indicating-valve requirement. Source: NFPA 13/24; PIV references."},
  {id:181, block:2, sec:"Valves (Control, Check, Alarm)", q:"A backflow preventer is installed on a fire service main mainly to:", opts:["Increase sprinkler discharge pressure","Prevent potentially contaminated system water from flowing back into the public supply","Sense heat and trip the system","Replace the alarm check valve"], correct:1, re:"Backflow preventers protect the potable supply from cross-contamination by stagnant or treated sprinkler water; required by plumbing/water authorities, not by NFPA itself. Source: backflow-prevention/cross-connection references; NFPA 13/25 context."},
  {id:182, block:2, sec:"Valves (Control, Check, Alarm)", q:"A Reduced Pressure Zone (RPZ) backflow assembly differs from a Double Check (DCVA) assembly by adding:", opts:["A third check valve","A differential relief valve that dumps water if a check fails","A retard chamber","A second OS&Y valve"], correct:1, re:"An RPZ adds a hydraulically operated relief valve between two checks; if a check leaks, the relief dumps to drain, giving higher protection for higher-hazard connections. Source: backflow-assembly references (AWWA M14)."},
  {id:183, block:2, sec:"Valves (Control, Check, Alarm)", q:"A pressure-reducing valve (PRV) is used in a tall standpipe/sprinkler system to:", opts:["Increase pressure at upper floors","Limit excessive pressure at lower floors/hose connections","Sense water flow","Hold back air in a dry system"], correct:1, re:"In high-rise systems, static pressure at lower levels can be excessive; PRVs reduce it to safe values at hose valves and lower-zone piping. Source: NFPA 14/NFPA 13 pressure-regulation provisions."},
  {id:184, block:2, sec:"Valves (Control, Check, Alarm)", q:"The main drain valve at the riser is used to:", opts:["Supply water to the sprinklers","Drain the system and perform a main drain (water-supply) test","Reduce incoming pressure","Hold back air"], correct:1, re:"The main drain lets the system be drained and is used for the main drain test, which checks for supply-side obstructions by comparing static and residual pressure. Source: NFPA 13/25 main-drain test."},
  {id:185, block:2, sec:"Hangers, Bracing & FDC", q:"Hangers used to support sprinkler system piping are required by NFPA 13 to be:", opts:["Listed for the service","Any wire available on site","Made only of copper","Spaced 50 ft apart maximum"], correct:0, re:"NFPA 13 requires hanger components that support system piping to be listed (with limited exceptions for certain field-fabricated parts meeting MSS criteria). Source: NFPA 13 hanging/support provisions."},
  {id:186, block:2, sec:"Hangers, Bracing & FDC", q:"For 1 in. steel sprinkler pipe, the maximum distance between hangers per NFPA 13 is:", opts:["6 ft","12 ft","20 ft","30 ft"], correct:1, re:"NFPA 13 limits hanger spacing on 1 in. (and 1-1/4 in.) steel pipe to a maximum of 12 ft; larger steel sizes (2 in. and up) allow up to 15 ft. Source: NFPA 13 maximum-distance-between-hangers table."},
  {id:187, block:2, sec:"Hangers, Bracing & FDC", q:"For 2 in. and larger steel sprinkler pipe, the maximum hanger spacing per NFPA 13 is generally:", opts:["8 ft","10 ft","15 ft","25 ft"], correct:2, re:"Steel pipe 2 in. and larger may be supported at up to 15 ft maximum hanger spacing under NFPA 13. Source: NFPA 13 maximum-distance-between-hangers table."},
  {id:188, block:2, sec:"Hangers, Bracing & FDC", q:"CPVC sprinkler pipe requires closer hanger spacing than steel because CPVC:", opts:["Is heavier than steel","Is more flexible and sags more, especially when warm","Cannot hold water","Conducts heat better"], correct:1, re:"CPVC is more flexible and loses stiffness as it warms, so it needs more frequent support than steel to prevent sag; follow the manufacturer's listed spacing. Source: NFPA 13; listed CPVC hanger guidance."},
  {id:189, block:2, sec:"Hangers, Bracing & FDC", q:"The purpose of seismic sway bracing on sprinkler piping is to:", opts:["Increase water pressure","Resist differential movement and keep piping intact during an earthquake","Reduce friction loss","Insulate the pipe from heat"], correct:1, re:"Sway bracing restrains the piping against earthquake-induced lateral/longitudinal movement so it does not rupture or pull apart; required in seismic design areas. Source: NFPA 13 earthquake-protection provisions."},
  {id:190, block:2, sec:"Hangers, Bracing & FDC", q:"Lateral sway braces on feed and cross mains are spaced at a maximum of:", opts:["20 ft on center","40 ft on center","80 ft on center","120 ft on center"], correct:1, re:"NFPA 13 limits lateral sway braces to a maximum of 40 ft on center on feed/cross mains (and qualifying branch lines). Source: NFPA 13 lateral-bracing spacing."},
  {id:191, block:2, sec:"Hangers, Bracing & FDC", q:"Longitudinal sway braces on feed and cross mains are spaced at a maximum of:", opts:["40 ft on center","60 ft on center","80 ft on center","160 ft on center"], correct:2, re:"NFPA 13 limits longitudinal sway braces to a maximum of 80 ft on center on feed and cross mains. Source: NFPA 13 longitudinal-bracing spacing."},
  {id:192, block:2, sec:"Hangers, Bracing & FDC", q:"Flexible couplings used in seismic design allow the piping to:", opts:["Carry more water","Flex at joints so movement does not break rigid connections","Eliminate the need for any bracing","Lower the temperature rating"], correct:1, re:"Listed flexible couplings provide controlled articulation so seismic movement is accommodated at the joint rather than overstressing the pipe; their placement is coordinated with bracing. Source: NFPA 13 seismic flexibility provisions."},
  {id:193, block:2, sec:"Hangers, Bracing & FDC", q:"A Fire Department Connection (FDC) allows the fire department to:", opts:["Shut off the sprinkler system","Pump additional water/pressure into the sprinkler or standpipe system","Drain the system","Test the alarm bell only"], correct:1, re:"The FDC is an inlet where fire-department apparatus can boost water and pressure into the system to supplement the supply during a fire. Source: NFPA 13/14; FDC purpose."},
  {id:194, block:2, sec:"Hangers, Bracing & FDC", q:"A standard FDC inlet most commonly uses which hose-thread connection size?", opts:["1 in.","1-1/2 in.","2-1/2 in.","6 in."], correct:2, re:"The default FDC provides 2-1/2 in. National Hose (NH) threaded swivel inlets (often two, a 'Siamese' connection), unless the local jurisdiction specifies a large-diameter (Storz) connection. Source: NFPA 13/14 FDC inlet requirements."},
  {id:195, block:2, sec:"Hangers, Bracing & FDC", q:"NFPA requires an FDC to be located at what height above the adjoining grade?", opts:["Not less than 18 in. and not more than 48 in.","Exactly 6 in.","Not less than 8 ft","Below grade in a pit"], correct:0, re:"FDCs are to be located between 18 in. and 48 in. above the level of the adjoining ground/finished floor so hoses can be connected. Source: NFPA 14 (6.4.6) / NFPA 13 FDC location."},
  {id:196, block:2, sec:"Hangers, Bracing & FDC", q:"A check valve is installed on the FDC line to:", opts:["Reduce the inlet pressure","Prevent system water from flowing out the FDC during normal operation","Sense heat","Indicate valve position"], correct:1, re:"The FDC has a check valve so that water normally flows only inward; it keeps system water (and any boosted pressure) from discharging out the FDC inlets. Source: NFPA 13/14; FDC check-valve requirement."},
  {id:197, block:2, sec:"Hangers, Bracing & FDC", q:"Each FDC inlet must be provided with which of the following to keep debris out?", opts:["A pressure gauge","A plug, cap, or breakable cover","A sprinkler head","A retard chamber"], correct:1, re:"FDC inlets are fitted with caps/plugs (or breakable covers) to keep out debris and vandalism while remaining quickly removable by the fire department. Source: NFPA 13/14 FDC provisions."},
  {id:198, block:2, sec:"Hangers, Bracing & FDC", q:"An automatic ball drip (drip valve) at the FDC is provided to:", opts:["Boost system pressure","Drain residual water from the FDC piping to prevent freezing","Sense water flow","Hold air in a dry system"], correct:1, re:"The automatic drip/ball drip lets water trapped in the FDC piping drain out so it does not freeze and burst the connection in cold weather. Source: NFPA 13/14 FDC drainage provisions."},
  {id:199, block:2, sec:"Hangers, Bracing & FDC", q:"A hanger on a branch line must be located within a limited distance of each sprinkler primarily to:", opts:["Increase water pressure at the head","Support the head and keep the pipe from sagging or whipping","Change the temperature rating","Serve as a seismic brace"], correct:1, re:"NFPA 13 requires a hanger within a set distance of each sprinkler so the head is properly supported and the pipe does not sag, droop, or move excessively. Source: NFPA 13 location-of-hangers-on-branch-lines provisions."},
  {id:200, block:2, sec:"Hangers, Bracing & FDC", q:"An FDC serving a combined system is typically identified by:", opts:["A green light","A sign indicating the system/area it serves (e.g., 'AUTOSPKR' or 'STANDPIPE')","No marking at all","A temperature color code"], correct:1, re:"FDCs must be identified by a sign or raised letters showing the service they supply (sprinkler, standpipe, or combined) and any pressure information, so responders connect to the right inlet. Source: NFPA 13/14 FDC signage requirements."},
  {id:201, block:3, sec:"Hydraulic Calculation Basics", q:"A vertical column of water exerts a static pressure of approximately:", opts:["5.0 psi per foot of height","1.0 psi per foot of height","2.31 psi per foot of height","0.433 psi per foot of height"], correct:3, re:"Water exerts about 0.433 psi for each vertical foot of height; equivalently it takes 2.31 ft of water to make 1 psi. Standard fire-protection hydraulics (NFPA 13 elevation calculations)."},
  {id:202, block:3, sec:"Hydraulic Calculation Basics", q:"How many feet of water column are required to produce a pressure of 1 psi?", opts:["0.433 ft","1.0 ft","4.33 ft","2.31 ft"], correct:3, re:"Since water exerts 0.433 psi/ft, the inverse (1 ÷ 0.433) is about 2.31 ft of water per psi. Standard hydraulics constant used in NFPA 13 calculations."},
  {id:203, block:3, sec:"Hydraulic Calculation Basics", q:"'Residual pressure' in a water-supply or flow test is the pressure remaining:", opts:["While the required quantity of water is flowing","After the pump is shut off","Before any valve is opened","Only at the highest sprinkler"], correct:0, re:"Residual pressure is the pressure that remains in the system while water is flowing; the drop from static to residual reflects friction and demand. NFPA 291 hydrant-test terminology."},
  {id:204, block:3, sec:"Hydraulic Calculation Basics", q:"The three forms of energy balanced in a fire-protection hydraulic calculation (Bernoulli) are pressure (head), elevation, and:", opts:["Magnetism","Temperature","Surface tension","Velocity (velocity pressure)"], correct:3, re:"Bernoulli's principle balances pressure head, elevation head, and velocity head; fire-protection hydraulics uses a modified form for pipe-flow calculations. Canute / NFPA 13 hydraulic theory."},
  {id:205, block:3, sec:"Hydraulic Calculation Basics", q:"As water is pumped UP to a higher floor, the elevation change causes pressure to:", opts:["Increase about 0.433 psi per foot of rise","Decrease about 0.433 psi per foot of rise","Stay exactly the same","Double on each floor"], correct:1, re:"Each foot of rise costs about 0.433 psi of pressure that the supply must overcome, so pressure decreases with elevation gain. NFPA 13 elevation (pressure) loss."},
  {id:206, block:3, sec:"Hydraulic Calculation Basics", q:"The discharge from a sprinkler or nozzle is found with the formula:", opts:["Q = P + K","Q = P²","Q = K ÷ P","Q = K√P"], correct:3, re:"Flow equals the K-factor times the square root of pressure: Q = K√P, where Q is gpm, K is the discharge coefficient, and P is psi. NFPA 13 hydraulic fundamentals."},
  {id:207, block:3, sec:"Hydraulic Calculation Basics", q:"In the formula Q = K√P, the symbol 'K' represents the:", opts:["Pipe length","Discharge coefficient (K-factor) of the orifice","Number of sprinklers","Pump horsepower"], correct:1, re:"K is the nominal discharge coefficient (K-factor) of the sprinkler or nozzle orifice, in units of gpm/√psi. NFPA 13 K-factor definition."},
  {id:208, block:3, sec:"Hydraulic Calculation Basics", q:"A standard 1/2-in. orifice spray sprinkler has a nominal K-factor of approximately:", opts:["1.4","5.6","2.8","11.2"], correct:1, re:"The standard 1/2-in. (DN15) spray sprinkler used in most light-hazard commercial work has a nominal K-factor of about 5.6 (gpm/√psi). NFPA 13 nominal K-factors."},
  {id:209, block:3, sec:"Hydraulic Calculation Basics", q:"A K=5.6 sprinkler operating at 25 psi discharges approximately how many gpm? (Q = K√P)", opts:["14 gpm","56 gpm","28 gpm","112 gpm"], correct:2, re:"Q = 5.6 × √25 = 5.6 × 5 = 28 gpm. Direct application of Q = K√P (NFPA 13)."},
  {id:210, block:3, sec:"Hydraulic Calculation Basics", q:"A K=5.6 sprinkler must flow 22.4 gpm. What pressure is required? (P = (Q/K)²)", opts:["4 psi","16 psi","8 psi","32 psi"], correct:1, re:"P = (Q/K)² = (22.4/5.6)² = (4)² = 16 psi. Rearranged form of Q = K√P (NFPA 13)."},
  {id:211, block:3, sec:"Hydraulic Calculation Basics", q:"NFPA 13 sets the minimum operating pressure for a standard spray sprinkler at not less than:", opts:["3 psi","15 psi","7 psi","25 psi"], correct:2, re:"NFPA 13 requires a minimum of 7 psi at a standard spray sprinkler (unless the listing requires higher); below that, the spray pattern is not reliable. NFPA 13 minimum operating pressure."},
  {id:212, block:3, sec:"Hydraulic Calculation Basics", q:"If the pressure at a K=5.6 sprinkler is quadrupled (×4), the discharge (flow) will:", opts:["Stay the same","Double (×2)","Triple (×3)","Quadruple (×4)"], correct:1, re:"Because flow varies with the square root of pressure (Q = K√P), quadrupling pressure only doubles the flow (√4 = 2). NFPA 13 K-factor relationship."},
  {id:213, block:3, sec:"Hydraulic Calculation Basics", q:"The 'design area' in a hydraulically calculated sprinkler system is:", opts:["The total building floor area","The area covered by one sprinkler","The hydraulically most demanding area assumed to operate in a fire","The area of the riser room"], correct:2, re:"The design (remote) area is the most hydraulically demanding group of sprinklers assumed to operate; the system is calculated to deliver the required density over that area. NFPA 13 density/area method."},
  {id:214, block:3, sec:"Hydraulic Calculation Basics", q:"In hydraulic calculations, 'density' is expressed in units of:", opts:["gpm per square foot","psi per foot","gallons per minute only","feet per second"], correct:0, re:"Design density is the water application rate over an area, expressed in gpm/ft² (gallons per minute per square foot). NFPA 13 density/area design."},
  {id:215, block:3, sec:"Hydraulic Calculation Basics", q:"To find the minimum flow from one sprinkler protecting 130 ft² at a density of 0.10 gpm/ft², you would:", opts:["Add density + area","Multiply density × area = 13 gpm","Divide area by density","Subtract density from area"], correct:1, re:"Minimum flow = density × coverage area = 0.10 gpm/ft² × 130 ft² = 13 gpm for that sprinkler. NFPA 13 density × area basis."},
  {id:216, block:3, sec:"Hydraulic Calculation Basics", q:"In a hydraulic calculation, friction loss in the piping is treated as:", opts:["A pressure gain","A pressure loss the supply must overcome","Irrelevant to the design","Equal to the elevation gain"], correct:1, re:"Friction (flow) loss is a pressure penalty that the water supply must overcome along with elevation and the minimum sprinkler pressure. NFPA 13 hydraulic calculation."},
  {id:217, block:3, sec:"Hydraulic Calculation Basics", q:"On a hydraulic graph (semi-log N1.85 paper), the water supply is plotted as a line and the system demand as a point; the design is adequate when the demand point falls:", opts:["Above and to the right of the supply line","On or below (to the left of) the supply line","Exactly on the horizontal axis","Off the chart entirely"], correct:1, re:"If the demand point lies on or below/left of the available supply curve, the supply can satisfy the demand. NFPA 13 graphical hydraulic analysis."},
  {id:218, block:3, sec:"Density/Area Design Method", q:"For an OFFICE building classified as Light Hazard, the classic NFPA 13 design density is about:", opts:["0.05 gpm/ft²","0.20 gpm/ft²","0.10 gpm/ft²","0.40 gpm/ft²"], correct:2, re:"Light Hazard occupancies (offices, schools, churches) use a classic design density near 0.10 gpm/ft². NFPA 13 density/area (Light Hazard)."},
  {id:219, block:3, sec:"Density/Area Design Method", q:"The classic NFPA 13 design density for Ordinary Hazard Group 1 is approximately:", opts:["0.10 gpm/ft²","0.30 gpm/ft²","0.15 gpm/ft²","0.60 gpm/ft²"], correct:2, re:"Ordinary Hazard Group 1 uses a classic density of about 0.15 gpm/ft². NFPA 13 density/area (OH-1)."},
  {id:220, block:3, sec:"Density/Area Design Method", q:"The classic NFPA 13 design density for Ordinary Hazard Group 2 is approximately:", opts:["0.10 gpm/ft²","0.20 gpm/ft²","0.15 gpm/ft²","0.50 gpm/ft²"], correct:1, re:"Ordinary Hazard Group 2 uses a classic density of about 0.20 gpm/ft². NFPA 13 density/area (OH-2)."},
  {id:221, block:3, sec:"Density/Area Design Method", q:"In the density/area method, which two quantities define the design 'point' for a hazard classification?", opts:["Density (gpm/ft²) and area of operation (ft²)","Voltage and amperage","Temperature and humidity","Pipe size and pipe length"], correct:0, re:"The method pairs a water application density (gpm/ft²) with a design area of operation (ft²) selected from the hazard classification. NFPA 13 density/area design."},
  {id:222, block:3, sec:"Density/Area Design Method", q:"A commonly used design AREA of operation for Ordinary and Light Hazard density/area design is:", opts:["1,500 ft²","500 ft²","100 ft²","25,000 ft²"], correct:0, re:"A 1,500 ft² design area of operation is the classic baseline for Light and Ordinary Hazard density/area design. NFPA 13 density/area (design area)."},
  {id:223, block:3, sec:"Density/Area Design Method", q:"On the classic density/area curves, as the assumed DESIGN AREA increases, the required DENSITY generally:", opts:["Increases","Drops to zero","Stays constant","Decreases"], correct:3, re:"The classic curves let the designer trade a larger design area for a lower required density (or a smaller area for higher density). NFPA 13 density/area curve trade-off."},
  {id:224, block:3, sec:"Density/Area Design Method", q:"A higher hazard classification (more combustible contents) generally requires:", opts:["A higher density of water application","A lower density and smaller area","No sprinklers at all","Only smoke detection"], correct:0, re:"Greater fuel load and faster heat-release require a higher water application density to control the fire. NFPA 13 hazard classification basis."},
  {id:225, block:3, sec:"Density/Area Design Method", q:"Which of these is normally classified as an Ordinary Hazard (Group 2) occupancy?", opts:["A private office","A machine shop or mercantile with moderate combustibles","A church sanctuary","An open parking deck with no storage"], correct:1, re:"Occupancies with moderate-to-high combustible contents (machine shops, many mercantile/manufacturing uses) fall in Ordinary Hazard Group 2. NFPA 13 occupancy classification."},
  {id:226, block:3, sec:"Density/Area Design Method", q:"In the density/area method, the total minimum water demand for the sprinklers is found by:", opts:["Adding the K-factors","Density ÷ area","Area ÷ density","Density × design area (plus hose allowance)"], correct:3, re:"Sprinkler demand ≈ density × design area; a hose-stream allowance and friction/elevation are then added to size the supply. NFPA 13 density/area demand."},
  {id:227, block:3, sec:"Density/Area Design Method", q:"A hose-stream allowance (inside/outside hose) is ADDED to the sprinkler demand at the point of:", opts:["The base of the riser / point of connection to the supply","Each individual sprinkler","The most remote sprinkler only","The attic"], correct:0, re:"Inside- and outside-hose allowances are added to the system demand at the base of the riser or the supply connection, not at each sprinkler. NFPA 13 hose-stream allowance."},
  {id:228, block:3, sec:"Density/Area Design Method", q:"The duration of water supply (minutes) required generally INCREASES as the hazard classification:", opts:["Becomes lighter","Is irrelevant","Has no effect on duration","Becomes higher (more hazardous)"], correct:3, re:"Higher hazards require both higher density AND longer supply durations (e.g., Light ~30 min vs. Ordinary/Extra longer). NFPA 13 water-supply duration."},
  {id:229, block:3, sec:"Density/Area Design Method", q:"When the most hydraulically remote sprinkler is calculated first, the calculation then proceeds:", opts:["Back toward the water supply, accumulating losses","Out toward the dead-end only","In random order","Only at the pump"], correct:0, re:"Calculations start at the most remote sprinkler and work back toward the supply, adding flows and accumulating friction and elevation losses. NFPA 13 hydraulic calculation procedure."},
  {id:230, block:3, sec:"Density/Area Design Method", q:"NFPA 13 editions beginning around 2022 changed the density/area approach by:", opts:["Limiting the multi-point density/area curves to existing systems and making the single-point density the default for new work","Eliminating sprinklers entirely","Doubling every density value","Banning hydraulic calculations"], correct:0, re:"NFPA 13 (2022) limited the classic density/area curves to evaluating existing systems and made the single-point density (from the hazard table) the default for new design. NFPA 13 (2022) Ch. 19."},
  {id:231, block:3, sec:"Density/Area Design Method", q:"In the 'single-point' density approach, the designer uses:", opts:["Any point on a curve they choose","A fixed density and area defined by the hazard classification table","The pump nameplate only","The pipe schedule only"], correct:1, re:"Single-point design fixes the density and design area from the hazard classification (no free selection along a curve). NFPA 13 (2022) single-point density."},
  {id:232, block:3, sec:"Density/Area Design Method", q:"Compared with Light Hazard, an Ordinary Hazard area generally needs sprinklers that flow:", opts:["Less water","No water","More water (higher density)","The same regardless of hazard"], correct:2, re:"Ordinary Hazard requires a higher application density than Light Hazard, so each operating sprinkler must deliver more water. NFPA 13 density comparison."},
  {id:233, block:3, sec:"Density/Area Design Method", q:"The minimum flow each sprinkler must deliver in a calculated system depends on its:", opts:["Color only","Thread size only","Manufacturer's logo","Coverage area × required density"], correct:3, re:"Each sprinkler's minimum flow = its protected coverage area × the required design density. NFPA 13 density/area calculation."},
  {id:234, block:3, sec:"Density/Area Design Method", q:"Selecting a LARGER design area (more sprinklers operating) than required will generally make the calculated water demand:", opts:["Larger / more conservative","Unchanged","Lower","Zero"], correct:0, re:"More operating sprinklers means more total flow and friction, increasing the demand — a more conservative (and costlier) design. NFPA 13 density/area selection."},
  {id:235, block:3, sec:"Friction Loss & Hazen-Williams", q:"The empirical formula adopted by NFPA 13 to calculate friction (flow) loss in sprinkler piping is the:", opts:["Boyle's law","Ohm's law","Hazen-Williams formula","Charles's law"], correct:2, re:"NFPA 13 uses the Hazen-Williams formula to compute friction loss in water-filled fire-protection piping. NFPA 13 hydraulic calculation method."},
  {id:236, block:3, sec:"Friction Loss & Hazen-Williams", q:"In the Hazen-Williams formula, the 'C' value represents the pipe's:", opts:["Cost","Internal roughness / smoothness","Color code","Length in feet"], correct:1, re:"The C-factor (coefficient) describes the interior roughness of the pipe — higher C means smoother pipe and lower friction loss. Hazen-Williams (NFPA 13)."},
  {id:237, block:3, sec:"Friction Loss & Hazen-Williams", q:"A HIGHER Hazen-Williams C-value indicates a pipe that produces:", opts:["More friction loss","No flow","Less friction loss (smoother bore)","Higher elevation"], correct:2, re:"Higher C = smoother interior = lower friction loss for a given flow. Hazen-Williams C-factor meaning (NFPA 13)."},
  {id:238, block:3, sec:"Friction Loss & Hazen-Williams", q:"The Hazen-Williams C-value typically used for UNLINED cast iron / ductile iron pipe is:", opts:["150","120","130","100"], correct:3, re:"Unlined cast/ductile iron is assigned C = 100 in NFPA 13's friction-loss table (accounts for aging/tuberculation). NFPA 13 C-value table."},
  {id:239, block:3, sec:"Friction Loss & Hazen-Williams", q:"The Hazen-Williams C-value used for black or galvanized steel pipe in WET sprinkler systems is:", opts:["80","100","150","120"], correct:3, re:"Steel pipe in wet (and deluge) systems is assigned C = 120; dry/preaction steel uses C = 100. NFPA 13 C-value table."},
  {id:240, block:3, sec:"Friction Loss & Hazen-Williams", q:"The Hazen-Williams C-value used for copper tube and most listed plastic (CPVC) pipe is:", opts:["100","120","150","140"], correct:2, re:"Copper tube and listed plastic (CPVC) are assigned C = 150 — the smoothest common materials, giving the least friction loss. NFPA 13 C-value table."},
  {id:241, block:3, sec:"Friction Loss & Hazen-Williams", q:"Steel pipe in a DRY or PREACTION system is assigned a Hazen-Williams C-value of:", opts:["120","100","130","150"], correct:1, re:"Because internal corrosion is greater in dry/preaction systems, steel pipe there uses C = 100 (versus 120 for wet steel). NFPA 13 C-value table."},
  {id:242, block:3, sec:"Friction Loss & Hazen-Williams", q:"For a given flow and pipe size, friction loss is GREATEST in the pipe with which C-value?", opts:["C = 150","C = 120","C = 140","C = 100"], correct:3, re:"The lowest C (roughest pipe) produces the greatest friction loss; C = 100 (e.g., unlined iron, dry-system steel) is the worst of those listed. Hazen-Williams (NFPA 13)."},
  {id:243, block:3, sec:"Friction Loss & Hazen-Williams", q:"In the Hazen-Williams formula, friction loss is most sensitive to (increases most steeply with) the:", opts:["Sprinkler thread","Pipe color","Ambient temperature","Flow rate Q"], correct:3, re:"Friction loss rises with flow raised to about the 1.85 power, so roughly doubling the flow nearly quadruples the loss. Hazen-Williams exponent on Q (NFPA 13)."},
  {id:244, block:3, sec:"Friction Loss & Hazen-Williams", q:"In the Hazen-Williams pipe-friction relationship, friction loss varies inversely with the pipe DIAMETER raised to a power near:", opts:["4.87","1.85","1.0","10"], correct:0, re:"Diameter appears to about the 4.87 power in the denominator, so a small increase in pipe diameter sharply reduces friction loss. Hazen-Williams (NFPA 13)."},
  {id:245, block:3, sec:"Friction Loss & Hazen-Williams", q:"If the flow in a pipe is roughly doubled (and pipe size unchanged), the Hazen-Williams friction loss will increase by approximately:", opts:["No change","About 2 times","About 4 times (≈3.6×)","About 10 times"], correct:2, re:"Because Q is raised to ~1.85, doubling flow multiplies friction loss by about 2^1.85 ≈ 3.6, i.e., nearly 4×. Hazen-Williams (NFPA 13)."},
  {id:246, block:3, sec:"Friction Loss & Hazen-Williams", q:"Fittings and valves (elbows, tees, check valves) are accounted for in hydraulic calculations using:", opts:["The number of bolts","Their weight in pounds","Their paint color","Equivalent pipe lengths"], correct:3, re:"NFPA 13 converts each fitting/valve to an 'equivalent length' of pipe that is added to the actual pipe length before computing friction loss. NFPA 13 equivalent-length method."},
  {id:247, block:3, sec:"Friction Loss & Hazen-Williams", q:"When a pipe's C-value differs from the C = 120 base used to tabulate equivalent fitting lengths, the equivalent lengths must be:", opts:["Ignored","Set to zero","Doubled always","Adjusted (multiplied) by a C-factor correction"], correct:3, re:"Equivalent fitting lengths are tabulated for C = 120 and must be multiplied by a correction factor when the actual pipe C-value differs. NFPA 13 fitting equivalent-length adjustment."},
  {id:248, block:3, sec:"Friction Loss & Hazen-Williams", q:"The single most effective way to REDUCE friction loss in a long run of sprinkler pipe is to:", opts:["Use a rougher pipe","Add more elbows","Increase the pipe diameter","Lower the C-value"], correct:2, re:"Because loss varies inversely with diameter to ~4.87 power, increasing pipe size is by far the most effective way to cut friction loss. Hazen-Williams diameter sensitivity (NFPA 13)."},
  {id:249, block:3, sec:"Friction Loss & Hazen-Williams", q:"The Hazen-Williams formula is specifically intended for the flow of:", opts:["Water (turbulent flow) in pipes","Compressed air","Steam","Electricity"], correct:0, re:"Hazen-Williams is an empirical equation for water flowing in pipes under turbulent conditions — exactly the case in water-based fire protection. Hazen-Williams scope (NFPA 13)."},
  {id:250, block:3, sec:"Friction Loss & Hazen-Williams", q:"Compared with new clean steel, an OLD tuberculated (corroded) steel pipe effectively behaves as if it has a C-value that is:", opts:["Higher","Exactly 150","Lower","Unchanged"], correct:2, re:"Internal corrosion and tuberculation roughen the bore and reduce the effective C-value, increasing friction loss over the pipe's life. Hazen-Williams C-factor aging (NFPA 13 basis)."},
  {id:251, block:3, sec:"Friction Loss & Hazen-Williams", q:"Two identical pipes carry the same flow; pipe A is copper (C=150) and pipe B is dry-system steel (C=100). Which has the LOWER friction loss?", opts:["Pipe A (copper, C=150)","Pipe B (steel, C=100)","They are identical","Cannot be determined"], correct:0, re:"The higher C-value (copper, C=150) is smoother and produces lower friction loss for the same flow. Hazen-Williams C comparison (NFPA 13)."},
  {id:252, block:3, sec:"Water Supply & Flow Tests", q:"In a hydrant flow test, the 'static pressure' is read at the residual hydrant:", opts:["Only after the test ends","While the test hydrant is wide open","With no hydrants flowing","Inside the pump"], correct:2, re:"Static pressure is taken at the residual (test-gauge) hydrant before any hydrant is opened to flow. NFPA 291 hydrant flow test procedure."},
  {id:253, block:3, sec:"Water Supply & Flow Tests", q:"During a hydrant flow test, the 'residual pressure' is read at the residual hydrant:", opts:["Before flow starts","While water is flowing from the flow hydrant(s)","With all hydrants closed","At the city reservoir"], correct:1, re:"Residual pressure is the gauge reading at the residual hydrant while the flow hydrant(s) discharge water; the static-to-residual drop reveals supply strength. NFPA 291."},
  {id:254, block:3, sec:"Water Supply & Flow Tests", q:"A pitot gauge held in the stream at a flowing hydrant outlet measures the:", opts:["Static pressure","Elevation head","Velocity pressure of the discharging stream (to compute flow)","Air pressure"], correct:2, re:"The pitot reads the velocity pressure of the stream, which is converted to flow (gpm) using the outlet size and discharge coefficient. NFPA 291 pitot method."},
  {id:255, block:3, sec:"Water Supply & Flow Tests", q:"The general formula for flow from a hydrant/nozzle using a pitot reading is Q = 29.83 × c × d² × √P, where 'd' is the:", opts:["Distance to the fire","Number of outlets","Depth of the main","Outlet (orifice) diameter in inches"], correct:3, re:"In Q = 29.83·c·d²·√P, d is the discharge outlet diameter (in.), c is the coefficient, and P is the pitot pressure (psi). NFPA 291 / IFSTA hydrant-flow formula."},
  {id:256, block:3, sec:"Water Supply & Flow Tests", q:"A water-supply flow test is typically used to establish the available water at a residual pressure of:", opts:["0 psi","20 psi","100 psi","175 psi"], correct:1, re:"Results are commonly projected to the flow available at 20 psi residual, the value used for hydrant color-coding and design. NFPA 291 (20 psi residual)."},
  {id:257, block:3, sec:"Water Supply & Flow Tests", q:"To get reliable hydrant-test results, NFPA 291 recommends flowing enough water to drop the residual pressure by at least:", opts:["5%","10%","25%","75%"], correct:2, re:"A pressure drop of at least 25% from static improves accuracy when projecting the available flow to other pressures. NFPA 291 recommended drop."},
  {id:258, block:3, sec:"Water Supply & Flow Tests", q:"On the NFPA 291 hydrant color-coding scale, a hydrant flowing 1,500 gpm or more at 20 psi is painted (capped) with which CLASS color?", opts:["Red","Light blue","Green","Orange"], correct:1, re:"NFPA 291 marks Class AA hydrants (≥1,500 gpm at 20 psi) light blue; green = 1,000–1,499, orange = 500–999, red = below 500 gpm. NFPA 291 color classes."},
  {id:259, block:3, sec:"Water Supply & Flow Tests", q:"On the NFPA 291 scale, a RED hydrant bonnet/cap indicates an available flow at 20 psi of:", opts:["1,500 gpm or more","500–999 gpm","1,000–1,499 gpm","Less than 500 gpm"], correct:3, re:"Red marks the weakest hydrants — less than 500 gpm available at 20 psi residual. NFPA 291 color classes."},
  {id:260, block:3, sec:"Water Supply & Flow Tests", q:"A municipal (city) water main delivered to a building is an example of a:", opts:["Public water supply source","Private fire pump","Gravity tank","Pressure tank"], correct:0, re:"The city/municipal main is a public water supply; private tanks, reservoirs, and pumps supplement it when it is inadequate. NFPA 13 water-supply sources."},
  {id:261, block:3, sec:"Water Supply & Flow Tests", q:"A gravity (elevated) storage tank supplies fire-protection pressure mainly through:", opts:["Compressed air over the water","Its elevation/height above the system (head)","An electric heater","A diesel engine"], correct:1, re:"A gravity tank develops pressure from its height — each foot of elevation adds about 0.433 psi at the base. NFPA 22 gravity tank principle."},
  {id:262, block:3, sec:"Water Supply & Flow Tests", q:"A pressure tank provides water under pressure by maintaining a cushion of:", opts:["Steam","Compressed air above the stored water","Vacuum","Sand"], correct:1, re:"A pressure tank is partly filled with water and pressurized with compressed air so water discharges immediately on demand. NFPA 22 pressure tank."},
  {id:263, block:3, sec:"Water Supply & Flow Tests", q:"The standard governing the design and construction of water storage tanks for private fire protection is:", opts:["NFPA 13","NFPA 14","NFPA 20","NFPA 22"], correct:3, re:"NFPA 22 covers water tanks (gravity, suction, pressure, embankment) used for private fire protection. NFPA 22 scope."},
  {id:264, block:3, sec:"Water Supply & Flow Tests", q:"The standard covering the installation of PRIVATE FIRE SERVICE MAINS and their appurtenances (underground supply to a site) is:", opts:["NFPA 24","NFPA 13D","NFPA 25","NFPA 72"], correct:0, re:"NFPA 24 governs private fire service mains — the underground piping, valves, and hydrants supplying water to a property. NFPA 24 scope."},
  {id:265, block:3, sec:"Water Supply & Flow Tests", q:"The required CAPACITY (volume) of a fire-protection storage tank is determined by:", opts:["Tank color","The fire-flow demand (gpm) multiplied by the required duration (minutes)","The number of bolts","The pump horsepower only"], correct:1, re:"Tank volume = required fire flow (gpm) × required supply duration (minutes), set by the system demand and hazard. NFPA 22 / NFPA 13 supply sizing."},
  {id:266, block:3, sec:"Water Supply & Flow Tests", q:"A ground-level SUCTION tank differs from a gravity tank in that it:", opts:["Develops full system pressure by elevation alone","Needs no pump or elevation","Uses compressed air only","Feeds a fire pump that boosts the pressure"], correct:3, re:"A suction (ground) tank stores water at low elevation and supplies a fire pump that provides the needed pressure. NFPA 22 suction tank / NFPA 20."},
  {id:267, block:3, sec:"Water Supply & Flow Tests", q:"When the public main cannot supply the required fire flow AND pressure, the usual remedy is to add a:", opts:["Larger paint coating","Second roof drain","Smaller pipe","Fire pump and/or storage tank"], correct:3, re:"Inadequate public supply is supplemented with a stored water source (tank/reservoir) and/or a fire pump to meet the demand. NFPA 13 / NFPA 20 water-supply provisions."},
  {id:268, block:3, sec:"Water Supply & Flow Tests", q:"In hydrant testing, if the static-to-residual pressure drop is very SMALL while flowing a large quantity, the water supply is:", opts:["Very weak","Strong (abundant)","Frozen","Disconnected"], correct:1, re:"A small pressure drop under heavy flow indicates a strong, abundant supply; a large drop indicates a weak supply. NFPA 291 interpretation of test results."},
  {id:269, block:3, sec:"Fire Pumps (NFPA 20)", q:"The standard for the installation of stationary pumps for fire protection is:", opts:["NFPA 20","NFPA 14","NFPA 13","NFPA 25"], correct:0, re:"NFPA 20 governs the selection and installation of stationary fire pumps and their drivers, controllers, and accessories. NFPA 20 scope."},
  {id:270, block:3, sec:"Fire Pumps (NFPA 20)", q:"The most common type of fire pump used for water-based fire protection is the:", opts:["Horizontal split-case centrifugal pump","Positive-displacement piston pump","Hand pump","Peristaltic pump"], correct:0, re:"Centrifugal pumps (commonly horizontal split-case) are the standard fire-pump type; positive-displacement pumps are limited to special uses like foam/water mist. NFPA 20 pump types."},
  {id:271, block:3, sec:"Fire Pumps (NFPA 20)", q:"On a fire pump's performance curve, 'churn' (shutoff) is the condition where the pump operates at:", opts:["Zero flow (no discharge)","100% of rated flow","150% of rated flow","Maximum overload"], correct:0, re:"Churn (shutoff) is zero-flow operation; the pump is recirculating internally and producing its maximum head. NFPA 20 pump curve (churn point)."},
  {id:272, block:3, sec:"Fire Pumps (NFPA 20)", q:"At CHURN (no flow), NFPA 20 limits the total head (pressure) to not more than what percent of rated pressure?", opts:["100%","121%","140%","175%"], correct:2, re:"Churn (shutoff) pressure shall not exceed 140% of rated pressure for a listed fire pump. NFPA 20 churn-pressure limit."},
  {id:273, block:3, sec:"Fire Pumps (NFPA 20)", q:"At 150% of rated flow (the overload point), a fire pump must still produce a total head of at least:", opts:["50% of rated head","65% of rated head","100% of rated head","140% of rated head"], correct:1, re:"At 150% of rated capacity the pump must deliver not less than 65% of its rated total head. NFPA 20 overload-point requirement."},
  {id:274, block:3, sec:"Fire Pumps (NFPA 20)", q:"A fire pump's 'rated' point is where it delivers:", opts:["Zero flow at maximum head","Churn pressure","150% flow at 65% head","100% of rated capacity at 100% of rated head"], correct:3, re:"The rated (100%) point is the listed flow and pressure the pump is selected to provide. NFPA 20 rated point."},
  {id:275, block:3, sec:"Fire Pumps (NFPA 20)", q:"The three points checked during a fire-pump acceptance flow test are churn (no-flow), 100% of rated flow, and:", opts:["50% of rated flow","125% of rated flow","150% of rated flow","200% of rated flow"], correct:2, re:"NFPA 20 requires testing at churn, 100%, and 150% of rated capacity to verify the pump's performance curve. NFPA 20 acceptance-test flow points."},
  {id:276, block:3, sec:"Fire Pumps (NFPA 20)", q:"A small pump that maintains system pressure between preset limits when no water is flowing is called a:", opts:["Jockey (pressure-maintenance) pump","Booster relief pump","Sump pump","Priming pump"], correct:0, re:"The jockey (pressure-maintenance) pump makes up minor leakage so the main fire pump does not cycle on small pressure drops. NFPA 20 jockey pump."},
  {id:277, block:3, sec:"Fire Pumps (NFPA 20)", q:"A jockey pump should be sized to deliver a flow that is:", opts:["Greater than the fire pump","At least 150% of rated flow","Exactly equal to the fire pump","Less than the flow of a single sprinkler"], correct:3, re:"The jockey pump is sized to make up allowable leakage — less than one sprinkler's flow — so that an actual sprinkler operation forces the main pump to start. NFPA 20 jockey-pump sizing guidance."},
  {id:278, block:3, sec:"Fire Pumps (NFPA 20)", q:"Typical pressure-switch settings are arranged so that the JOCKEY pump starts and stops:", opts:["At higher pressures than the fire pump (above the fire pump's start point)","At lower pressures than the fire pump","Only when the fire pump runs","Never automatically"], correct:0, re:"The jockey pump's start/stop settings are above the fire pump's start point so the jockey handles small leakage and the fire pump only starts on a real demand. NFPA 20 pressure-setting hierarchy."},
  {id:279, block:3, sec:"Fire Pumps (NFPA 20)", q:"Once an ELECTRIC-driven fire pump starts automatically, its controller is generally required to:", opts:["Stop it after 10 seconds","Require manual shutdown (not stop automatically) unless arranged for automatic stop with a minimum run timer","Run it for exactly 1 minute","Cycle it on and off rapidly"], correct:1, re:"NFPA 20 generally requires manual shutdown of the fire pump after automatic start; where automatic stopping is permitted, a minimum run-time timer applies. NFPA 20 controller/stopping requirements."},
  {id:280, block:3, sec:"Fire Pumps (NFPA 20)", q:"A fire pump driven by a DIESEL engine must be provided with a fuel supply sized for at least the design run time, and the engine controller must include:", opts:["A single battery only","No batteries","Two storage battery banks (dual batteries)","An AC-only starter"], correct:2, re:"Diesel fire-pump controllers require two separate storage battery units so engine cranking is reliable if one bank fails. NFPA 20 diesel controller batteries."},
  {id:281, block:3, sec:"Fire Pumps (NFPA 20)", q:"A circulation (casing) relief valve on a fire pump is provided primarily to:", opts:["Increase the discharge pressure","Relieve heat buildup by allowing a small flow during churn (no-flow) operation","Prime the pump","Replace the check valve"], correct:1, re:"The small casing/circulation relief valve discharges a little water during churn to prevent the pump from overheating when running at no flow. NFPA 20 circulation relief valve."},
  {id:282, block:3, sec:"Fire Pumps (NFPA 20)", q:"A MAIN relief valve is required on a fire pump when the system could be exposed to pressures that:", opts:["Could exceed the pressure rating of system components (e.g., diesel overspeed)","Are always safe","Never occur","Equal atmospheric pressure"], correct:0, re:"A main pressure-relief valve protects components when overpressure is possible (e.g., diesel engine running over rated speed, or pressures above the system rating). NFPA 20 main relief valve."},
  {id:283, block:3, sec:"Fire Pumps (NFPA 20)", q:"To prevent the fire pump from cycling (rapid start/stop) on minor leakage, the system relies on the:", opts:["Main drain","Inspector's test valve","Jockey pump and proper pressure settings","Smoke detector"], correct:2, re:"The jockey pump handles small leakage so the main fire pump is not started by minor pressure drops, preventing damaging short-cycling. NFPA 20 pressure-maintenance function."},
  {id:284, block:3, sec:"Fire Pumps (NFPA 20)", q:"A fire pump must be capable of furnishing its required flow even when the suction supply pressure is as low as the lowest value permitted by the AHJ, and NFPA 20 requires suction pressure at 150% flow to remain at least:", opts:["100 psi","50 psi","0 psi (not negative)","175 psi"], correct:2, re:"NFPA 20 generally requires the suction gauge pressure to remain at 0 psi or higher when the pump runs at 150% of rated flow (a small negative is allowed only for listed ground suction-tank arrangements). NFPA 20 suction-pressure requirement."},
  {id:285, block:3, sec:"Fire Pumps (NFPA 20)", q:"A fire pump is installed primarily to:", opts:["Cool the building","Detect smoke","Store water for months","Boost (increase) water pressure and/or flow to meet system demand"], correct:3, re:"A fire pump boosts pressure (and provides flow) when the available supply cannot meet the sprinkler/standpipe demand. NFPA 20 purpose of fire pumps."},
  {id:286, block:3, sec:"Standpipe Systems (NFPA 14)", q:"The standard for the installation of standpipe and hose systems is:", opts:["NFPA 14","NFPA 13","NFPA 20","NFPA 24"], correct:0, re:"NFPA 14 governs the design and installation of standpipe and hose systems in buildings. NFPA 14 scope."},
  {id:287, block:3, sec:"Standpipe Systems (NFPA 14)", q:"A Class I standpipe system provides which size hose connection, intended for fire-department use?", opts:["1-inch","2½-inch","1½-inch","4-inch"], correct:1, re:"Class I provides 2½-in. hose connections for trained firefighters / fire-department use. NFPA 14 Class I."},
  {id:288, block:3, sec:"Standpipe Systems (NFPA 14)", q:"A Class II standpipe system provides 1½-inch hose stations intended primarily for use by:", opts:["The fire department only","Plumbers","Trained building occupants / first-aid firefighting","Elevator technicians"], correct:2, re:"Class II supplies 1½-in. hose (often on a rack/reel) for first-aid firefighting by occupants. NFPA 14 Class II."},
  {id:289, block:3, sec:"Standpipe Systems (NFPA 14)", q:"A Class III standpipe system provides:", opts:["Only 1-inch connections","Both 2½-inch and 1½-inch hose connections (Class I + Class II functions)","No hose connections","Sprinklers only"], correct:1, re:"Class III combines Class I (2½-in.) and Class II (1½-in.) functions, serving both fire-department and occupant use. NFPA 14 Class III."},
  {id:290, block:3, sec:"Standpipe Systems (NFPA 14)", q:"For a Class I or Class III standpipe, NFPA 14 requires a minimum RESIDUAL pressure at the topmost (most remote) 2½-inch outlet of at least:", opts:["100 psi","65 psi","150 psi","175 psi"], correct:0, re:"NFPA 14 requires 100 psi residual at the hydraulically most remote 2½-in. outlet (for the required flow). NFPA 14 Class I/III pressure."},
  {id:291, block:3, sec:"Standpipe Systems (NFPA 14)", q:"For a Class II standpipe, NFPA 14 requires a minimum residual pressure at the most remote 1½-inch outlet of at least:", opts:["25 psi","100 psi","65 psi","175 psi"], correct:2, re:"NFPA 14 requires 65 psi residual at the most remote 1½-in. hose connection for the required Class II flow. NFPA 14 Class II pressure."},
  {id:292, block:3, sec:"Standpipe Systems (NFPA 14)", q:"The minimum flow used to size the most remote Class I standpipe (first/most remote riser) is:", opts:["500 gpm","250 gpm","100 gpm","1,000 gpm"], correct:0, re:"The most remote Class I standpipe is sized for 500 gpm (through the two most remote 2½-in. outlets). NFPA 14 Class I flow."},
  {id:293, block:3, sec:"Standpipe Systems (NFPA 14)", q:"For each ADDITIONAL standpipe beyond the most remote one, NFPA 14 generally adds a flow allowance of:", opts:["50 gpm","100 gpm","500 gpm","250 gpm"], correct:3, re:"Each additional standpipe adds 250 gpm to the demand (for floor areas not exceeding the threshold). NFPA 14 additional-standpipe flow."},
  {id:294, block:3, sec:"Standpipe Systems (NFPA 14)", q:"The minimum flow for a Class II standpipe hose station is:", opts:["50 gpm","500 gpm","250 gpm","100 gpm"], correct:3, re:"A Class II hose station is sized for 100 gpm at the most remote 1½-in. connection. NFPA 14 Class II flow."},
  {id:295, block:3, sec:"Standpipe Systems (NFPA 14)", q:"NFPA 14 caps the total required standpipe system demand for a fully sprinklered building at:", opts:["1,000 gpm","500 gpm","1,250 gpm","2,000 gpm"], correct:0, re:"The total Class I demand need not exceed 1,000 gpm in a building protected throughout by sprinklers (1,250 gpm where not fully sprinklered). NFPA 14 maximum demand."},
  {id:296, block:3, sec:"Standpipe Systems (NFPA 14)", q:"NFPA 14 caps the total required standpipe demand for a building that is NOT fully sprinklered at:", opts:["750 gpm","1,000 gpm","1,250 gpm","2,500 gpm"], correct:2, re:"For buildings not protected throughout by sprinklers, the total Class I standpipe demand need not exceed 1,250 gpm. NFPA 14 maximum demand."},
  {id:297, block:3, sec:"Standpipe Systems (NFPA 14)", q:"Where the static pressure at a hose connection would EXCEED 175 psi, NFPA 14 requires the use of:", opts:["A larger sprinkler","No special device","A check valve only","A pressure-reducing valve (PRV) or pressure-regulating device"], correct:3, re:"To keep hose-connection pressures usable and within limits, pressure-regulating/reducing devices are required where static pressure exceeds about 175 psi. NFPA 14 pressure-regulating requirement."},
  {id:298, block:3, sec:"Standpipe Systems (NFPA 14)", q:"A 'wet' standpipe system differs from a 'dry' (or automatic-dry) standpipe in that the wet system:", opts:["Has no water source","Uses only the fire department's pumper for water","Is filled with water at all times","Has no hose connections"], correct:2, re:"A wet standpipe contains water at all times so flow is immediate; a dry standpipe is normally empty and is filled when needed (manually or automatically). NFPA 14 wet vs. dry standpipe."},
  {id:299, block:3, sec:"Standpipe Systems (NFPA 14)", q:"A fire-department connection (FDC) on a standpipe system allows the fire department to:", opts:["Pump additional water/pressure into the standpipe from a pumper","Drain the system","Shut off the sprinklers","Test the smoke alarms"], correct:0, re:"The FDC lets responding apparatus boost water and pressure into the standpipe/sprinkler system to support firefighting. NFPA 14 fire-department connection."},
  {id:300, block:3, sec:"Standpipe Systems (NFPA 14)", q:"In a high-rise, standpipe hose connections are generally required to be located:", opts:["Only in the lobby","On the roof only","In the exit stairways (and as required at each floor level)","In the elevator car"], correct:2, re:"Standpipe hose connections are located in exit stairways (and other required points) so firefighters can connect at each floor in a protected location. NFPA 14 hose-connection location."},
  {id:301, block:4, sec:"ITM Frequencies & Records", q:"NFPA 25 is the standard for the inspection, testing, and maintenance (ITM) of:", opts:["Water-based fire protection systems","Portable fire extinguishers","Fire alarm systems only","Emergency lighting"], correct:0, re:"NFPA 25 is titled the Standard for the Inspection, Testing, and Maintenance of Water-Based Fire Protection Systems, covering sprinkler, standpipe, fire pump and related systems (NFPA 25 Ch. 1)."},
  {id:302, block:4, sec:"ITM Frequencies & Records", q:"Under NFPA 25, the party ultimately responsible for keeping ITM records and making them available to the AHJ is the:", opts:["Sprinkler contractor","Property owner or designated representative","Fire department","Insurance company"], correct:1, re:"NFPA 25 Ch. 4 (Owner Responsibilities) places responsibility for ITM, recordkeeping, and providing records to the AHJ on the property owner or their designated representative."},
  {id:303, block:4, sec:"ITM Frequencies & Records", q:"NFPA 25 defines an 'annual' frequency as occurring once per year within a range of:", opts:["Exactly 12 months only","Minimum 6 months, maximum 18 months","Minimum 9 months, maximum 15 months","Minimum 11 months, maximum 13 months"], correct:2, re:"NFPA 25 defines annual as once per year with a minimum of 9 months and a maximum of 15 months between activities (NFPA 25 frequency definitions, Ch. 3)."},
  {id:304, block:4, sec:"ITM Frequencies & Records", q:"Under NFPA 25, the main drain test on each system riser is conducted at least:", opts:["Weekly","Monthly","Every 5 years","Annually"], correct:3, re:"NFPA 25 (Ch. 13) requires a main drain test at least annually at each water-based system riser to detect a change in the water supply or control valves."},
  {id:305, block:4, sec:"ITM Frequencies & Records", q:"How often must a forward flow test of a backflow preventer in a fire protection system be performed under NFPA 25?", opts:["Annually","Quarterly","Every 3 years","Every 5 years"], correct:0, re:"NFPA 25 (Ch. 13) requires backflow prevention assemblies in fire protection piping to be forward flow tested annually at the system demand flow rate."},
  {id:306, block:4, sec:"ITM Frequencies & Records", q:"A full-flow trip test of a dry pipe valve must be performed at least every:", opts:["Year","3 years","2 years","5 years"], correct:1, re:"NFPA 25 (Ch. 13) requires a full-flow trip test of dry pipe valves at least every 3 years, in addition to the annual partial (priming-line) trip test."},
  {id:307, block:4, sec:"ITM Frequencies & Records", q:"Under NFPA 25, system pressure gauges are to be replaced or tested by comparison to a calibrated gauge at least every:", opts:["Year","3 years","5 years","10 years"], correct:2, re:"NFPA 25 (Ch. 13) requires gauges to be replaced or tested against a calibrated gauge every 5 years; gauges off by more than 3% of full scale are recalibrated or replaced."},
  {id:308, block:4, sec:"ITM Frequencies & Records", q:"Waterflow alarm devices on wet pipe systems are functionally tested at what minimum frequency under NFPA 25?", opts:["Weekly","Monthly","Annually","Quarterly"], correct:3, re:"NFPA 25 (Ch. 5) requires waterflow alarm devices on wet pipe sprinkler systems to be tested quarterly via the inspector's test connection."},
  {id:309, block:4, sec:"ITM Frequencies & Records", q:"Antifreeze solutions in a sprinkler system must be tested for concentration at least:", opts:["Annually","Quarterly","Monthly","Every 5 years"], correct:0, re:"NFPA 25 (Ch. 5) requires antifreeze solutions to be tested at least annually, before the onset of freezing weather, to confirm proper freeze protection."},
  {id:310, block:4, sec:"ITM Frequencies & Records", q:"Under NFPA 25, internal examination of piping for obstructions (the 5-year internal inspection) is performed every:", opts:["Year","5 years","3 years","10 years"], correct:1, re:"NFPA 25 (Ch. 14) requires an internal inspection of piping for obstructing material every 5 years to look for foreign matter, tuberculation, sludge, or MIC."},
  {id:311, block:4, sec:"ITM Frequencies & Records", q:"Valve supervisory (tamper) switches are tested for proper signal at what frequency under NFPA 25?", opts:["Quarterly","Annually","Semiannually","Every 5 years"], correct:2, re:"NFPA 25 (Ch. 13) requires valve supervisory switches to be tested semiannually (every 6 months) to verify a signal when the valve is moved off its normal position."},
  {id:312, block:4, sec:"ITM Frequencies & Records", q:"Standard-response sprinklers (manufactured 1920 or later) first require representative sample testing at what age, then every 10 years thereafter?", opts:["20 years","100 years","75 years","50 years"], correct:3, re:"NFPA 25 (Ch. 5) requires standard-response sprinklers to be sample-tested at 50 years and every 10 years thereafter; at 75 years the interval shortens to every 5 years (or replace)."},
  {id:313, block:4, sec:"ITM Frequencies & Records", q:"Dry-type sprinklers (with an extended dry barrel) require representative sample testing beginning at what age?", opts:["20 years","10 years","50 years","75 years"], correct:0, re:"NFPA 25 (Ch. 5) requires dry-type sprinklers to be sample-tested 10 years after manufacture in older editions; the widely cited interval is 20 years after installation then every 10 years (NFPA 25 2023)."},
  {id:314, block:4, sec:"ITM Frequencies & Records", q:"Under NFPA 25, ITM records must be retained for at least:", opts:["30 days","1 year after the next inspection of that type","6 months","Forever"], correct:1, re:"NFPA 25 Ch. 4 requires records be retained for 1 year after the next ITM activity of the same type (longer if the local code, e.g. IFC, requires more)."},
  {id:315, block:4, sec:"ITM Frequencies & Records", q:"On a wet pipe system, the gauge near the alarm valve is inspected (read) at what minimum frequency under NFPA 25?", opts:["Daily","Weekly","Monthly","Annually"], correct:2, re:"NFPA 25 (Ch. 5/13) requires gauges on wet pipe systems to be inspected monthly to confirm normal water pressure; dry/preaction systems are checked weekly."},
  {id:316, block:4, sec:"ITM Frequencies & Records", q:"A water motor gong (mechanical waterflow alarm) is tested at what minimum frequency under NFPA 25?", opts:["Every 5 years","Semiannually","Annually","Quarterly"], correct:3, re:"NFPA 25 (Ch. 5) requires mechanical waterflow devices such as a water motor gong to be tested quarterly; pressure-switch and vane-type devices are tested semiannually."},
  {id:317, block:4, sec:"ITM Frequencies & Records", q:"Who, under NFPA 25, must be qualified and competent to perform ITM on water-based fire protection systems?", opts:["Personnel who have developed competence through training and experience","Any building occupant","Only a registered architect","Only the fire marshal"], correct:0, re:"NFPA 25 Ch. 4 requires ITM to be performed by qualified personnel who have developed competence through training and experience; many jurisdictions, including California, also require licensing/certification."},
  {id:318, block:4, sec:"Hydrostatic & Acceptance Testing", q:"New sprinkler piping must be hydrostatically tested at what minimum pressure for 2 hours under NFPA 13?", opts:["100 psi","200 psi","150 psi","300 psi"], correct:1, re:"NFPA 13 requires new sprinkler systems to be hydrostatically tested at not less than 200 psi for 2 hours (or 50 psi above the maximum static pressure when that exceeds 150 psi)."},
  {id:319, block:4, sec:"Hydrostatic & Acceptance Testing", q:"When the normal static pressure exceeds 150 psi, the acceptance hydrostatic test pressure must be at least:", opts:["200 psi","Twice the static pressure","50 psi above the maximum static pressure","The same as static pressure"], correct:2, re:"NFPA 13 requires the test pressure to be 50 psi in excess of the maximum static (system) pressure where that maximum exceeds 150 psi; otherwise 200 psi is used."},
  {id:320, block:4, sec:"Hydrostatic & Acceptance Testing", q:"The acceptance hydrostatic test must hold the required pressure for a minimum duration of:", opts:["30 minutes","1 hour","24 hours","2 hours"], correct:3, re:"NFPA 13 requires the hydrostatic test pressure to be maintained for 2 hours with no visible leakage and acceptable pressure loss."},
  {id:321, block:4, sec:"Hydrostatic & Acceptance Testing", q:"A hydrostatic test on new metallic sprinkler piping is considered successful when, after 2 hours, there is:", opts:["No visible leakage (and pressure loss does not exceed 5 psi where measured)","No more than a 10 psi drop","Any drop less than 50 psi","A pressure increase"], correct:0, re:"NFPA 13 acceptance criteria require no visible leakage; where pressure-loss criteria apply, loss is limited to about 5 psi over 2 hours for the test to pass."},
  {id:322, block:4, sec:"Hydrostatic & Acceptance Testing", q:"Hydrostatic acceptance tests of fire sprinkler piping are normally performed using:", opts:["Compressed air only","Water","Nitrogen","Steam"], correct:1, re:"NFPA 13 requires hydrostatic tests to be performed with water; an air leakage (pneumatic) test is only an additional check on dry/preaction systems, not a substitute for the hydrostatic test."},
  {id:323, block:4, sec:"Hydrostatic & Acceptance Testing", q:"Dry pipe and preaction systems, in addition to the hydrostatic test, also receive an air pressure leakage test of:", opts:["200 psi for 2 hours","100 psi for 1 hour","40 psi for 24 hours","No air test is allowed"], correct:2, re:"NFPA 13 requires dry/preaction systems to also be air-tested at 40 psi for 24 hours, with a maximum allowable loss of 1.5 psi over that period."},
  {id:324, block:4, sec:"Hydrostatic & Acceptance Testing", q:"When pneumatically testing a dry/preaction system at 40 psi for 24 hours, the maximum allowable pressure loss is:", opts:["20 psi","5 psi","10 psi","1.5 psi"], correct:3, re:"NFPA 13 limits the 24-hour, 40 psi air test loss to 1.5 psi; greater loss indicates leaks that must be found and corrected."},
  {id:325, block:4, sec:"Hydrostatic & Acceptance Testing", q:"Manual and semiautomatic dry standpipe systems are hydrostatically retested under NFPA 25 at what interval?", opts:["Every 5 years","Every 3 years","Annually","Every 10 years"], correct:0, re:"NFPA 25 (Ch. 6) requires manual and semiautomatic dry standpipe systems to be hydrostatically tested at 200 psi (or 50 psi above maximum pressure) for 2 hours every 5 years."},
  {id:326, block:4, sec:"Hydrostatic & Acceptance Testing", q:"During acceptance, the underground supply main feeding a sprinkler system must be flushed before connection primarily to:", opts:["Increase water pressure","Remove debris, rocks, and foreign matter that could obstruct sprinklers","Test the backflow preventer","Chlorinate the water"], correct:1, re:"NFPA 24/13 require the underground lead-in to be flushed at high velocity before connecting the system so that stones, mud, and debris cannot enter and plug sprinklers or valves."},
  {id:327, block:4, sec:"Hydrostatic & Acceptance Testing", q:"The contractor's material and test certificate for an aboveground sprinkler system is completed and signed:", opts:["Before any pipe is installed","Only if the AHJ requests it","After acceptance testing, documenting the test results","Every year during ITM"], correct:2, re:"NFPA 13 requires the Contractor's Material and Test Certificate for Aboveground Piping to be completed after acceptance testing to document the hydrostatic test, flushing, and other results, and provided to the owner/AHJ."},
  {id:328, block:4, sec:"Hydrostatic & Acceptance Testing", q:"During the hydrostatic acceptance test, gauges, alarm devices, and other equipment not rated for the test pressure should be:", opts:["Left in place to test them too","Painted","Set to maximum","Isolated or removed so they are not damaged"], correct:3, re:"Equipment not rated for the elevated test pressure (e.g., certain gauges, dry valve trim, alarm devices) is isolated or removed during the hydrostatic test to avoid damage, per NFPA 13 practice."},
  {id:329, block:4, sec:"Hydrostatic & Acceptance Testing", q:"A hydrostatic test should be conducted using a test pump, with the system pressure relieved before disconnecting, because:", opts:["Trapped high pressure can cause injury or component damage if released suddenly","The water is reusable","It speeds the test","Code forbids gauges"], correct:0, re:"Stored hydrostatic energy is hazardous; relieving pressure before breaking connections prevents injury and equipment damage. This is standard safe practice in NFPA 13/25 testing."},
  {id:330, block:4, sec:"Hydrostatic & Acceptance Testing", q:"After an addition or modification of more than 20 sprinklers to an existing system, NFPA 13 typically requires:", opts:["No testing","An acceptance hydrostatic test of the new work","A 5-year obstruction investigation","Only a visual check"], correct:1, re:"NFPA 13 requires acceptance (hydrostatic) testing of new or modified piping; modifications affecting more than 20 sprinklers generally trigger full acceptance testing of the affected work and notification of the AHJ."},
  {id:331, block:4, sec:"Hydrostatic & Acceptance Testing", q:"Before performing a hydrostatic test in freezing conditions, the tester must ensure the test water:", opts:["Is heated to boiling","Contains foam concentrate","Will not freeze in the piping during or after the test","Is salt water"], correct:2, re:"Test water must be protected from freezing; ice can damage piping and invalidate results. NFPA 13 cautions against hydrostatic testing where water may freeze before it is drained."},
  {id:332, block:4, sec:"Hydrostatic & Acceptance Testing", q:"The acceptance test of a sprinkler system's operating (alarm) function during commissioning verifies that:", opts:["The pipe color is correct","The owner has insurance","Heads are painted","Waterflow through the system actuates the waterflow alarm"], correct:3, re:"Acceptance testing includes an operational test confirming that flow actuates the waterflow alarm (water motor gong/pressure switch) within the required time, demonstrating the alarm path works."},
  {id:333, block:4, sec:"Hydrostatic & Acceptance Testing", q:"A flushing investigation/flow test of the underground and lead-in connection at acceptance is performed at a velocity sufficient to:", opts:["Carry out obstructing material (a recognized minimum flushing velocity)","Burst the pipe","Fill a storage tank","Test the sprinkler heads"], correct:0, re:"NFPA 24 specifies minimum flushing flows by pipe size to achieve a velocity (about 10 ft/s) that scours debris from the main before it can enter the system."},
  {id:334, block:4, sec:"Hydrostatic & Acceptance Testing", q:"For CPVC and other nonmetallic sprinkler pipe, the manufacturer's instructions for hydrostatic testing must be followed because:", opts:["Plastic cannot be tested","Cure time and pressure limits differ from steel and must be respected","It is exempt from NFPA 13","Air testing replaces water testing"], correct:1, re:"Listed nonmetallic pipe (e.g., CPVC) requires solvent-cement cure time before pressurizing and has specific test parameters; NFPA 13 requires following the manufacturer's listing and instructions."},
  {id:335, block:4, sec:"Main Drain & Forward Flow Tests", q:"The primary purpose of the main drain test is to:", opts:["Drain the system for winter","Test the sprinkler heads","Detect a change in the condition of the water supply and main control valve","Flush antifreeze out"], correct:2, re:"NFPA 25 (Ch. 13) states the main drain test detects a change in the water supply piping and the main control valve (e.g., a partially closed valve or supply deterioration)."},
  {id:336, block:4, sec:"Main Drain & Forward Flow Tests", q:"During a main drain test you record the static pressure, then fully open the main drain and record the:", opts:["Air pressure","Pipe diameter","Sprinkler temperature","Residual (flowing) pressure"], correct:3, re:"The test compares static pressure to residual pressure with the drain wide open; the residual reading is compared to prior tests and the original acceptance value (NFPA 25 Ch. 13)."},
  {id:337, block:4, sec:"Main Drain & Forward Flow Tests", q:"Under NFPA 25, what reduction in full-flow main drain pressure compared to previous results requires investigation?", opts:["10% or greater","Any reduction at all","25% or greater","50% or greater"], correct:0, re:"NFPA 25 (Ch. 13) requires investigation when there is a 10% or greater reduction in full-flow (residual) pressure compared to the original acceptance test or previous results."},
  {id:338, block:4, sec:"Main Drain & Forward Flow Tests", q:"A sharply reduced residual pressure on a main drain test most commonly indicates:", opts:["Too many sprinklers","A partially closed valve or obstructed supply","A new pump","Cold weather"], correct:1, re:"A large drop or low residual typically points to a partially closed control valve, an obstruction, or a deteriorated supply, all of which must be investigated and corrected (NFPA 25 Ch. 13)."},
  {id:339, block:4, sec:"Main Drain & Forward Flow Tests", q:"When the sole water supply to a system is through a backflow preventer or pressure-reducing valve, NFPA 25 requires the main drain test:", opts:["Never","Only at 5 years","Quarterly (on a downstream system)","Only at acceptance"], correct:2, re:"NFPA 25 (Ch. 13) requires a quarterly main drain test on a system downstream where the supply passes through a backflow preventer or PRV, to confirm the device and valve are not impairing flow."},
  {id:340, block:4, sec:"Main Drain & Forward Flow Tests", q:"A forward flow test of a backflow preventer verifies the device can pass:", opts:["Zero flow","Reverse flow","Only 50 gpm","The full system demand including any hose stream allowance"], correct:3, re:"NFPA 25 (Ch. 13) requires the forward flow test to demonstrate the backflow assembly can deliver the system demand (plus hose allowance where part of the demand) without excessive pressure loss."},
  {id:341, block:4, sec:"Main Drain & Forward Flow Tests", q:"Where a metered or full-demand forward flow test cannot be conducted, NFPA 25 allows the forward flow test to be performed by:", opts:["Flowing water through the system main drain or other connection at the maximum achievable rate","Skipping it","Closing the supply valve","Using compressed air"], correct:0, re:"NFPA 25 permits the forward flow test through the system main drain or a connection sized to flow the system demand when a metered connection is not available, achieving the maximum flow possible."},
  {id:342, block:4, sec:"Main Drain & Forward Flow Tests", q:"The main drain valve used for the test is typically located:", opts:["At the highest point of the system","At the system riser, downstream of the main control valve","Only at the fire department connection","In the attic"], correct:1, re:"The main drain connection is on the riser downstream of the main control valve so the test reflects supply through that valve; opening it flows water to evaluate the supply (NFPA 25 Ch. 13)."},
  {id:343, block:4, sec:"Main Drain & Forward Flow Tests", q:"Before closing the main drain at the end of the test, the valve should be closed:", opts:["As fast as possible","Halfway only","Slowly, to avoid a water hammer surge","Never closed"], correct:2, re:"Closing the main drain slowly prevents water hammer (pressure surge) that could damage piping, gauges, or fittings; gradual operation is standard safe practice."},
  {id:344, block:4, sec:"Main Drain & Forward Flow Tests", q:"After a main drain test on a dry pipe or preaction system, the technician must remember to:", opts:["Leave the valve open","Remove the gauges","Drain the antifreeze","Restore the system to service (reset the dry valve, restore air pressure) and confirm set"], correct:3, re:"On dry/preaction systems the main drain test can trip or partially operate trim; the system must be restored to its normal set condition and confirmed in service afterward."},
  {id:345, block:4, sec:"Main Drain & Forward Flow Tests", q:"The main drain test results are most useful when compared against:", opts:["The original acceptance test data and previous annual results","A neighboring building","The air pressure gauge","The thermometer"], correct:0, re:"NFPA 25 emphasizes trending: comparing current static/residual readings to acceptance and prior tests reveals gradual supply deterioration or a creeping valve closure (Ch. 13)."},
  {id:346, block:4, sec:"Main Drain & Forward Flow Tests", q:"A forward flow test that cannot achieve full system demand should at minimum confirm:", opts:["The pipe is red","Flow can be established and the device is not obstructed, with results recorded","The building is occupied","The pump is off"], correct:1, re:"When full demand is not achievable, NFPA 25 still requires establishing flow to verify the assembly is not stuck/obstructed; the achievable flow and pressures are documented for trending."},
  {id:347, block:4, sec:"Main Drain & Forward Flow Tests", q:"During the main drain test, a NO-change or normal residual pressure indicates:", opts:["Sprinklers have operated","The system has failed","The supply main is likely clear and the control valve open","The pump has failed"], correct:2, re:"A residual close to historical values indicates the water supply and control valve are in their expected condition; significant deviation triggers investigation (NFPA 25 Ch. 13)."},
  {id:348, block:4, sec:"Main Drain & Forward Flow Tests", q:"Discharge from the main drain during testing should be directed to:", opts:["The electrical room","The sprinkler heads","The roof","An approved drain or location where it will not cause damage"], correct:3, re:"Main drain discharge must go to a safe, approved point so the large flow does not flood occupied space or damage property; planning the discharge path is part of the test procedure."},
  {id:349, block:4, sec:"Main Drain & Forward Flow Tests", q:"A main drain test is also performed any time the main control valve has been:", opts:["Closed and reopened (to verify the supply was restored)","Painted","Inspected visually","Labeled"], correct:0, re:"Whenever the main control valve is operated/closed and reopened, a main drain test confirms full water supply was restored (the valve is truly fully open), per NFPA 25 practice."},
  {id:350, block:4, sec:"Main Drain & Forward Flow Tests", q:"The flow rate during a forward flow test of a backflow assembly should be the:", opts:["Lowest possible flow","System demand (the design flow the assembly must pass)","Twice the system demand","Zero"], correct:1, re:"NFPA 25 (Ch. 13) sets the forward flow test rate at the system demand so the test proves the backflow preventer will not choke the design flow in a fire."},
  {id:351, block:4, sec:"Backflow Prevention", q:"A backflow preventer is installed on a fire sprinkler service primarily to:", opts:["Increase pressure","Filter the water","Prevent potentially contaminated system water from flowing back into the potable supply","Measure flow"], correct:2, re:"A backflow preventer protects the public potable water system from cross-contamination by stagnant/treated sprinkler water flowing backward; it is a cross-connection control device."},
  {id:352, block:4, sec:"Backflow Prevention", q:"Under NFPA 25, how often is a backflow preventer forward flow tested?", opts:["Quarterly","Semiannually","Every 5 years","Annually"], correct:3, re:"NFPA 25 (Ch. 13) requires an annual forward flow test of backflow prevention assemblies at the system demand flow rate."},
  {id:353, block:4, sec:"Backflow Prevention", q:"An internal inspection of a backflow preventer's check valves and components is required under NFPA 25 every:", opts:["5 years","2 years","Year","10 years"], correct:0, re:"NFPA 25 (Ch. 13) requires internal inspection of backflow assemblies every 5 years to confirm components move freely and seats/seals are in good condition (consistent with manufacturer/AHJ)."},
  {id:354, block:4, sec:"Backflow Prevention", q:"In addition to NFPA 25 forward flow testing, most jurisdictions require an operational/differential pressure test of a backflow assembly by a certified backflow tester:", opts:["Never","Annually","Only at installation","Every 10 years"], correct:1, re:"Cross-connection control programs (and California/water-purveyor rules) typically require an annual certified backflow test of the differential and check valves, separate from the NFPA 25 forward flow test."},
  {id:355, block:4, sec:"Backflow Prevention", q:"A double check valve assembly (DCVA) provides backflow protection by using:", opts:["A single check valve","An air gap only","Two independently operating check valves in series","A pressure gauge"], correct:2, re:"A DCVA uses two spring-loaded check valves in series with test cocks and shutoffs; it is common where the sprinkler water is a non-health hazard (no additives)."},
  {id:356, block:4, sec:"Backflow Prevention", q:"A reduced pressure (RP/RPZ) backflow assembly is generally required when the sprinkler system contains:", opts:["Only plain water","Air only","No water","Antifreeze, foam, or other additives (a health hazard cross-connection)"], correct:3, re:"Where additives such as antifreeze or foam create a health hazard, a reduced-pressure principle assembly (with a relief valve venting to atmosphere) is required for higher protection."},
  {id:357, block:4, sec:"Backflow Prevention", q:"The relief (discharge) port of an RPZ assembly venting water during normal standby may indicate:", opts:["A fouled or leaking check valve needing service","Normal high flow","Correct operation always","The pump is running"], correct:0, re:"Continuous discharge from the RPZ relief valve usually signals fouled checks or a failed relief valve seat and must be investigated; brief discharge on pressure fluctuation can be normal."},
  {id:358, block:4, sec:"Backflow Prevention", q:"Adding a backflow preventer to an existing fire sprinkler service can reduce available pressure, so NFPA 13/25 require:", opts:["Ignoring the loss","Accounting for the device's pressure loss in the hydraulic design/forward flow verification","Removing sprinklers","Doubling the pipe size always"], correct:1, re:"A backflow assembly adds friction loss; the system demand must still be met through it, which the forward flow test and hydraulic calculations verify."},
  {id:359, block:4, sec:"Backflow Prevention", q:"After internally inspecting or repairing a backflow preventer, the assembly must be:", opts:["Left open to drain","Painted red","Returned to service and a forward flow test/operational test performed to confirm function","Removed permanently"], correct:2, re:"Following internal inspection or repair, NFPA 25 requires the assembly be returned to service and tested (forward flow plus the certified differential test) to confirm it works and passes design flow."},
  {id:360, block:4, sec:"Backflow Prevention", q:"Where a backflow preventer or PRV is the sole supply path, the quarterly main drain test mainly serves to:", opts:["Test the sprinklers","Fill the tank","Drain the system","Exercise the device and confirm it is not impairing the water supply"], correct:3, re:"The quarterly main drain test on a system fed solely through a backflow/PRV exercises those components and verifies they are not stuck or fouled, choking the supply (NFPA 25 Ch. 13)."},
  {id:361, block:4, sec:"Backflow Prevention", q:"The shutoff valves on a backflow assembly are typically required to be:", opts:["Supervised (locked/sealed or electrically monitored) so they are not left closed","Unsupervised and free to close","Removed","Welded shut"], correct:0, re:"Because a closed backflow shutoff disables the entire system, those valves must be supervised by the same means as other control valves (NFPA 25 Ch. 13 control valve requirements)."},
  {id:362, block:4, sec:"Backflow Prevention", q:"A forward flow test through a backflow preventer is documented with which key data?", opts:["Only the date","Flow rate achieved and inlet/outlet pressures (and pressure loss across the device)","The pipe color","The technician's lunch break"], correct:1, re:"The forward flow test record should capture the flow achieved and pressures so loss across the device and ability to meet demand can be trended over time (NFPA 25 Ch. 13)."},
  {id:363, block:4, sec:"Backflow Prevention", q:"A backflow assembly that fails its certified differential pressure test must be:", opts:["Ignored until next year","Painted","Repaired or replaced and retested before being relied upon","Left in service"], correct:2, re:"A failed backflow test means the device is not providing protection or may be restricting flow; it must be repaired/replaced and retested before the system is considered protected."},
  {id:364, block:4, sec:"Backflow Prevention", q:"Locating an RPZ assembly so its relief discharge drains properly is important because the assembly:", opts:["Never discharges","Discharges only air","Is sealed","Can discharge significant water and must drain to an approved point without flooding"], correct:3, re:"An RPZ can dump a large volume from the relief port during a check failure or surge; an adequate air gap and floor drain prevent flooding and back-pressure on the relief valve."},
  {id:365, block:4, sec:"Backflow Prevention", q:"The test cocks on a backflow assembly are used to:", opts:["Connect test gauges to check the checks and relief valve differential","Drain the building","Add antifreeze","Vent air from sprinklers"], correct:0, re:"Test cocks are the gauge connection points a certified tester uses to measure the differential across each check and the relief valve opening point during the annual operational test."},
  {id:366, block:4, sec:"Backflow Prevention", q:"Compared with a DCVA, an RPZ assembly typically causes:", opts:["No pressure loss","Greater pressure loss, which must be considered in system demand","Negative pressure loss","An increase in pressure"], correct:1, re:"The relief mechanism and additional internals of an RPZ usually create more friction loss than a DCVA; this added loss must be accounted for so the system still meets demand."},
  {id:367, block:4, sec:"Alarm & Waterflow Device Testing", q:"A waterflow alarm test on a wet pipe system is performed by opening the:", opts:["Main control valve","Fire department connection","Inspector's test connection","Antifreeze loop"], correct:2, re:"The inspector's test connection has an orifice equivalent to one sprinkler; opening it flows water to actuate the waterflow alarm, simulating a single sprinkler operating (NFPA 25 Ch. 5)."},
  {id:368, block:4, sec:"Alarm & Waterflow Device Testing", q:"After opening the inspector's test connection, a waterflow alarm must actuate within a maximum of:", opts:["10 seconds","30 seconds","5 minutes","90 seconds"], correct:3, re:"NFPA 13/25 require the waterflow alarm to operate within 90 seconds of flow equal to one sprinkler at the inspector's test connection."},
  {id:369, block:4, sec:"Alarm & Waterflow Device Testing", q:"The inspector's test connection orifice is sized to discharge the equivalent of:", opts:["One sprinkler (the smallest orifice on the system)","A 2.5-inch fire hose","The whole system at once","No flow"], correct:0, re:"NFPA 13 requires the inspector's test connection to have an orifice equivalent to the smallest sprinkler on the system, so the alarm test simulates one operating sprinkler."},
  {id:370, block:4, sec:"Alarm & Waterflow Device Testing", q:"A vane-type waterflow switch is NOT permitted on which system because tripping flow could break the vane?", opts:["Wet pipe","Dry pipe","Gridded wet","Looped wet"], correct:1, re:"NFPA 13/25 prohibit vane-type waterflow devices on dry pipe systems; the surge when the dry valve trips could shear the vane and send it into the piping. Pressure-type switches are used instead."},
  {id:371, block:4, sec:"Alarm & Waterflow Device Testing", q:"Pressure-switch type and vane-type waterflow alarm devices are functionally tested under NFPA 25 at what minimum frequency?", opts:["Quarterly","Annually","Semiannually","Every 5 years"], correct:2, re:"NFPA 25 (Ch. 5) requires vane-type and pressure-switch waterflow alarm devices to be tested semiannually, while mechanical water motor gongs are tested quarterly."},
  {id:372, block:4, sec:"Alarm & Waterflow Device Testing", q:"On a dry pipe system, opening the inspector's test connection for an alarm test will:", opts:["Do nothing","Close the main valve","Add antifreeze","Drop air pressure and trip the dry valve, sending water (a partial/full trip test)"], correct:3, re:"Because dry systems hold air, flowing the inspector's test connection bleeds air and can trip the dry valve; alarm/trip testing on dry systems must be planned to avoid an unintended full trip when only an alarm test is intended."},
  {id:373, block:4, sec:"Alarm & Waterflow Device Testing", q:"A supervisory device on a sprinkler system monitors conditions such as:", opts:["Control valve position, low air pressure, or low temperature","Room temperature for comfort","Lighting levels","Door locks"], correct:0, re:"Supervisory signals indicate off-normal conditions (valve closed, low/high air pressure, low building/enclosure temperature, low water level) that could impair the system (NFPA 25/72)."},
  {id:374, block:4, sec:"Alarm & Waterflow Device Testing", q:"Low air pressure supervisory alarms on dry/preaction systems are tested under NFPA 25:", opts:["Never","Annually (or per manufacturer)","Every 10 years","Only at acceptance"], correct:1, re:"NFPA 25 (Ch. 5/13) requires low air (and low temperature, low water) supervisory signal devices to be tested at least annually, or in accordance with the manufacturer's instructions."},
  {id:375, block:4, sec:"Alarm & Waterflow Device Testing", q:"When a waterflow alarm is interfaced with a fire alarm control panel, the alarm signal transmission to the panel is verified under which companion standard?", opts:["NFPA 13 only","NFPA 10","NFPA 72","NFPA 30"], correct:2, re:"NFPA 72 (National Fire Alarm and Signaling Code) governs the initiating-device circuit and signal verification when sprinkler waterflow/supervisory devices connect to the fire alarm system."},
  {id:376, block:4, sec:"Alarm & Waterflow Device Testing", q:"A retard chamber installed ahead of a wet pipe waterflow pressure switch is used to:", opts:["Increase pressure","Drain the system","Filter water","Absorb brief surges/pressure fluctuations to prevent false alarms"], correct:3, re:"The retard chamber delays alarm actuation through momentary surges (e.g., water hammer) so only sustained flow triggers the alarm, reducing nuisance alarms; it must still allow alarm within 90 seconds of real flow."},
  {id:377, block:4, sec:"Alarm & Waterflow Device Testing", q:"During a waterflow alarm test, the technician should first notify the:", opts:["Monitoring station/occupants so the alarm is not mistaken for a real fire","Window washer","Water utility billing dept","Roofing contractor"], correct:0, re:"Because testing actuates real alarm signals, the central monitoring station and building occupants must be notified beforehand and the system placed on test to avoid a false dispatch (NFPA 25/72 practice)."},
  {id:378, block:4, sec:"Alarm & Waterflow Device Testing", q:"A water motor gong (mechanical alarm) is driven by:", opts:["An electric motor","Waterflow through a small water motor that strikes the gong","Compressed air","A spring clock"], correct:1, re:"The water motor gong uses a small Pelton-type water motor energized by alarm-line flow to mechanically strike the gong; it requires no electricity and is tested quarterly (NFPA 25 Ch. 5)."},
  {id:379, block:4, sec:"Alarm & Waterflow Device Testing", q:"Waterflow and supervisory initiating devices are inspected (visually, for physical damage) at what frequency under NFPA 25?", opts:["Daily","Every 3 years","Quarterly","Every 5 years"], correct:2, re:"NFPA 25 (Ch. 5) requires quarterly inspection of waterflow and supervisory signal-initiating devices to confirm they are free of physical damage, in addition to functional testing."},
  {id:380, block:4, sec:"Alarm & Waterflow Device Testing", q:"After completing alarm/waterflow testing, the technician must confirm that:", opts:["The alarm is left ringing","The gauges are removed","The valve is left closed","All devices reset, the system is back in service, and monitoring is taken off test"], correct:3, re:"Restoring service means verifying devices reset, valves are open and supervised, air/water pressures are normal, and the monitoring station is taken off test mode and re-armed."},
  {id:381, block:4, sec:"Alarm & Waterflow Device Testing", q:"A pressure-type waterflow switch operates by sensing:", opts:["A pressure rise in the alarm/system line caused by flow","Vane deflection","Temperature","Smoke"], correct:0, re:"A pressure-actuated waterflow switch closes its contacts when alarm-line pressure rises due to flow; unlike a vane switch it has no moving paddle in the waterway, so it suits dry systems."},
  {id:382, block:4, sec:"Alarm & Waterflow Device Testing", q:"If a waterflow alarm fails to operate within 90 seconds during testing, the technician should:", opts:["Pass it anyway","Investigate and correct the cause (e.g., obstruction, faulty switch, closed alarm valve)","Remove the device","Wait a week"], correct:1, re:"Failure to alarm within the required time is a deficiency; the cause (blocked alarm port, stuck retard chamber, defective switch, or closed alarm valve) must be found and corrected and the device retested."},
  {id:383, block:4, sec:"Alarm & Waterflow Device Testing", q:"The inspector's test connection is normally located:", opts:["At the main valve","In the fire pump room","At the hydraulically most remote point of the system","At the FDC"], correct:2, re:"The inspector's test connection is placed at or near the most remote point so its single-sprinkler-equivalent flow represents the worst case for actuating the alarm and verifying flow path (NFPA 13)."},
  {id:384, block:4, sec:"Impairments & Obstruction Investigation", q:"In NFPA 25 terms, an 'impairment' is a condition where:", opts:["A sprinkler is dusty","A gauge reads slightly off","The paint is faded","A water-based fire protection system (or part) is out of order/not able to function as intended"], correct:3, re:"NFPA 25 (Ch. 15) defines an impairment as a condition in which a fire protection system or portion is out of order, resulting in the system not functioning if a fire occurs."},
  {id:385, block:4, sec:"Impairments & Obstruction Investigation", q:"A planned outage of a sprinkler system for scheduled work is classified as a(n):", opts:["Preplanned impairment","Emergency impairment","Permanent shutdown","Acceptance test"], correct:0, re:"NFPA 25 (Ch. 15) distinguishes preplanned impairments (scheduled, e.g., for maintenance/modification) from emergency impairments (unexpected, e.g., a break or fire damage)."},
  {id:386, block:4, sec:"Impairments & Obstruction Investigation", q:"Under NFPA 25, the person responsible for managing an impairment is the:", opts:["Window cleaner","Impairment coordinator","Architect","Tenant"], correct:1, re:"NFPA 25 (Ch. 15) requires the owner to assign an impairment coordinator who oversees the steps before, during, and at the restoration of any impairment."},
  {id:387, block:4, sec:"Impairments & Obstruction Investigation", q:"A break or accidental shutoff that takes a system out of service unexpectedly is a(n):", opts:["Preplanned impairment","5-year obstruction investigation","Emergency impairment","Forward flow test"], correct:2, re:"NFPA 25 (Ch. 15) classifies unexpected losses of protection (pipe break, frozen/burst pipe, valve found shut, fire/water damage) as emergency impairments requiring immediate action."},
  {id:388, block:4, sec:"Impairments & Obstruction Investigation", q:"When a system is impaired, NFPA 25 requires a tag indicating the impairment be placed:", opts:["Only in the office file","On every sprinkler","On the roof","At each fire department connection and system control valve (and other AHJ-designated points)"], correct:3, re:"NFPA 25 (Ch. 15) requires the impairment tag at each FDC, the main control valve, and other points the AHJ designates so responders and staff know the system is out of service."},
  {id:389, block:4, sec:"Impairments & Obstruction Investigation", q:"Before a preplanned impairment begins, the impairment coordinator should determine the extent and expected duration and:", opts:["Inspect affected areas for increased risk and notify the fire department, alarm company, and occupants","Do nothing else","Shut off the electricity","Remove the sprinklers"], correct:0, re:"NFPA 25 (Ch. 15) lists pre-impairment steps: assess extent/duration, inspect for increased hazards, notify the FD/alarm monitoring/insurer/occupants, and prepare to mitigate (e.g., fire watch)."},
  {id:390, block:4, sec:"Impairments & Obstruction Investigation", q:"NFPA 25 requires mitigation such as a fire watch when a water-based system impairment exceeds what duration in a 24-hour period?", opts:["1 hour","10 hours","4 hours","48 hours"], correct:1, re:"NFPA 25 (Ch. 15) requires evacuation or an approved fire watch (or temporary protection) when a water-based system is impaired more than 10 hours in any 24-hour period."},
  {id:391, block:4, sec:"Impairments & Obstruction Investigation", q:"A fire watch performed during an impairment consists of:", opts:["An automatic camera","A locked door","Trained personnel patrolling the affected area to detect fire and notify the fire department","An extra sprinkler"], correct:2, re:"A fire watch is one or more trained persons continuously patrolling the impaired area, equipped to summon the fire department and alert/evacuate occupants if fire is detected (NFPA 25 Ch. 15)."},
  {id:392, block:4, sec:"Impairments & Obstruction Investigation", q:"When the impaired system is restored, the impairment coordinator must verify, before removing the tag, that:", opts:["The tag is laminated","The building is repainted","The lights are on","Necessary inspections/tests were performed and the system is fully operational"], correct:3, re:"NFPA 25 (Ch. 15) requires confirming the supply is restored (main drain test), no leaks exist, and all valves are open/supervised; only then is the impairment tag removed and stakeholders notified."},
  {id:393, block:4, sec:"Impairments & Obstruction Investigation", q:"Restoring a sprinkler system to service after impairment should include a main drain test to confirm:", opts:["The water supply was fully restored (control valve fully open)","Antifreeze concentration","The paint color","The gauge brand"], correct:0, re:"A main drain test after restoration verifies the control valve is fully open and full supply is available; a low residual would reveal a valve left partly closed (NFPA 25 Ch. 13/15)."},
  {id:394, block:4, sec:"Impairments & Obstruction Investigation", q:"An obstruction investigation under NFPA 25 is triggered when conditions such as which are found?", opts:["Clean, clear pipe","Foreign material, tuberculation, sludge, or evidence of MIC in the piping","Fresh paint","A new gauge"], correct:1, re:"NFPA 25 (Ch. 14) lists conditions (plugged sprinklers, foreign matter in the drain, tubercles, MIC, unusual color/odor) that require an obstruction investigation to locate and remove blockage."},
  {id:395, block:4, sec:"Impairments & Obstruction Investigation", q:"MIC, a corrosion concern that can obstruct sprinkler piping, stands for:", opts:["Mechanical inspection code","Maximum inflow capacity","Microbiologically influenced corrosion","Main inlet connection"], correct:2, re:"Microbiologically influenced corrosion (MIC) is bacterial-driven corrosion that forms nodules/tubercles and pinhole leaks, restricting flow; finding it triggers an NFPA 25 Ch. 14 obstruction investigation."},
  {id:396, block:4, sec:"Impairments & Obstruction Investigation", q:"The 5-year internal pipe examination for obstructions is typically conducted by:", opts:["Listening to the pipe","Adding antifreeze","Painting the pipe","Opening a flushing connection and removing a sprinkler near the end of a branch line to inspect inside"], correct:3, re:"NFPA 25 (Ch. 14) directs examining the interior at representative points (e.g., a cross-main flushing connection and a branch-line-end sprinkler removed) for foreign material, tuberculation, or MIC."},
  {id:397, block:4, sec:"Impairments & Obstruction Investigation", q:"If an obstruction investigation finds material in the piping, the required corrective action is to:", opts:["Flush/clean the system to remove the obstruction and determine/correct the source","Ignore it","Paint over it","Increase the air pressure"], correct:0, re:"NFPA 25 (Ch. 14) requires the system to be flushed/cleaned to remove obstructing material and the source (e.g., debris from the main, MIC) identified and corrected to prevent recurrence."},
  {id:398, block:4, sec:"Impairments & Obstruction Investigation", q:"During an emergency impairment, the impairment coordinator must implement mitigation and:", opts:["Wait until the next business day","Take immediate corrective action and notify the fire department, occupants, and other affected parties","Remove all signage","Disable the alarms"], correct:1, re:"NFPA 25 (Ch. 15) requires emergency impairments to be addressed immediately, with prompt corrective steps and notification of the FD, occupants, alarm company, and others, plus a fire watch if needed."},
  {id:399, block:4, sec:"Impairments & Obstruction Investigation", q:"Records of an impairment (start time, cause, mitigation, restoration) should be:", opts:["Discarded immediately","Posted publicly online","Documented and retained as part of the system records","Kept only verbally"], correct:2, re:"NFPA 25 (Ch. 4/15) requires impairments to be documented (dates, scope, mitigation, restoration confirmation) and retained with the system records for the AHJ and for trending."},
  {id:400, block:4, sec:"Impairments & Obstruction Investigation", q:"After completing the 5-year internal obstruction inspection with no obstruction found, the technician should:", opts:["Begin a full obstruction investigation anyway","Drain the antifreeze permanently","Leave the pipe open","Document the inspection results and restore the system to service"], correct:3, re:"If the 5-year internal examination finds clear piping, an obstruction investigation is not triggered; the findings are documented and the system is restored to normal service (NFPA 25 Ch. 14)."},
  {id:401, block:5, sec:"California Fire Code & CCR Title 19", q:"In California, which Title 24 part is the California Fire Code (CFC)?", opts:["Part 6","Part 2","Part 9","Part 11"], correct:2, re:"The California Fire Code is Title 24, Part 9 of the California Code of Regulations. The California Building Code is Part 2. Source: California Building Standards Code / DGS BSC, 2022 CFC Title 24 Part 9."},
  {id:402, block:5, sec:"California Fire Code & CCR Title 19", q:"The California Fire Code is based on which model code, amended with California-specific provisions?", opts:["The International Fire Code (IFC)","The Uniform Plumbing Code","The International Residential Code","The National Electrical Code"], correct:0, re:"The CFC is pre-assembled from the International Fire Code with necessary California amendments. Source: 2022 California Fire Code, Title 24 Part 9, Preface."},
  {id:403, block:5, sec:"California Fire Code & CCR Title 19", q:"Which California Code of Regulations title contains the State Fire Marshal regulations for servicing, testing and maintaining automatic fire-extinguishing (sprinkler) systems?", opts:["Title 8","Title 16","Title 19","Title 22"], correct:2, re:"CCR Title 19 (Public Safety) contains the State Fire Marshal regulations for servicing, testing and maintaining automatic fire-extinguishing systems. Source: CCR Title 19, Division 1; H&S Code 13195."},
  {id:404, block:5, sec:"California Fire Code & CCR Title 19", q:"CCR Title 19 adopts which NFPA standard by reference for the inspection, testing and maintenance of water-based fire protection systems?", opts:["NFPA 13","NFPA 14","NFPA 72","NFPA 25"], correct:3, re:"CCR Title 19, Section 904 incorporates NFPA 25 (the standard for ITM of water-based fire protection systems) by reference. Source: CCR Title 19 §904; NFPA 25."},
  {id:405, block:5, sec:"California Fire Code & CCR Title 19", q:"Which NFPA standard is the primary reference for the design and installation of automatic sprinkler systems adopted by the California Fire Code?", opts:["NFPA 20","NFPA 13","NFPA 24","NFPA 291"], correct:1, re:"NFPA 13, Standard for the Installation of Sprinkler Systems, is the primary design/installation reference adopted by the CFC (Chapter 9). Source: California Fire Code Chapter 9 / Chapter 80; NFPA 13."},
  {id:406, block:5, sec:"California Fire Code & CCR Title 19", q:"Under California Fire Code Section 903, an automatic sprinkler system is generally required throughout a Group A-1 fire area where the fire area exceeds:", opts:["5,000 sq ft","8,000 sq ft","12,000 sq ft","20,000 sq ft"], correct:2, re:"CFC §903.2.1.1 requires sprinklers for Group A-1 where the fire area exceeds 12,000 sq ft (among other triggers such as occupant load). Source: California Fire Code §903.2.1."},
  {id:407, block:5, sec:"California Fire Code & CCR Title 19", q:"The agency in California that adopts the State Fire Marshal regulations in CCR Title 19 is part of which department?", opts:["Cal/OSHA","The Division of the State Architect","The Department of Consumer Affairs","The Office of the State Fire Marshal (CAL FIRE)"], correct:3, re:"The Office of the State Fire Marshal, within CAL FIRE, adopts the Title 19 fire prevention regulations. Source: Office of the State Fire Marshal; CCR Title 19."},
  {id:408, block:5, sec:"California Fire Code & CCR Title 19", q:"Which design document must a sprinkler contractor typically prepare and submit for plan review before installing a fire sprinkler system?", opts:["Working plans (shop drawings) and hydraulic calculations","Only a load calculation","An electrical single-line diagram","A grading plan"], correct:0, re:"NFPA 13 and the CFC require working plans (shop drawings) plus hydraulic calculations be submitted to the authority having jurisdiction for review before installation. Source: NFPA 13 plans/calcs chapter; CFC §901.2."},
  {id:409, block:5, sec:"California Fire Code & CCR Title 19", q:"The body in a jurisdiction with legal authority to approve fire sprinkler plans and inspect installations is referred to in the codes as the:", opts:["General contractor","Registered design professional","Listing laboratory","Authority having jurisdiction (AHJ)"], correct:3, re:"The 'authority having jurisdiction' (AHJ) is the codes' term for the office/individual responsible for approving equipment, installation and procedures. Source: NFPA 13 definitions; California Fire Code Chapter 2."},
  {id:410, block:5, sec:"California Fire Code & CCR Title 19", q:"Which document is the source of the State Fire Marshal's statutory authority over automatic extinguishing system service and testing?", opts:["The Vehicle Code","The Business and Professions Code","The California Health and Safety Code","The Penal Code"], correct:2, re:"California Health and Safety Code §13195 directs the State Fire Marshal to adopt the Title 19 regulations governing automatic extinguishing system service and testing. Source: H&S Code §13195."},
  {id:411, block:5, sec:"California Fire Code & CCR Title 19", q:"Under CCR Title 19, the standard placard/forms used to document inspection of automatic extinguishing systems are developed by:", opts:["The local water utility","The insurance carrier","The pipe manufacturer","The Office of the State Fire Marshal (AES forms)"], correct:3, re:"CCR Title 19 mandates use of the Office of the State Fire Marshal AES (Automatic Extinguishing Systems) forms to document inspection/testing. Source: CCR Title 19 §906.4."},
  {id:412, block:5, sec:"California Fire Code & CCR Title 19", q:"When a local jurisdiction adopts the California Fire Code, it may:", opts:["Delete all sprinkler requirements","Eliminate the AHJ","Ignore the State Fire Marshal entirely","Adopt more restrictive local amendments based on local conditions"], correct:3, re:"Local jurisdictions may adopt amendments more restrictive than the state model code based on local climatic, geological or topographical conditions. Source: California Health & Safety Code §17958.7; California Fire Code adoption process."},
  {id:413, block:5, sec:"California Fire Code & CCR Title 19", q:"Which California Building Standards Code part contains general building fire-and-life-safety construction requirements (e.g., occupancy and construction type) referenced alongside the Fire Code?", opts:["Part 9 (Fire Code)","Part 4 (Mechanical Code)","Part 2 (Building Code)","Part 5 (Plumbing Code)"], correct:2, re:"The California Building Code is Title 24, Part 2, containing occupancy classification and construction-type requirements that the Fire Code references. Source: California Building Standards Code, Title 24, Part 2."},
  {id:414, block:5, sec:"California Fire Code & CCR Title 19", q:"A complete fire sprinkler plan submittal for AHJ review should generally include all of the following EXCEPT:", opts:["Hydraulic calculations","The contractor's personal tax return","Equipment cut sheets/listings","A water supply (flow test) basis"], correct:1, re:"Working plans, hydraulic calculations, the water supply basis, and listed equipment data are required for review; a contractor's tax return is not part of the fire sprinkler plan submittal. Source: NFPA 13 plans/calcs chapter; CFC §901.2."},
  {id:415, block:5, sec:"California Fire Code & CCR Title 19", q:"The California Fire Code is updated on what general cycle as part of the Title 24 code adoption process?", opts:["Every 6 months","Every 3 years (triennial)","Every 10 years","Only when an earthquake occurs"], correct:1, re:"California Building Standards (Title 24), including the Fire Code, are adopted on a triennial (3-year) cycle. Source: California Building Standards Commission / DGS BSC code adoption cycle."},
  {id:416, block:5, sec:"California Fire Code & CCR Title 19", q:"NFPA 25, adopted by CCR Title 19, primarily governs:", opts:["Inspection, testing and maintenance of installed water-based systems","Design of new sprinkler systems","Manufacture of sprinkler heads","Fire alarm wiring"], correct:0, re:"NFPA 25 is the Standard for the Inspection, Testing, and Maintenance of Water-Based Fire Protection Systems; design of new systems is governed by NFPA 13. Source: NFPA 25 scope; CCR Title 19 §904."},
  {id:417, block:5, sec:"California Fire Code & CCR Title 19", q:"When the California Fire Code and an adopted NFPA standard differ, the installer should:", opts:["Always ignore the NFPA standard","Use whichever is cheaper","Average the two values","Follow the more restrictive requirement, consistent with the AHJ"], correct:3, re:"Where the adopting code (CFC) and a referenced standard differ, the more restrictive provision generally governs, subject to AHJ direction. Source: California Fire Code Chapter 1 administration; AHJ authority."},
  {id:418, block:5, sec:"Occupancy Hazard Classification", q:"NFPA 13 occupancy hazard classifications are based primarily on:", opts:["The quantity and combustibility of the contents","The number of building occupants","The height of the building","The age of the structure"], correct:0, re:"NFPA 13 classifies occupancy hazard by the quantity and combustibility of the contents (and expected heat release), unlike life-safety codes that focus on occupant needs. Source: NFPA 13 Chapter 4, Occupancy classification."},
  {id:419, block:5, sec:"Occupancy Hazard Classification", q:"An occupancy where the quantity and combustibility of contents is low and fires are expected to have a relatively low rate of heat release is classified as:", opts:["Ordinary hazard Group 2","Light hazard","Extra hazard Group 1","Extra hazard Group 2"], correct:1, re:"Light hazard occupancies have low quantity and combustibility of contents and a low expected heat release rate. Source: NFPA 13 light hazard definition (Chapter 4)."},
  {id:420, block:5, sec:"Occupancy Hazard Classification", q:"A typical office building, church, or school classroom is generally classified by NFPA 13 as which occupancy hazard?", opts:["Extra hazard Group 1","Ordinary hazard Group 1","Light hazard","Storage"], correct:2, re:"Offices, churches, schools and similar occupancies are listed as light hazard in NFPA 13. Source: NFPA 13 Annex/Chapter 4 light hazard examples."},
  {id:421, block:5, sec:"Occupancy Hazard Classification", q:"NFPA 13 divides ordinary hazard occupancies into:", opts:["A single class only","High and low only","Groups A through D","Group 1 and Group 2"], correct:3, re:"Ordinary hazard is divided into Group 1 and Group 2, with Group 2 representing greater quantity and combustibility of contents. Source: NFPA 13 Chapter 4 ordinary hazard."},
  {id:422, block:5, sec:"Occupancy Hazard Classification", q:"In ordinary hazard Group 1, the stockpile (storage) height of contents is generally limited to a maximum of about:", opts:["8 ft","4 ft","16 ft","20 ft"], correct:0, re:"Ordinary hazard Group 1 includes a stockpile height limitation of about 8 ft (2.4 m). Source: NFPA 13 ordinary hazard Group 1 definition."},
  {id:423, block:5, sec:"Occupancy Hazard Classification", q:"In ordinary hazard Group 2, the stockpile height for moderately combustible contents may extend up to about:", opts:["8 ft","12 ft","10 ft","30 ft"], correct:1, re:"Ordinary hazard Group 2 allows a taller stockpile, up to about 12 ft (3.7 m) for the same combustibility, reflecting greater quantity than Group 1. Source: NFPA 13 ordinary hazard Group 2 definition."},
  {id:424, block:5, sec:"Occupancy Hazard Classification", q:"An occupancy with very high quantity of combustibles, including areas where dust or lint is present and rapidly spreading fires may occur, is classified as:", opts:["Extra hazard Group 1","Ordinary hazard Group 1","Light hazard","Light hazard, small room"], correct:0, re:"Extra hazard Group 1 covers spaces with very high combustible quantity and rapidly spreading fire potential, such as areas with dust or lint, but with little or no flammable/combustible liquids. Source: NFPA 13 extra hazard Group 1 definition."},
  {id:425, block:5, sec:"Occupancy Hazard Classification", q:"An occupancy containing substantial amounts of flammable or combustible liquids, or extensive shielding of combustibles, is classified as:", opts:["Light hazard","Extra hazard Group 2","Ordinary hazard Group 2","Ordinary hazard Group 1"], correct:1, re:"Extra hazard Group 2 is the highest spray-occupancy class, including substantial flammable/combustible liquids and extensive shielding of combustibles. Source: NFPA 13 extra hazard Group 2 definition."},
  {id:426, block:5, sec:"Occupancy Hazard Classification", q:"Which of the following occupancies would most likely be classified as ordinary hazard Group 2?", opts:["A machine shop or metalworking area","A library reading room","A hospital patient room","A hotel guest room"], correct:0, re:"Machine shops/metalworking are listed examples of ordinary hazard Group 2; libraries (reading rooms), hospital rooms and hotel rooms are light hazard. Source: NFPA 13 Annex occupancy examples."},
  {id:427, block:5, sec:"Occupancy Hazard Classification", q:"NFPA 13 commodity classifications for storage are designated as:", opts:["Class A through F","Grade A through D","Type 1 through 5","Class I through IV (plus plastics groups)"], correct:3, re:"Storage commodities are classified Class I through Class IV (with separate plastics/elastomer groupings), Class IV presenting the greatest hazard of the four numbered classes. Source: NFPA 13 commodity classification chapter."},
  {id:428, block:5, sec:"Occupancy Hazard Classification", q:"Of the numbered storage commodity classes, which presents the greatest fire hazard?", opts:["Class I","Class II","Class III","Class IV"], correct:3, re:"Class IV contains higher levels of plastics/combustibles than Class III and presents the greatest hazard of the numbered (non-plastic-group) classes. Source: NFPA 13 commodity classification chapter."},
  {id:429, block:5, sec:"Occupancy Hazard Classification", q:"A Class I commodity in NFPA 13 is best described as:", opts:["Free-flowing flammable liquids","Essentially noncombustible products on combustible pallets or in ordinary cartons","Exposed unexpanded plastics","Aerosols, Level 3"], correct:1, re:"Class I commodities are essentially noncombustible products that may be stored on wood pallets or in single-layer corrugated cartons. Source: NFPA 13 commodity classification, Class I."},
  {id:430, block:5, sec:"Occupancy Hazard Classification", q:"Why is correct occupancy hazard classification critical to sprinkler design?", opts:["It sets the paint color of the pipe","It selects the alarm bell size","It determines design density, design area and water demand","It has no effect on the hydraulics"], correct:2, re:"The hazard classification drives the design density (gpm/sq ft), the design area, and ultimately the system's water demand. Misclassification can leave a system under-designed. Source: NFPA 13 design approaches; density/area method."},
  {id:431, block:5, sec:"Occupancy Hazard Classification", q:"A printing plant using large quantities of combustible inks and solvents would most likely be classified as:", opts:["Extra hazard","Light hazard","Ordinary hazard Group 1 only","Always light hazard"], correct:0, re:"Process areas with large quantities of flammable/combustible liquids such as inks and solvents fall under extra hazard. Source: NFPA 13 extra hazard examples (printing, paint shops, solvent use)."},
  {id:432, block:5, sec:"Occupancy Hazard Classification", q:"When an occupancy contains storage above the heights/quantities covered by ordinary or extra hazard spray criteria, design generally shifts to:", opts:["Storage protection design criteria","Light hazard criteria","No sprinklers required","Residential criteria"], correct:0, re:"High-piled and bulk storage beyond the spray occupancy limits is designed using NFPA 13 storage protection criteria (commodity, storage height, arrangement). Source: NFPA 13 storage chapters."},
  {id:433, block:5, sec:"Occupancy Hazard Classification", q:"Compared with light hazard, ordinary and extra hazard occupancies generally require:", opts:["Higher water density and reduced maximum protection area per sprinkler","Lower water density and larger sprinkler spacing","No change in design","Fewer sprinklers"], correct:0, re:"Higher hazard classes call for greater design density and a smaller maximum protection area per sprinkler (more sprinklers, closer spacing). Source: NFPA 13 spacing/coverage and density tables."},
  {id:434, block:5, sec:"Occupancy Hazard Classification", q:"A residential dwelling unit protected to residential sprinkler standards is most associated with which design family?", opts:["Extra hazard Group 2","Storage criteria","NFPA 13D/13R residential criteria (life-safety focus)","Ordinary hazard Group 2"], correct:2, re:"Dwelling units are commonly protected under NFPA 13D (one- and two-family) or 13R (residential up to four stories), which focus on life safety with residential sprinklers. Source: NFPA 13D / 13R scope."},
  {id:435, block:5, sec:"Sprinkler Spacing & Coverage", q:"For standard spray sprinklers in light hazard occupancy, the maximum protection area per sprinkler is generally:", opts:["100 sq ft","130 sq ft","200 sq ft","225 sq ft"], correct:3, re:"Light hazard standard spray sprinklers have a maximum protection area of 225 sq ft per sprinkler. Source: NFPA 13 protection area of coverage table (light hazard)."},
  {id:436, block:5, sec:"Sprinkler Spacing & Coverage", q:"For standard spray sprinklers in ordinary hazard occupancy, the maximum protection area per sprinkler is generally:", opts:["225 sq ft","130 sq ft","90 sq ft","400 sq ft"], correct:1, re:"Ordinary hazard standard spray sprinklers have a maximum protection area of 130 sq ft per sprinkler. Source: NFPA 13 protection area of coverage table (ordinary hazard)."},
  {id:437, block:5, sec:"Sprinkler Spacing & Coverage", q:"For standard spray sprinklers in light hazard (smooth ceiling, non-combustible/limited-combustible), the maximum distance between sprinklers is generally:", opts:["15 ft","12 ft","18 ft","20 ft"], correct:0, re:"The maximum spacing between standard spray sprinklers in light hazard is 15 ft. Source: NFPA 13 spacing requirements (light hazard)."},
  {id:438, block:5, sec:"Sprinkler Spacing & Coverage", q:"For standard spray sprinklers, the minimum distance between two sprinklers (unless a listed baffle is used) is generally:", opts:["3 ft","4 ft","8 ft","6 ft"], correct:3, re:"The minimum center-to-center spacing between standard spray sprinklers is 6 ft, unless a qualifying baffle is installed, to prevent cold soldering. Source: NFPA 13 minimum spacing / baffles."},
  {id:439, block:5, sec:"Sprinkler Spacing & Coverage", q:"The minimum 6 ft spacing between standard spray sprinklers is primarily intended to prevent:", opts:["Pipe corrosion","Cold soldering (one sprinkler's discharge cooling/skipping the next)","Excessive paint use","High water pressure"], correct:1, re:"The 6 ft minimum prevents cold soldering, where spray from one operating sprinkler wets/cools an adjacent sprinkler and delays or prevents its operation. Source: NFPA 13 minimum spacing rationale."},
  {id:440, block:5, sec:"Sprinkler Spacing & Coverage", q:"For standard spray sprinklers, the maximum distance from a sprinkler to a wall is generally:", opts:["Equal to the full distance between sprinklers","One-half the allowable distance between sprinklers","Always 10 ft","Always 2 ft"], correct:1, re:"The maximum distance from a sprinkler to a wall is one-half the maximum allowable spacing between sprinklers (e.g., 7.5 ft for a 15 ft layout). Source: NFPA 13 distance to walls."},
  {id:441, block:5, sec:"Sprinkler Spacing & Coverage", q:"For an ordinary hazard layout with 15 ft maximum spacing between sprinklers, the maximum distance from a sprinkler to a wall is:", opts:["7.5 ft","5 ft","10 ft","15 ft"], correct:0, re:"Half of 15 ft is 7.5 ft, the maximum wall distance for that layout. Source: NFPA 13 distance to walls (one-half spacing rule)."},
  {id:442, block:5, sec:"Sprinkler Spacing & Coverage", q:"For standard spray sprinklers in extra hazard occupancy, the maximum protection area per sprinkler is generally:", opts:["100 sq ft","130 sq ft","225 sq ft","300 sq ft"], correct:0, re:"Extra hazard standard spray sprinklers have a maximum protection area of 100 sq ft per sprinkler (90 sq ft for some hydraulically calculated high-density designs). Source: NFPA 13 protection area of coverage (extra hazard)."},
  {id:443, block:5, sec:"Sprinkler Spacing & Coverage", q:"For extra hazard (and high-density hydraulically calculated) standard spray sprinklers, the maximum distance between sprinklers is generally:", opts:["15 ft","12 ft","20 ft","18 ft"], correct:1, re:"Extra hazard layouts limit maximum spacing to 12 ft between standard spray sprinklers. Source: NFPA 13 spacing (extra hazard)."},
  {id:444, block:5, sec:"Sprinkler Spacing & Coverage", q:"The protection area of coverage for a standard spray sprinkler is determined by multiplying:", opts:["Pipe diameter by length","Sprinkler K-factor by pressure","Ceiling height by room width","The distance along the branch line (S) by the distance between branch lines (L)"], correct:3, re:"Protection area = S x L, where S is the dimension along the branch line and L is the dimension between branch lines, and must not exceed the table maximum for the hazard. Source: NFPA 13 protection area of coverage method."},
  {id:445, block:5, sec:"Sprinkler Spacing & Coverage", q:"NFPA 13's 'small room rule' applies to a compartment that is light hazard, of unobstructed construction, and not larger than:", opts:["400 sq ft","800 sq ft","600 sq ft","1,200 sq ft"], correct:1, re:"A 'small room' is a light hazard compartment with unobstructed construction and floor area not exceeding 800 sq ft. Source: NFPA 13 small room definition."},
  {id:446, block:5, sec:"Sprinkler Spacing & Coverage", q:"When the small room rule applies, a sprinkler is permitted to be located up to how far from any single wall?", opts:["6 ft","9 ft","7.5 ft","12 ft"], correct:1, re:"Under the small room rule, sprinklers may be located up to 9 ft from any single wall, more permissive than the standard 7.5 ft light hazard wall distance. Source: NFPA 13 small room rule."},
  {id:447, block:5, sec:"Sprinkler Spacing & Coverage", q:"Extended coverage (EC) sprinklers differ from standard spray sprinklers in that they:", opts:["Cannot be used indoors","Always use less water","Have no listing requirements","Are listed to protect larger floor areas at specified spacings"], correct:3, re:"Extended coverage sprinklers are specially listed to cover larger areas (e.g., up to 400 sq ft in light hazard) at the spacings stated in their listing. Source: NFPA 13 extended coverage sprinklers."},
  {id:448, block:5, sec:"Sprinkler Spacing & Coverage", q:"For extended coverage sprinklers, the spacing and coverage that may be used are governed by:", opts:["The standard spray tables only","The pipe schedule","The contractor's preference","The individual sprinkler's listing"], correct:3, re:"EC sprinkler spacing/coverage must follow the specific listing for that sprinkler, which may exceed standard spray maximums. Source: NFPA 13 extended coverage / listing requirements."},
  {id:449, block:5, sec:"Sprinkler Spacing & Coverage", q:"In a light hazard layout, the maximum protection area per sprinkler and maximum spacing combine to limit coverage to roughly:", opts:["Any area the designer chooses","A 20 ft x 20 ft area","A 25 ft x 25 ft area","A 15 ft x 15 ft area not exceeding 225 sq ft"], correct:3, re:"Light hazard standard spray sprinklers are bounded by 15 ft maximum spacing AND a 225 sq ft maximum protection area, so a 15x15 grid (225 sq ft) is at the limit. Source: NFPA 13 spacing and coverage (light hazard)."},
  {id:450, block:5, sec:"Sprinkler Spacing & Coverage", q:"If the calculated protection area (S x L) for a head exceeds the table maximum for the occupancy, the designer must:", opts:["Increase the spacing further","Ignore the table","Add sprinklers / reduce spacing so each head stays within the maximum area","Use a larger drain"], correct:2, re:"Each sprinkler must protect no more than its table maximum area; if S x L is too large, spacing must be reduced (more sprinklers added). Source: NFPA 13 protection area of coverage limits."},
  {id:451, block:5, sec:"Sprinkler Spacing & Coverage", q:"Sprinklers must be positioned so that their actual coverage is within both the maximum area AND the maximum spacing because:", opts:["Only area matters","Either limit alone can leave a gap in coverage or over-extend a head","Only spacing matters","Neither limit applies indoors"], correct:1, re:"Both limits apply simultaneously; satisfying area but exceeding spacing (or vice versa) can leave unprotected gaps, so the more restrictive controls. Source: NFPA 13 spacing and protection area of coverage."},
  {id:452, block:5, sec:"Obstructions & Clearance to Storage", q:"NFPA 13 requires a minimum clearance between the top of storage and sprinkler deflectors of at least:", opts:["6 in","12 in","36 in","18 in"], correct:3, re:"A minimum 18 in (457 mm) clearance is required between the top of storage and the sprinkler deflectors so spray patterns can develop and overlap. Source: NFPA 13 clearance to storage."},
  {id:453, block:5, sec:"Obstructions & Clearance to Storage", q:"The 18 in clearance below the deflector to the top of storage exists primarily to:", opts:["Allow the discharge spray pattern to develop and overlap to pre-wet combustibles","Save material cost","Make room for lighting","Reduce pipe size"], correct:0, re:"The clear space lets sprinkler discharge fan out and overlap so combustibles are pre-wetted; storage too close blocks pattern development. Source: NFPA 13 clearance to storage rationale."},
  {id:454, block:5, sec:"Obstructions & Clearance to Storage", q:"For the storage of rubber tires, NFPA 13 generally requires a clearance to the deflectors of at least:", opts:["18 in","24 in","12 in","36 in"], correct:3, re:"Rubber tire storage requires a greater clearance of at least 36 in (900 mm) to the sprinkler deflectors. Source: NFPA 13 clearance to storage (rubber tires)."},
  {id:455, block:5, sec:"Obstructions & Clearance to Storage", q:"For standard spray sprinklers under unobstructed construction, the deflector must be located below the ceiling within a range of:", opts:["6 in to 24 in","0 in to 4 in","1 in to 12 in","12 in to 36 in"], correct:2, re:"Under unobstructed construction, standard pendent/upright spray deflectors must be 1 in to 12 in below the ceiling (concealed/recessed types per their listing). Source: NFPA 13 distance below ceilings / deflector position."},
  {id:456, block:5, sec:"Obstructions & Clearance to Storage", q:"NFPA 13's 'three times rule' for standard spray sprinklers requires that a sprinkler be located away from an obstruction a distance of at least:", opts:["Twice the obstruction's dimension","One-half the obstruction's dimension","Three times the maximum dimension of the obstruction","Ten feet regardless of size"], correct:2, re:"The three times rule positions the sprinkler at least 3x the maximum dimension of the obstruction away from it (capped at 24 in) so spray can pass both sides. Source: NFPA 13 obstructions to discharge (positioning away from obstructions)."},
  {id:457, block:5, sec:"Obstructions & Clearance to Storage", q:"Under the three times rule for standard spray sprinklers, the required horizontal clearance from the obstruction is capped at a maximum of:", opts:["12 in","18 in","24 in","48 in"], correct:2, re:"The three times rule need not exceed 24 in of horizontal clearance for standard spray sprinklers. Source: NFPA 13 obstructions (3x rule, 24 in maximum)."},
  {id:458, block:5, sec:"Obstructions & Clearance to Storage", q:"For continuous obstructions wider than 4 ft (e.g., wide ducts) located below sprinklers, NFPA 13 generally requires:", opts:["Nothing additional","Sprinklers installed beneath the obstruction","Removing the ceiling sprinklers","Doubling the pipe size"], correct:1, re:"Obstructions wider than 4 ft generally require additional sprinklers installed underneath them, with deflectors positioned per the standard. Source: NFPA 13 obstructions (sprinklers required below wide obstructions)."},
  {id:459, block:5, sec:"Obstructions & Clearance to Storage", q:"When sprinklers are installed below a wide obstruction, NFPA 13 generally requires the deflector to be located below the bottom of the obstruction within:", opts:["12 in","24 in","36 in","48 in"], correct:0, re:"Sprinklers placed under a wide obstruction must have deflectors located less than 12 in below the bottom of the obstruction. Source: NFPA 13 obstructions (deflector below wide obstruction)."},
  {id:460, block:5, sec:"Obstructions & Clearance to Storage", q:"The 'four times rule' in NFPA 13 is an extension of the obstruction rule that applies to:", opts:["Standard spray sprinklers only","Extended coverage sprinklers","Dry pendent sprinklers only","In-rack sprinklers only"], correct:1, re:"The four times rule extends the obstruction-positioning concept to extended coverage sprinklers, with a larger maximum clearance (up to 36 in). Source: NFPA 13 obstructions (extended coverage, 4x rule)."},
  {id:461, block:5, sec:"Obstructions & Clearance to Storage", q:"An obstruction located 18 in or more below the deflector and not wider than 4 ft can generally be:", opts:["Never allowed","Required to have its own riser","Disregarded for obstruction purposes","Cause for removing all ceiling sprinklers"], correct:2, re:"An obstruction 18 in or more below the deflector and up to 4 ft wide can generally be ignored, as the spray pattern has developed above it. Source: NFPA 13 obstructions (below-deflector allowance)."},
  {id:462, block:5, sec:"Obstructions & Clearance to Storage", q:"Obstructions that prevent sprinkler discharge from reaching the protected hazard (such as wide overhead obstructions) are addressed by NFPA 13 because they:", opts:["Improve coverage","Reduce pipe friction","Create unprotected shadow areas below them","Have no effect"], correct:2, re:"Such obstructions create 'shadow' areas the ceiling sprinklers cannot reach, requiring additional sprinklers or repositioning. Source: NFPA 13 obstructions to discharge pattern development."},
  {id:463, block:5, sec:"Obstructions & Clearance to Storage", q:"The minimum 18 in clear space below deflectors in a storage area is best understood as:", opts:["Only at one sprinkler","A vertical line at the wall","A horizontal plane below which all storage must remain","Optional in all cases"], correct:2, re:"The 18 in clearance is treated as a horizontal plane throughout the storage area; all stored materials must remain below that plane. Source: NFPA 13 clearance to storage (horizontal plane)."},
  {id:464, block:5, sec:"Obstructions & Clearance to Storage", q:"Materials stored on shelves against a wall, below ceiling sprinklers, are treated differently regarding the 18 in clearance because they:", opts:["Do not impede the overlap of spray from multiple ceiling sprinklers","Always need 36 in","Require in-rack sprinklers always","Are never combustible"], correct:0, re:"Wall storage does not block the overlap of spray from multiple ceiling sprinklers the way island storage does, so the 18 in rule is applied differently. Source: NFPA 13 clearance to storage (wall storage)."},
  {id:465, block:5, sec:"Obstructions & Clearance to Storage", q:"Bottom chords of bar joists, beams and similar structural members are examples of obstructions evaluated using:", opts:["The K-factor","The occupant load","The friction loss formula","The beam rule / obstruction distance rules"], correct:3, re:"Structural members like beams and joist bottom chords are evaluated with NFPA 13's obstruction (beam) rules governing distance from sprinkler to obstruction and deflector height. Source: NFPA 13 obstructions to discharge (beam rule)."},
  {id:466, block:5, sec:"Obstructions & Clearance to Storage", q:"Light fixtures, ductwork and similar non-structural items that obstruct discharge are referred to in NFPA 13 as:", opts:["Listed appliances","Seismic braces","Pipe hangers","Obstructions to sprinkler discharge"], correct:3, re:"Non-structural items that block the spray are 'obstructions to sprinkler discharge' and must be addressed by relocating sprinklers or adding coverage. Source: NFPA 13 obstructions to discharge."},
  {id:467, block:5, sec:"Obstructions & Clearance to Storage", q:"Maintaining required clearance below deflectors and proper sprinkler-to-obstruction distance is primarily the responsibility of:", opts:["Only the building occupant after move-in","The designer/installer at installation, and the owner during occupancy","The water utility","The alarm contractor"], correct:1, re:"Proper clearances must be designed/installed per NFPA 13, and the owner must maintain them (e.g., not stacking storage too high) during occupancy. Source: NFPA 13 clearance/obstruction rules; NFPA 25 maintenance of clearances."},
  {id:468, block:5, sec:"Obstructions & Clearance to Storage", q:"If a new mezzanine, duct, or partition is added below an existing sprinkler system, the installer should:", opts:["Ignore it","Remove the affected sprinklers permanently","Evaluate obstructions and add or relocate sprinklers as required by NFPA 13","Increase the system pressure only"], correct:2, re:"New obstructions can create shadow areas; NFPA 13 requires evaluating them and adding/relocating sprinklers to restore coverage. Source: NFPA 13 obstructions; system modifications."},
  {id:469, block:5, sec:"Seismic Protection", q:"In areas subject to earthquakes, NFPA 13 requires sprinkler piping to be protected against damage primarily by means of:", opts:["Extra paint","Larger sprinkler heads","Sway bracing, flexible couplings and clearances","Higher water pressure"], correct:2, re:"Seismic protection uses sway bracing, flexible couplings, restraint of branch lines, and clearances at penetrations to resist earthquake movement. Source: NFPA 13 seismic protection (Chapter on Protection of Piping Against Damage Where Subject to Earthquakes)."},
  {id:470, block:5, sec:"Seismic Protection", q:"Sway braces that resist movement perpendicular to the run of the pipe are called:", opts:["Longitudinal braces","Lateral braces","Vertical braces","Flexible couplings"], correct:1, re:"Lateral sway braces resist horizontal movement perpendicular to the pipe; longitudinal braces resist movement parallel to the pipe. Source: NFPA 13 seismic bracing definitions."},
  {id:471, block:5, sec:"Seismic Protection", q:"Sway braces that resist movement parallel to the run of the pipe are called:", opts:["Lateral braces","Longitudinal braces","Riser clamps","Hangers"], correct:1, re:"Longitudinal braces resist movement along (parallel to) the pipe run; lateral braces resist perpendicular movement. Source: NFPA 13 seismic bracing definitions."},
  {id:472, block:5, sec:"Seismic Protection", q:"On feed and cross mains, NFPA 13 generally requires lateral sway braces spaced no more than:", opts:["40 ft apart on center","20 ft apart","80 ft apart","100 ft apart"], correct:0, re:"Lateral sway braces are placed at intervals not exceeding 40 ft (12 m) on center along mains. Source: NFPA 13 seismic bracing spacing (lateral braces)."},
  {id:473, block:5, sec:"Seismic Protection", q:"On feed and cross mains, NFPA 13 generally requires longitudinal sway braces spaced no more than:", opts:["40 ft apart","80 ft apart on center","60 ft apart","120 ft apart"], correct:1, re:"Longitudinal sway braces are placed at intervals not exceeding 80 ft (24 m) on center along feed and cross mains. Source: NFPA 13 seismic bracing spacing (longitudinal braces)."},
  {id:474, block:5, sec:"Seismic Protection", q:"At the top of a sprinkler riser, NFPA 13 generally requires:", opts:["No bracing","Only a flexible coupling and nothing else","Only a hanger","Four-way (combined lateral and longitudinal) bracing"], correct:3, re:"Four-way bracing (combined lateral and longitudinal) is required at the top of risers and where risers pass through floors. Source: NFPA 13 seismic bracing (four-way bracing at risers)."},
  {id:475, block:5, sec:"Seismic Protection", q:"Flexible couplings on risers are generally required within what distance of the top and bottom of the riser?", opts:["24 in","12 in","6 in","48 in"], correct:0, re:"Flexible couplings are required within 24 in (610 mm) of the top and bottom of risers (with exceptions for very short risers). Source: NFPA 13 seismic (flexible couplings on risers)."},
  {id:476, block:5, sec:"Seismic Protection", q:"Flexible couplings are installed in seismic sprinkler systems to:", opts:["Increase water pressure","Eliminate the need for any bracing","Allow controlled movement at points where differential movement is expected","Reduce the pipe diameter"], correct:2, re:"Flexible couplings accommodate differential/relative movement at risers, building seismic joints and similar locations, working together with rigid bracing elsewhere. Source: NFPA 13 seismic (flexible couplings purpose)."},
  {id:477, block:5, sec:"Seismic Protection", q:"Where fire sprinkler piping crosses a building seismic separation (expansion) joint, NFPA 13 requires:", opts:["A rigid welded connection","Flexibility/clearance to accommodate movement on both sides of the joint","Removal of the pipe","Doubling the bracing only"], correct:1, re:"Piping crossing seismic separation joints must include provisions (flexible assemblies/clearance) to allow independent movement of the two building sections. Source: NFPA 13 seismic separation assemblies."},
  {id:478, block:5, sec:"Seismic Protection", q:"Clearance is required around sprinkler pipe where it passes through walls, floors, or platforms in seismic areas so that:", opts:["Water can leak out","The pipe can be painted","The pipe is not damaged by relative movement of the building element","The pipe is hidden"], correct:2, re:"Clearance (or a flexible sleeve) at penetrations prevents the rigid building element from shearing or crushing the pipe during seismic movement. Source: NFPA 13 seismic (clearance at penetrations)."},
  {id:479, block:5, sec:"Seismic Protection", q:"The required nominal clearance around pipe 1 in to 3-1/2 in passing through walls/floors in seismic designs is generally:", opts:["About 1 in","No clearance","About 2 in","About 6 in"], correct:0, re:"NFPA 13 generally requires a nominal 1 in clearance around pipe of 1 in through 3-1/2 in (and 2 in for 4 in and larger) at penetrations, unless flexible couplings/sleeves are provided. Source: NFPA 13 seismic clearance at penetrations."},
  {id:480, block:5, sec:"Seismic Protection", q:"A sway brace assembly must be capable of resisting loads in:", opts:["Only the downward direction","Only the upward direction","Only horizontal water flow","Both tension and compression along the brace"], correct:3, re:"Seismic sway braces must resist horizontal loads acting in both directions (tension and compression) along the brace axis. Source: NFPA 13 seismic bracing (load directions)."},
  {id:481, block:5, sec:"Seismic Protection", q:"The portion of piping whose seismic load is carried by a given sway brace is referred to as the brace's:", opts:["Zone of influence","Friction zone","Hazard area","Riser nipple"], correct:0, re:"Each sway brace carries the seismic load of a defined 'zone of influence' of pipe; loads are summed within that zone to size the brace. Source: NFPA 13 seismic bracing (zone of influence / load calculation)."},
  {id:482, block:5, sec:"Seismic Protection", q:"End-of-line / branch line restraint in seismic designs is intended to:", opts:["Increase flow","Limit excessive lateral movement of unbraced branch line ends","Replace all hangers","Lower the water demand"], correct:1, re:"Branch line and end restraints limit lateral sway of pipe that is not otherwise braced, reducing the chance of breakage at fittings/sprinklers. Source: NFPA 13 seismic (restraint of branch lines)."},
  {id:483, block:5, sec:"Seismic Protection", q:"Seismic bracing components such as braces, fasteners and attachments to the structure must be:", opts:["Listed/approved and installed to the structure capable of carrying the load","Any hardware on hand","Made of wood","Optional in all jurisdictions"], correct:0, re:"Brace members, fittings and structural attachments must be listed/approved and anchored to building structure able to resist the calculated seismic loads. Source: NFPA 13 seismic bracing (components and attachment to structure)."},
  {id:484, block:5, sec:"Seismic Protection", q:"In California, seismic protection of fire sprinkler piping is required because:", opts:["It is purely optional everywhere","Only coastal cities have earthquakes","Much of the state is in high seismic-risk zones and the codes mandate it","Water freezes in California"], correct:2, re:"California's high seismic activity leads the CFC/NFPA 13 to require seismic protection of sprinkler systems statewide in applicable areas. Source: NFPA 13 seismic chapter; California Building Standards seismic provisions."},
  {id:485, block:5, sec:"C-16 Scope, Permits & Plans", q:"In California, the CSLB classification for a Fire Protection Contractor is:", opts:["C-10","C-36","C-16","C-20"], correct:2, re:"C-16 is the CSLB classification for a Fire Protection Contractor. Source: CSLB Licensing Classifications, C-16 Fire Protection."},
  {id:486, block:5, sec:"C-16 Scope, Permits & Plans", q:"The CSLB C-16 classification authorizes a contractor to lay out, fabricate and install:", opts:["Only electrical fire alarm wiring","All types of fire protection systems (excluding electrical alarm systems)","Only residential smoke detectors","Only underground gas piping"], correct:1, re:"A C-16 contractor lays out, fabricates and installs all types of fire protection systems and associated equipment, excluding electrical alarm systems. Source: CSLB C-16 classification description (CCR Title 16 §832.16)."},
  {id:487, block:5, sec:"C-16 Scope, Permits & Plans", q:"Electrical fire alarm system wiring is generally outside the C-16 scope and instead falls to which classification?", opts:["C-16","C-36 (Plumbing)","C-10 (Electrical)","C-4 (Boiler)"], correct:2, re:"Electrical alarm system wiring is excluded from C-16 and is performed under the C-10 electrical classification. Source: CSLB C-16 description (excludes electrical alarm systems); C-10 Electrical."},
  {id:488, block:5, sec:"C-16 Scope, Permits & Plans", q:"Personnel installing or repairing water-based fire protection systems under a C-16 license for commercial/multifamily projects must generally hold:", opts:["A real estate license","A notary commission","A C-36 plumbing license","A Fire Sprinkler Fitter certification"], correct:3, re:"C-16 qualifiers and journey-level workers installing/repairing water-based fire protection systems for commercial or multifamily dwellings must obtain a Fire Sprinkler Fitter certification. Source: CSLB Industry Bulletin 24-02; H&S Code fire sprinkler fitter requirements."},
  {id:489, block:5, sec:"C-16 Scope, Permits & Plans", q:"The CSLB itself is part of which California department?", opts:["The Department of Consumer Affairs","CAL FIRE","Caltrans","The Franchise Tax Board"], correct:0, re:"The Contractors State License Board (CSLB) is within the California Department of Consumer Affairs. Source: CSLB / Department of Consumer Affairs."},
  {id:490, block:5, sec:"C-16 Scope, Permits & Plans", q:"Before beginning most commercial fire sprinkler installations, the contractor must typically obtain:", opts:["Nothing at all","Only a hydrant flow test","Only a business card","A building/fire permit and approved plans from the AHJ"], correct:3, re:"A permit and AHJ-approved plans are generally required before installing a fire sprinkler system; work without a permit can be a code violation. Source: California Fire Code §105 permits; CFC §901.2 plan review."},
  {id:491, block:5, sec:"C-16 Scope, Permits & Plans", q:"Fire sprinkler working plans (shop drawings) submitted for approval are generally prepared/approved by:", opts:["Any unlicensed person","Qualified persons and reviewed/approved by the AHJ (and design professional where required)","The water meter reader","The building occupant"], correct:1, re:"Working plans are prepared by qualified persons and must be reviewed/approved by the AHJ before installation; many projects also require a registered design professional. Source: NFPA 13 working plans; CFC §901.2."},
  {id:492, block:5, sec:"C-16 Scope, Permits & Plans", q:"After installation and before a sprinkler system is placed in service, NFPA 13 requires the contractor to perform and document:", opts:["No testing","Only a paint inspection","Only a visual glance","Acceptance testing including a hydrostatic test and flushing"], correct:3, re:"Acceptance testing (hydrostatic test, flushing of underground/lead-ins, main drain test, etc.) must be performed and documented before the system is accepted. Source: NFPA 13 system acceptance (hydrostatic test 200 psi / 50 psi above static for 2 hours)."},
  {id:493, block:5, sec:"C-16 Scope, Permits & Plans", q:"The standard hydrostatic acceptance test for a new sprinkler system under NFPA 13 is generally:", opts:["200 psi (or 50 psi above static if static exceeds 150 psi) for 2 hours","50 psi for 30 minutes","1,000 psi for 24 hours","No pressure, water only"], correct:0, re:"New sprinkler piping is hydrostatically tested at 200 psi for 2 hours (or 50 psi above static where static pressure exceeds 150 psi). Source: NFPA 13 hydrostatic test (acceptance)."},
  {id:494, block:5, sec:"C-16 Scope, Permits & Plans", q:"Upon completion, NFPA 13 requires the installing contractor to provide the owner with:", opts:["Nothing","The original purchase order only","Only a verbal confirmation","A Contractor's Material and Test Certificate"], correct:3, re:"The installing contractor must complete and furnish the Contractor's Material and Test Certificate documenting materials, tests and results. Source: NFPA 13 Contractor's Material and Test Certificate."},
  {id:495, block:5, sec:"C-16 Scope, Permits & Plans", q:"A C-16 contractor's responsibility for a fire sprinkler system generally includes:", opts:["Only selling the parts","Designing/laying out, installing, testing and providing required documentation per code","Only painting the pipe","Only inspecting other contractors' work"], correct:1, re:"The C-16 contractor lays out/designs, fabricates, installs, tests, and provides required documentation for the fire protection system, within the classification scope. Source: CSLB C-16 description; NFPA 13 installation and acceptance."},
  {id:496, block:5, sec:"C-16 Scope, Permits & Plans", q:"Installing fire sprinkler systems in California without the proper contractor's license can result in:", opts:["Disciplinary action, penalties, and unenforceable contracts","A commendation","Automatic license upgrade","Nothing under the law"], correct:0, re:"Unlicensed contracting in California is unlawful and can lead to penalties, disciplinary action and contracts that are not legally enforceable by the unlicensed party. Source: California Business & Professions Code §7028 et seq.; CSLB enforcement."},
  {id:497, block:5, sec:"C-16 Scope, Permits & Plans", q:"The general statutory monetary threshold above which a contractor's license is required for a single construction job in California is:", opts:["$100 or more","$5,000 or more","$500 or more (labor and materials)","$50,000 or more"], correct:2, re:"A CSLB contractor's license is generally required when the combined labor and material cost of a job is $500 or more. Source: California Business & Professions Code §7048; CSLB."},
  {id:498, block:5, sec:"C-16 Scope, Permits & Plans", q:"Standpipe systems (e.g., NFPA 14 hose connections for fire department use) fall within the scope of which classification as water-based fire protection?", opts:["C-10 only","C-20 only","C-16 Fire Protection","B General Building only"], correct:2, re:"Standpipe (water-based) systems are part of the C-16 fire protection scope of installing all types of fire protection systems. Source: CSLB C-16 description; NFPA 14 standpipes."},
  {id:499, block:5, sec:"C-16 Scope, Permits & Plans", q:"When a fire sprinkler system is connected to a public water supply, the contractor must also coordinate with the water purveyor regarding:", opts:["Wall paint color","Carpet selection","Backflow prevention and the service connection","Roof shingles"], correct:2, re:"Connection to a public supply requires coordinating backflow prevention and the service connection with the water purveyor/AHJ. Source: California Plumbing Code / AHJ backflow requirements; NFPA 13 water supply connection."},
  {id:500, block:5, sec:"C-16 Scope, Permits & Plans", q:"A C-16 contractor performing work that requires only incidental and supplemental tasks of another trade to complete the fire protection project may:", opts:["Perform that incidental and supplemental work as part of the C-16 project","Never touch any other trade work","Must hire a general contractor for each screw","Lose the license automatically"], correct:0, re:"CSLB rules allow a specialty contractor to take and execute work that is incidental and supplemental to the performance of work in the craft for which licensed. Source: CSLB CCR Title 16 §831 (incidental and supplemental)."}
];
